  # Auto-detect species from gene names
  detect_species <- function(seurat_obj) {
    genes <- rownames(seurat_obj)
    # Check for common housekeeping genes
    human_markers <- c("GAPDH", "ACTB", "B2M", "RPL13A", "HPRT1")
    mouse_markers <- c("Gapdh", "Actb", "B2m", "Rpl13a", "Hprt")

    human_count <- sum(human_markers %in% genes)
    mouse_count <- sum(mouse_markers %in% genes)

    if (human_count > mouse_count) {
      return("human")
    } else if (mouse_count > human_count) {
      return("mouse")
    } else {
      # Fallback: check uppercase ratio (human genes are all uppercase)
      sample_genes <- head(genes, 1000)
      upper_ratio <- mean(sample_genes == toupper(sample_genes))
      return(ifelse(upper_ratio > 0.8, "human", "mouse"))
    }
  }

