 is_csv_or_tsv <- function(file_path) {
  # Check if file exists and is readable
  if (!file.exists(file_path)) {
    print(paste("File does not exist:", file_path))
    stop("File does not exist")
  }
  
  if (!file.access(file_path, mode = 4) == 0) {
    print(paste("File is not readable:", file_path))
    stop("File is not readable")
  }
  
  print(paste("Checking file:", file_path))
  print(paste("File size:", file.info(file_path)$size))
  print(paste("File permissions:", file.info(file_path)$mode))
  
  # Check file extension first
  ext <- tolower(tools::file_ext(file_path))
  print(paste("File extension:", ext))
  
  if (ext == "rds") return("RDS")
  if (ext == "gz") return("GZ")
  
  # For txt, csv, tsv files, check content
  tryCatch({
    # Open file with explicit encoding
    con <- file(file_path, "rt", encoding = "UTF-8")
    lines <- readLines(con, n = 5)
    close(con)
    
    print("First line of file:")
    print(lines[1])
    
    # Count delimiters in each line
    comma_counts <- sapply(lines, function(line) sum(strsplit(line, "")[[1]] == ","))
    tab_counts <- sapply(lines, function(line) sum(strsplit(line, "")[[1]] == "\t"))
    space_counts <- sapply(lines, function(line) sum(strsplit(line, "")[[1]] == " "))
    
    print("Delimiter counts:")
    print(paste("Commas:", comma_counts[1]))
    print(paste("Tabs:", tab_counts[1]))
    print(paste("Spaces:", space_counts[1]))
    
    # Calculate modes with error handling
    mode_comma <- tryCatch(as.numeric(names(sort(table(comma_counts), decreasing = TRUE)[1])), error = function(e) 0)
    mode_tab <- tryCatch(as.numeric(names(sort(table(tab_counts), decreasing = TRUE)[1])), error = function(e) 0)
    mode_space <- tryCatch(as.numeric(names(sort(table(space_counts), decreasing = TRUE)[1])), error = function(e) 0)
    
    # Handle NA values
    mode_comma <- if (is.na(mode_comma)) 0 else mode_comma
    mode_tab <- if (is.na(mode_tab)) 0 else mode_tab
    mode_space <- if (is.na(mode_space)) 0 else mode_space
    
    print("Mode counts:")
    print(paste("Mode comma:", mode_comma))
    print(paste("Mode tab:", mode_tab))
    print(paste("Mode space:", mode_space))
    
    # Determine file type
    if (mode_comma >= mode_tab && mode_comma >= mode_space && mode_comma > 0) {
      return("CSV")
    } else if (mode_tab >= mode_comma && mode_tab >= mode_space && mode_tab > 0) {
      return("TSV")
    } else if (mode_space >= mode_comma && mode_space >= mode_tab && mode_space > 0) {
      return("SPACE")
    } else if (ext %in% c("csv", "txt", "tsv")) {
      if (ext == "csv") return("CSV")
      if (ext == "tsv") return("TSV")
      return("SPACE")
    }
    return("Unknown")
    
  }, error = function(e) {
    print(paste("Error in file format detection:", e))
    # Fallback to extension-based detection
    if (ext %in% c("csv", "txt", "tsv")) {
      if (ext == "csv") return("CSV")
      if (ext == "tsv") return("TSV")
      return("SPACE")
    }
    return("Unknown")
  })
}


