read_matrix_file <- function(file_path) {
  print(paste("Attempting to read file:", file_path))
  
  # Check file existence and permissions
  if (!file.exists(file_path)) {
    stop(paste("File does not exist:", file_path))
  }
  
  if (!file.access(file_path, mode = 4) == 0) {
    stop(paste("File is not readable:", file_path))
  }
  
  file_type <- is_csv_or_tsv(file_path)
  print(paste("Detected file type:", file_type))
  
  # Function to safely read table with multiple attempts
  safe_read_table <- function(file, sep) {
    tryCatch({
      read.table(file, header = TRUE, row.names = 1, sep = sep, 
                check.names = FALSE, comment.char = "", quote = "\"",
                encoding = "UTF-8", stringsAsFactors = FALSE)
    }, error = function(e) {
      # Try without row names if first attempt fails
      tryCatch({
        read.table(file, header = TRUE, sep = sep, 
                  check.names = FALSE, comment.char = "", quote = "\"",
                  encoding = "UTF-8", stringsAsFactors = FALSE)
      }, error = function(e2) {
        stop(paste("Failed to read file with separator", sep, ":", e2))
      })
    })
  }
  
  result <- tryCatch({
    if (file_type == "RDS") {
      readRDS(file_path)
    } else if (file_type == "GZ") {
      con <- gzfile(file_path, "rt")
      first_line <- readLines(con, n = 1)
      close(con)
      
      if (grepl(",", first_line)) {
        safe_read_table(gzfile(file_path), ",")
      } else if (grepl("\t", first_line)) {
        safe_read_table(gzfile(file_path), "\t")
      } else {
        safe_read_table(gzfile(file_path), " ")
      }
    } else if (file_type == "CSV") {
      safe_read_table(file_path, ",")
    } else if (file_type == "TSV") {
      safe_read_table(file_path, "\t")
    } else if (file_type == "SPACE") {
      safe_read_table(file_path, " ")
    } else {
      # Try all separators
      tryCatch({
        safe_read_table(file_path, ",")
      }, error = function(e) {
        tryCatch({
          safe_read_table(file_path, "\t")
        }, error = function(e) {
          safe_read_table(file_path, " ")
        })
      })
    }
  }, error = function(e) {
    print(paste("Error in read_matrix_file:", e))
    stop(paste("Error reading file:", e))
  })
  
  # Verify the result
  if (is.null(result) || nrow(result) == 0 || ncol(result) == 0) {
    stop("File was read but contains no valid data")
  }
  
  print(paste("Successfully read matrix with dimensions:", nrow(result), "x", ncol(result)))
  return(result)
}


check_spatial_data <- function(object) {
  # 方法1: アッセイ名で確認
   assay_names <- names(object@assays)
  has_spatial_assay <- if(inherits(assay_names, "try-error")) {
    FALSE
  } else {
    any(stringr::str_detect(assay_names, "Spatial"))
  }
  
  # 方法2: 画像の存在で確認
  has_images <- tryCatch({
    images <- Images(object)
    length(images) > 0
  }, error = function(e) FALSE)
  
  # 方法3: 空間座標が取得できるか確認
  has_coords <- tryCatch({
    # 実際に座標を取得できるか試してみる
    if (has_images) {
      for (img in Images(object)) {
        coords <- GetTissueCoordinates(object[[img]])
        if (!is.null(coords) && nrow(coords) > 0) {
          return(TRUE)
        }
      }
    }
    FALSE
  }, error = function(e) FALSE)
  
  return(has_spatial_assay || (has_images && has_coords))
}

observeEvent(input$uploadCountMatrixConfirm, {
  if(!is.null(proj_default) | !is.null(seurat_object)) {
    showModal(modal_confirm)
  } else {
    session$sendCustomMessage("handler_disableTabs", "sidebarMenu")
    session$sendCustomMessage("handler_startLoader", c("input_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "uploadCountMatrixConfirm")
    
    tryCatch({
      showModal(modalDialog(
        div('Analysis in Progress. This operation may take several minutes, please wait...', 
            style='color:#ffffff; background-color:#222d32;'), 
        footer = NULL, 
        style = 'font-size:20px; text-align:center;position:absolute;'
      ))
      
      # Setup project parameters
      metaD$my_project_name <- input$uploadCountMatrixprojectID
      minimum_cells <<- input$uploadCountMatrixminCells
      minimum_features <<- input$uploadCountMatrixminFeatures
      organism <<- input$uploadCountMatrixRadioSpecies
      updateSpecies()

      # Set Seurat assay version based on user selection
      assay_version <- ifelse(is.null(input$uploadCountMatrixAssayVersion), "v5", input$uploadCountMatrixAssayVersion)
      if (assay_version == "v4") {
        options(Seurat.object.assay.version = "v3")
      } else {
        options(Seurat.object.assay.version = "v5")
      }
      showNotification(paste("Creating Seurat object with Assay", assay_version))

      if(organism == "mouse") {
        showNotification("Species is mouse")
      } else {
        showNotification("Species is human")
      }
      
      # Create user directory
      userId <- session$token
      user_dir <<- paste0("./usr_temp/", userId, metaD$my_project_name, 
                         gsub(pattern = "[ ]|[:]", replacement = "_", x = paste0("_", Sys.time())))
      dir.create(user_dir, recursive = TRUE)
      
      # Read input file
      source_data <- NULL
      
      if (!is.null(input$countMatrix)) {
        # Handle uploaded file
        file_info <- input$countMatrix
        file_ext <- tools::file_ext(file_info$name)
        
        if (file_ext == "rds") {
          source_data <- readRDS(file_info$datapath)
        } else if (file_ext == "gz") {
          # Check if it's Matrix Market format
          first_line <- readLines(gzfile(file_info$datapath, "rt"), n = 1)
          if (grepl("%%MatrixMarket", first_line)) {
            # Read Matrix Market format
            source_data <- Matrix::readMM(file_info$datapath)
            # Matrix Market is already in genes x cells format, which matches Seurat's expectation
          } else {
            # Try TSV first for gz files, then CSV
            tryCatch({
              source_data <- read.delim(gzfile(file_info$datapath, "rt"), row.names = 1)
              if (ncol(source_data) <= 1) {
                source_data <- read.csv(gzfile(file_info$datapath, "rt"), row.names = 1)
              }
            }, error = function(e) {
              con <- gzfile(file_info$datapath, "rt")
              source_data <<- read.table(con, header = TRUE, sep = " ", row.names = 1)
              close(con)
            })
          }
        } else {
          # Check if it's Matrix Market format
          first_line <- readLines(file_info$datapath, n = 1)
          if (grepl("%%MatrixMarket", first_line)) {
            # Read Matrix Market format
            source_data <- Matrix::readMM(file_info$datapath)
            # Matrix Market is already in genes x cells format, which matches Seurat's expectation
          } else {
            # Try TSV first (read.delim), then CSV (read.csv)
            tryCatch({
              source_data <- read.delim(file_info$datapath, row.names = 1)
              if (ncol(source_data) <= 1) {
                source_data <- read.csv(file_info$datapath, row.names = 1)
              }
            }, error = function(e) {
              source_data <<- read.table(file_info$datapath, header = TRUE, sep = " ", row.names = 1)
            })
          }
        }
      } else if (!is.null(input$localMatrix)) {
        # Handle local file selection
        file_path <- parseFilePaths(volumes, input$localMatrix)$datapath
        if (length(file_path) > 0) {
          file_ext <- tools::file_ext(file_path)
          
          if (file_ext == "rds") {
            source_data <- readRDS(file_path)
          } else if (file_ext == "gz") {
            # Check if it's Matrix Market format
            first_line <- readLines(gzfile(file_path, "rt"), n = 1)
            if (grepl("%%MatrixMarket", first_line)) {
              # Read Matrix Market format
              source_data <- Matrix::readMM(file_path)
              # Convert to dense matrix and transpose (Matrix Market is usually genes x cells, Seurat expects cells x genes)
              source_data <- t(as.matrix(source_data))
            } else {
              # Try TSV first for gz files, then CSV
              tryCatch({
                source_data <- read.delim(gzfile(file_path, "rt"), row.names = 1)
                if (ncol(source_data) <= 1) {
                  source_data <- read.csv(gzfile(file_path, "rt"), row.names = 1)
                }
              }, error = function(e) {
                con <- gzfile(file_path, "rt")
                source_data <<- read.table(con, header = TRUE, sep = " ", row.names = 1)
                close(con)
              })
            }
          } else {
            # Check if it's Matrix Market format
            first_line <- readLines(file_path, n = 1)
            if (grepl("%%MatrixMarket", first_line)) {
              # Read Matrix Market format
              source_data <- Matrix::readMM(file_path)
              # Convert to dense matrix and transpose (Matrix Market is usually genes x cells, Seurat expects cells x genes)
              source_data <- t(as.matrix(source_data))
            } else {
              # Try TSV first (read.delim), then CSV (read.csv)
              tryCatch({
                source_data <- read.delim(file_path, row.names = 1)
                if (ncol(source_data) <= 1) {
                  source_data <- read.csv(file_path, row.names = 1)
                }
              }, error = function(e) {
                source_data <<- read.table(file_path, header = TRUE, sep = " ", row.names = 1)
              })
            }
          }
        } else {
          stop("No valid file path found from local selection")
        }
      } else {
        stop("No input file provided")
      }
      
      if (is.null(source_data)) {
        stop("Failed to read input data")
      }
      
      print("Data dimensions:")
      print(dim(source_data))
      print(paste("Genes (rows):", nrow(source_data)))
      print(paste("Cells (columns):", ncol(source_data)))
      
      # Create Seurat object
      seurat_object <<- CreateSeuratObject(counts = source_data, 
                                         project = metaD$my_project_name, 
                                         min.cells = as.numeric(minimum_cells), 
                                         min.features = as.numeric(minimum_features))
      
      seurat_object@meta.data$orig.ident <<- as.factor(metaD$my_project_name)

      # v5ではlayerをjointする
      if (is_assay5(seurat_object)){
        tryCatch({
          seurat_object <<- JoinLayers(seurat_object)
          showNotification("v5 assay's layers are joined.")
        }, error = function(e) {
          showNotification(paste("Error :  ", e), type = 'error', duration=200)
        })
      }

      # Initialize after data load
      session$sendCustomMessage("handler_startLoader", c("input_loader", 75))
      initializeAfterDataLoad(organism)

      if(organism == "human") {
        updateTextAreaInput(session, inputId="findMarkersSignatureMembers",
                          placeholder = "PRG4\nTSPAN15\nCOL22A1\nHTRA4")
      }

      session$sendCustomMessage("handler_enableTabs",
                              c("sidebarMenu", " FILE", " QUALITY CONTROL", " DATA NORMALIZATION\n& SCALING", " SEURAT OBJECT STRUCTURE", " UTILITY IDENTITY & ASSAY", " UTILITY CLUSTER", " UTILITY DATA MANIPULATION"))
      
    }, error = function(e) {
      print(paste("Error in file processing:", e))
      showNotification(paste("Error: ", e), type = 'error', duration=200)
      session$sendCustomMessage("handler_alert", 
                              "Data Input error. Please, refer to the help pages for input format.")
    }, finally = {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("input_loader", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "input_loader")
      session$sendCustomMessage("handler_enableAllButtons", "uploadCountMatrixConfirm")
    })
  }
})

