observeEvent(input$RunEmptyDrops, {
tryCatch({

library(DropletUtils)


  fdr_threshold <- 0.01
  lower_umi <- 100
  niters <- 10000
  seed <- 100
  prior_cells <- ncol(seurat_object)
  print("=== Starting EmptyDrops filtering ===")
  print(paste0("Original object: ", ncol(seurat_object), " cells"))
  
  # 1. RNAアッセイのカウントマトリックスを取得
  rna_counts <- GetAssayData(seurat_object, assay = "RNA", layer = "counts")
  print(paste0("RNA matrix dimensions: ", paste(dim(rna_counts), collapse = " x ")))  # 修正
  
  # 2. EmptyDropsの実行
  print("Running EmptyDrops...")
  set.seed(seed)
  e.out <- emptyDrops(rna_counts, 
                     lower = lower_umi, 
                     niters = niters)
  
  # 3. 結果の要約
 # print("EmptyDrops results:")
  print(paste0("Total barcodes tested:", length(e.out$FDR)))
  print(paste0("Barcodes with FDR <= ", fdr_threshold, ": ", 
      sum(e.out$FDR <= fdr_threshold, na.rm = TRUE)))
  print(paste0("NA values (low UMI):", sum(is.na(e.out$FDR))))
  
  # 4. 細胞の選択
  is.cell <- e.out$FDR <= fdr_threshold
  is.cell[is.na(is.cell)] <- FALSE
  
  # 選択された細胞のバーコード
  selected_cells <- colnames(rna_counts)[is.cell]
  print(paste0("Cells selected:", length(selected_cells)))
  
  # 5. EmptyDropsの結果をメタデータに追加（フィルタリング前）
  #seurat_object$emptydrops_fdr <- e.out$FDR
  #seurat_object$emptydrops_total_umi <- e.out$Total
  #seurat_object$emptydrops_is_cell <- is.cell
  
  # 6. Seuratオブジェクトをサブセット（すべてのアッセイが自動的に一致）
  seurat_object <<- subset(seurat_object, cells = selected_cells)
  
  # 7. フィルタリング統計を表示
  print("=== Filtering summary ===")
  print(paste0("Cells before:", prior_cells))
  print(paste0("Cells after:", ncol(seurat_object)))
  print(paste0("Cells removed:", prior_cells - ncol(seurat_object)))
  print(paste0("Retention rate: ", 
      round(ncol(seurat_object) / prior_cells * 100, 2), "%")) 

  showNotification(paste0("Cells before: ", prior_cells,  "  Cells after:", ncol(seurat_object)))

 }, error = function(e) {
      print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
    }, finally = { # with or without error
          removeModal()}
    )})

