seurat_object_read <- function() {
     tryCatch({
      print("seurat_object_read function------------------")
        # single cell experimentへの対応
        if (data.class(seurat_object) == "SingleCellExperiment") {
          showNotification("Converting SingleCellExperiment to Seurat object...")
          seurat_object <<- as.Seurat(seurat_object)
   #       print(seurat_object)
        }

        # characterをfactor型へ 50種類以上あるときはcharacterのまま
        if (!is.null(seurat_object@meta.data)){
          print("Change meta.data to factor")
          tryCatch({
          seurat_object@meta.data[]  <<- lapply(seurat_object@meta.data, function(x) {if(is.character(x) & (length(levels(as.factor(x))) <50) ) as.factor(x) else x })
          }, error = function(e) {
      print(paste("Error :  ", e))
      })
        }

        if (!is.null(seurat_object@meta.data$orig.ident)){
                #orig.identをファクターに
        seurat_object@meta.data$orig.ident <<- factor(seurat_object@meta.data$orig.ident)
        } else {
