      else {

gl_spatialFeature <<-  NULL
print("SpatialConfirm")

if (input$Spatialkeep.scale){
  keep.scale<-'all'
} else {
  keep.scale<-NULL
}

color_scheme <- switch(input$spatielfeatureColor,
  "default" = NULL,
  "Zissou1" = wesanderson::wes_palette("Zissou1", 100, type = "continuous"),
  "Blues" = colorRampPalette(RColorBrewer::brewer.pal(9, "Blues"))(100),
  "Reds" = colorRampPalette(RColorBrewer::brewer.pal(9, "Reds"))(100),
  "Greens" = colorRampPalette(RColorBrewer::brewer.pal(9, "Greens"))(100),
  "YlOrRd" = colorRampPalette(RColorBrewer::brewer.pal(9, "YlOrRd"))(100),
  "YrOrBr" = colorRampPalette(RColorBrewer::brewer.pal(9, "YrOrBr"))(100),
  "YlGnBu" = colorRampPalette(RColorBrewer::brewer.pal(9, "YlGnBu"))(100),
  "RdPu" = colorRampPalette(RColorBrewer::brewer.pal(9, "RdPu"))(100),
  "PuRd" = colorRampPalette(RColorBrewer::brewer.pal(9, "PuRd"))(100),
  "viridis" = viridis::viridis(100),
  "magma" = viridis::magma(100),
  "cividis" = viridis::cividis(100),
  "inferno" = viridis::inferno(100),
  "plasma" = viridis::plasma(100)
)

        minq <- paste0("q", input$spatialMinCutoff)
        maxq <- paste0("q", input$spatialMaxCutoff)

features_to_plot <- if (input$SpatialFeaturesSignature == "gene") input$SpatialGene else input$SpatialFeature

# SpatialPlotをリストで取得
gl_spatialFeature_list <<- SpatialPlot(
  seurat_object,
  features = features_to_plot, 
  alpha = c(input$plot.alpha, input$plot.alpha),
  image.alpha = input$image.alpha, 
  keep.scale = keep.scale,
  pt.size.factor = input$pt.size.factor,
  slot = input$SpatialGeneFeature,
  max.cutoff = maxq, 
  min.cutoff = minq,
  combine = FALSE
)

# 色付けを適用
for(i in seq_along(gl_spatialFeature_list)){
  if (input$spatielfeatureColor %in% c("Blues", "Reds", "Greens","YlOrRd", "YrOrBr","YlGnBu",'RdPu','PuRd')){
    gl_spatialFeature_list[[i]] <- gl_spatialFeature_list[[i]] +
      scale_fill_distiller(palette = input$spatielfeatureColor, direction = 1)
  } else if (input$spatielfeatureColor == "Zissou1"){
    pal <- wesanderson::wes_palette("Zissou1", 10, type = "continuous")
    gl_spatialFeature_list[[i]] <- gl_spatialFeature_list[[i]] +
      scale_fill_gradientn(colors = pal)
  } else if (input$spatielfeatureColor != "default"){
    gl_spatialFeature_list[[i]] <- gl_spatialFeature_list[[i]] +
      scale_fill_viridis_c(option = input$spatielfeatureColor, direction = 1)
  }

  gl_spatialFeature_list[[i]] <- gl_spatialFeature_list[[i]] +
    theme(legend.position = "right")
}

nplots <- length(gl_spatialFeature_list)
ncol_use <- ceiling(sqrt(nplots))


# パッチワークで統合（重要: 必ずリストを使用）
gl_spatialFeature <<- patchwork::wrap_plots(gl_spatialFeature_list, ncol = ncol_use)

# 描画
output$SpatialPlot <- renderPlot({
  gl_spatialFeature
}, height = input$SpatialHeight, width = input$SpatialWidth)

showNotification("Plot finished. It may take a while for plot to show up.")

