    intdata <- lapply(integrated.corrected.data[[2]], t)
    panorama <- do.call(cbind, intdata)
    incProgress(1/10)
    rownames(panorama) <- as.character(integrated.corrected.data[[3]])
    incProgress(1/10)
    colnames(panorama) <- unlist(sapply(assaylist, rownames))
