observeEvent(input$scVIintegration, {
      session$sendCustomMessage("handler_startLoader", c("input_loader", 10))
      session$sendCustomMessage("handler_disableAllButtons", "FasMNN")

      tryCatch({
        if (is.null(seurat_object@meta.data$orig.ident)) {
              showNotification("orig.ident is missing. You may copy the appropriate identity to orig.ident on UTILITY OPTIONs.", type='error', duration = 300)
              session$sendCustomMessage("handler_enableTabs", c("sidebarMenu"," FILE", " UTILITY IDENTITY & ASSAY", " UTILITY CLUSTER", " UTILITY DATA MANIPULATION"," SEURAT OBJECT STRUCTURE"))
              return()
        }
        showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%
        session$sendCustomMessage("handler_startLoader", c("input_loader", 20))
        # SeuratWrappers/batchelor are pre-loaded in global.R
        requireNamespace("SeuratWrappers", quietly = TRUE)
        requireNamespace("batchelor", quietly = TRUE)
#  reduc_data <- NULL
#  reduc_temp <- NULL
#    if (input$KeepReduct) {
#      if (('mnn' %in% names(seurat_object@reductions)) | ('pca' %in% names(seurat_object@reductions)) ) {
#      showNotification("fastMNNをかける前から存在するPCA等の次元圧縮データは残ります。必要に応じて再度PCA等を行って下さい。", duration = 120)
#    reduc_temp <- seurat_object@reductions
#    print('reduc_temp')
#    print(reduc_temp)
#      }}

   # DefaultAssay(seurat_object) <<- 'RNA'
      updateGeneSearchFP()
    seurat_object <<- NormalizeData(seurat_object)
    seurat_object <<- FindVariableFeatures(seurat_object, selection.method = "vst", nfeatures = 2000) # nfesturesが200になっていた。
#    var_genes <- VariableFeatures(seurat_object, selection.method = "vst") 
var_genes <- seurat_object[[DefaultAssay(seurat_object)]]@var.features

        if (!is.null(seurat_object@meta.data$orig.ident)){
        seurat_object@meta.data$orig.ident <<- factor(seurat_object@meta.data$orig.ident)
        } else {
        showNotification("orig.ident欠損。orig.ident is missing. All values set to 0. You may copy the appropriate identity to orig.ident on UTILITY OPTIONs.", type='error', duration = 120)
        seurat_object@meta.data$orig.ident <<- factor(0)
        updateMetadata()
        updateSelInpColor()
        return()
        }

