      if(length(na_cols) > 0) {
        na_message <- paste("Following columns contain NA:", 
                          paste(na_cols, collapse=", "))
        showNotification(
          na_message,
          type = "warning",
          duration = 90
        )
        showNotification("To keep them, check 'Preserve meta data column with NA?'", duration=90)
      }

      if (!input$h5adNA){
      seurat_object_temp@meta.data <- seurat_object@meta.data[,colSums(is.na(seurat_object@meta.data)) == 0]
    }
      #sceasy::convertFormat(seurat_object_temp, from="seurat", to = "anndata", outFile = file)

#active assayをRNAにコピー
    if (input$h5adActiveAssay != 'RNA'){
              seurat_object_temp@assays[["RNA"]] <- seurat_object@assays[[input$h5adActiveAssay]]
          }

    print("Before meta.data check:")
    print(colnames(seurat_object_temp@meta.data))

#エラー回避 なぜこれで動くのかは不明
meta <- seurat_object_temp[[]]
seurat_object_temp[[]] <- meta
    print("Final meta.data check:")
    print(colnames(seurat_object_temp@meta.data))
# v5対応
if (is_assay5(seurat_object)) {
    # Assay5の場合、JoinLayersしてからAssayに変換
    seurat_object_temp <- JoinLayers(seurat_object_temp, assay = input$h5adActiveAssay)
    seurat_object_temp[["RNA3"]] <- as(object =seurat_object_temp[[input$h5adActiveAssay]], Class = "Assay")

    # Check if data layer is empty (e.g., after scCDC without normalization)
    # More robust check for empty data
    rna3_data <- tryCatch({
      seurat_object_temp@assays$RNA3@data
    }, error = function(e) NULL)

    rna3_counts <- tryCatch({
      seurat_object_temp@assays$RNA3@counts
    }, error = function(e) NULL)

    data_layer_empty <- is.null(rna3_data) ||
                        length(rna3_data) == 0 ||
                        (is.matrix(rna3_data) && all(dim(rna3_data) == 0)) ||
                        (inherits(rna3_data, "dgCMatrix") && length(rna3_data@x) == 0)

    # Also check if data is same as counts (means not normalized)
    if (!data_layer_empty && !is.null(rna3_counts)) {
      if (identical(dim(rna3_data), dim(rna3_counts))) {
        # Check if data contains only integers (not normalized)
        sample_vals <- rna3_data@x[1:min(100, length(rna3_data@x))]
        if (all(sample_vals == floor(sample_vals))) {
          data_layer_empty <- TRUE  # Treat as empty if data = counts (not normalized)
        }
      }
    }

    if (data_layer_empty) {
      showNotification(
        paste0("Warning: '", input$h5adActiveAssay, "' assay has no normalized data (e.g., after scCDC). ",
               "Using counts as main data. Please normalize this assay before export for proper analysis."),
        type = "warning", duration = 60
      )
      # Use counts as main layer when data is empty
      if (!is.null(rna3_counts) && length(rna3_counts) > 0) {
        seurat2ann(seurat_object_temp, outFile= "seurat_temp.h5ad", assay = 'RNA3', main_layer = "counts", full = !input$h5adForCellxgene)
      } else {
        stop("Both data and counts layers are empty. Cannot export.")
      }
    } else {
      if (!is.null(rna3_counts)) {
            if (length(rna3_counts) > 0 && !input$h5adForCellxgene) {
                        seurat2ann(seurat_object_temp, outFile= "seurat_temp.h5ad", assay = 'RNA3', main_layer = "data", transfer_layers = "counts", full = !input$h5adForCellxgene)
           } else {
              seurat2ann(seurat_object_temp, outFile= "seurat_temp.h5ad", assay = 'RNA3', main_layer = "data", full = !input$h5adForCellxgene)
            }
        } else { seurat2ann(seurat_object_temp, outFile= "seurat_temp.h5ad", assay = 'RNA3', main_layer = "data", full = !input$h5adForCellxgene) }
    }


    } else {
            if (input$h5adActiveAssay != 'RNA'){
              seurat_object_temp@assays[["RNA"]] <- seurat_object_temp@assays[[input$h5adActiveAssay]]
            }


      # countがある場合は保存するように変更
      if (!is.null(seurat_object_temp[["RNA"]]$counts)) {
            if (length(seurat_object_temp[["RNA"]]$counts) > 0 && !input$h5adForCellxgene) {
              seurat2ann(seurat_object_temp, outFile= "seurat_temp.h5ad",  main_layer = "data", transfer_layers = "counts", full = !input$h5adForCellxgene)
           } else {
              seurat2ann(seurat_object_temp, outFile= "seurat_temp.h5ad",  main_layer = "data", full = !input$h5adForCellxgene)
            }
        } else { seurat2ann(seurat_object_temp, outFile= "seurat_temp.h5ad",  main_layer = "data", full = !input$h5adForCellxgene) }

    }

