# Python経由でCSR変換 + 圧縮
py_run_string(paste0("
import anndata as ad
import scipy.sparse
adata = ad.read_h5ad('seurat_temp.h5ad')

# より効率的なCSR変換
if scipy.sparse.issparse(adata.X):
    adata.X = adata.X.tocsr()
    print(f'Main matrix: {adata.X.format} format, shape: {adata.X.shape}')

# レイヤーの変換
for layer_name in list(adata.layers.keys()):
    if scipy.sparse.issparse(adata.layers[layer_name]):
        adata.layers[layer_name] = adata.layers[layer_name].tocsr()
        print(f'Layer {layer_name}: converted to CSR')

# 圧縮保存
adata.write_h5ad('", output_file, "', compression='gzip')
print('Successfully saved with CSR format and gzip compression')
"))
    
    file.remove("seurat_temp.h5ad")


