  observeEvent(input$utilitiesConfirmDownsample, {
    if(!identical(seurat_object@active.ident, NULL) )
    {
      tryCatch( {
          t <- table(seurat_object@active.ident)
          min_cell_num <- min(t)
          print(t)
          min_c <- as.integer(input$DownSampleCells)
          if (min_c != 0){
            min_cell_num <- min_c
          }
          cells <- c()
        for (i in levels(seurat_object@active.ident)) {
            cell_num <- sum(Idents(seurat_object) == i)
            if (cell_num > min_cell_num) {
                subset_cells <- sample(c(1:t[i]),min_cell_num)
            } else {
            subset_cells <- c(1:cell_num)
            }
              cell_name <-  colnames(seurat_object)[(seurat_object@active.ident == i)][subset_cells]
              cells <- c(cells, cell_name)
            }
          seurat_object <<- subset(seurat_object, cells = cells)
          seurat_object@meta.data$seurat_clusters <<- as.factor(Idents(seurat_object)) #こうしないとseurat_objectにゼロのクラスターが残存する
      showNotification("Finished downsampling the clusters.")
#      init_seurat_object <<- seurat_object
      }, error = function(e) {
            showNotification("Error in subsetting the cluster.", type='error')
            showNotification(paste("Error :  ", e), type = 'error', duration=200)
      })
    }
  })

