observeEvent(input$utilitiesConfirmDist, {
  tryCatch({
    library(data.table)
    
    # Get the selected column data
    cluster_data <- seurat_object@meta.data[, input$utilitiesDist]
    
    # Check for NAs and show warning if found
    na_count <- sum(is.na(cluster_data))
    if (na_count > 0) {
      showNotification(
        sprintf("Warning: %d NA values found in the cluster data", na_count),
        type = 'warning',
        duration = 60
      )
    }
    
    # Count including NAs
    t1 <- data.table(table(cluster_data, useNA = "ifany"))
    colnames(t1) <- c("Cluster", "Number")
    # Replace NA with "NA" in the Cluster column for better display
    t1[is.na(t1$Cluster), "Cluster"] <- "NA"
    output$distTable1 <- renderTable(t1)
    
    # Calculate proportions including NAs
    t2 <- data.table(prop.table(table(cluster_data, useNA = "ifany")))
    colnames(t2) <- c("Cluster", "Freq")
    # Replace NA with "NA" in the Cluster column
    t2[is.na(t2$Cluster), "Cluster"] <- "NA"
    # Format frequency as percentage
    t2[, Freq := sprintf("%.2f%%", Freq * 100)]
    output$distTable2 <- renderTable(t2)
    
  }, error = function(e) {
    showNotification("Error in changing clusters.", type = 'error')
    showNotification(paste("Error : ", e), type = 'error', duration = 200)
  })
})

