    observeEvent(input$confirmUpdateMeta, {
      tryCatch({
 withProgress(message = 'This may take several minutes',{

  # メタデータを取得
  metadata <- seurat_object@meta.data
  
  # 全ての列に対して処理
  for (col in colnames(metadata)) {
    # Cell_id列はスキップ（常にcharacter）
    if (col == "Cell_id") next
    
    col_data <- as.character(metadata[[col]])
    col_data_clean <- trimws(col_data)
    non_na_values <- col_data_clean[!is.na(col_data_clean) & col_data_clean != ""]
    
    if (length(non_na_values) > 0) {
      numeric_test <- suppressWarnings(as.numeric(non_na_values))
      
      # percent.mtは強制的にnumeric
      if (grepl("percent\\.mt", col, ignore.case = TRUE)) {
        metadata[[col]] <- suppressWarnings(as.numeric(col_data_clean))
        print(paste(col, ": forced to numeric (percent.mt column)"))
        next
      }
      
      if (all(!is.na(numeric_test))) {
        # 数値に変換可能な場合
        unique_count <- length(unique(non_na_values))
        total_count <- length(non_na_values)
        uniqueness_ratio <- unique_count / total_count
        
        # 連続値パターン
        continuous_patterns <- c("percent\\.", "pct\\.", "^nCount_", "^nFeature_", 
                                "_score$", "_expression$", "^log", "^scale")
        is_continuous <- any(sapply(continuous_patterns, function(pattern) 
                                   grepl(pattern, col)))
        
        # カテゴリカルパターン
        categorical_patterns <- c("_clusters$", "cluster", "^res\\.", "louvain", 
                                 "leiden", "ident", "group", "batch", "sample")
        is_categorical <- any(sapply(categorical_patterns, function(pattern) 
                                    grepl(pattern, col, ignore.case = TRUE)))
        
        if (is_continuous) {
          metadata[[col]] <- suppressWarnings(as.numeric(col_data_clean))
          print(paste(col, ": converted to numeric (continuous pattern)"))
        } else if (is_categorical || uniqueness_ratio < 0.1) {
          metadata[[col]] <- factor(col_data_clean)
          print(paste(col, ": converted to factor (categorical,", 
                     unique_count, "levels)"))
        } else if (uniqueness_ratio > 0.5) {
          metadata[[col]] <- suppressWarnings(as.numeric(col_data_clean))
          print(paste(col, ": converted to numeric (unique ratio:", 
                     round(uniqueness_ratio, 2), ")"))
        } else {
          metadata[[col]] <- factor(col_data_clean)
          print(paste(col, ": converted to factor (", unique_count, 
                     "levels, ratio:", round(uniqueness_ratio, 2), ")"))
        }
      } else {
        # 文字列データの処理
        unique_count <- length(unique(non_na_values))
        total_count <- length(non_na_values)
        uniqueness_ratio <- unique_count / total_count
        
        if (col %in% c("Cell_id", "barcode", "sample_id") ||  
            uniqueness_ratio > 0.5) {
          # characterのまま（type.convertは使わない）
          metadata[[col]] <- col_data_clean
          print(paste(col, ": kept as character (unique ratio:", 
                     round(uniqueness_ratio, 2), ")"))
        } else {
          # factorに変換
          metadata[[col]] <- factor(col_data_clean)
          print(paste(col, ": converted to factor (", unique_count, "levels)"))
        }
      }
    } else {
      # 全てNAの場合
      print(paste(col, ": all NA/empty - kept as is"))
    }
  }
  
  # グローバル変数のseurat_objectを更新
  seurat_object@meta.data <<- metadata
  
  # 型変換後の確認
  print("\nFinal column types:")
  sapply(seurat_object@meta.data, class)
      # Update UI
      updateMetadata()
      updateSelInpColor()
        showNotification("Metadata is updated.")
})
      }, error = function(e) { showNotification('Error', type='error')
      showNotification(paste("Error :  ", e), type = 'error', duration=200)})
      showNotification("You may try Seurat V.5")
