    # Preview Meta to Reduction conversion
    observeEvent(input$previewReduction, {
      tryCatch({
        if (length(input$metaToReductionCols) < 2) {
          showNotification("Please select at least 2 metadata columns", type = "warning")
          return()
        }
        
        # Get selected columns
        selected_cols <- input$metaToReductionCols
        
        # Find common prefix
        common_prefix <- ""
        if (input$reductionName == "") {
          # Auto-detect common prefix
          splits <- strsplit(selected_cols, "_")
          if (length(unique(sapply(splits, length))) == 1 && all(sapply(splits, length) > 1)) {
            # All have same number of parts
            common_parts <- splits[[1]]
            for (i in 1:length(common_parts)) {
              if (all(sapply(splits, function(x) x[i] == common_parts[i]))) {
                common_prefix <- paste0(common_prefix, common_parts[i], "_")
              } else {
                break
              }
            }
          }
          # If no common prefix found, use first part before underscore
          if (common_prefix == "" && all(grepl("_", selected_cols))) {
            common_prefix <- paste0(sub("_.*", "", selected_cols[1]), "_")
          }
        }
        
        # Set reduction name and key
        reduction_name <- ifelse(input$reductionName != "", input$reductionName, gsub("_$", "", common_prefix))
        reduction_key <- ifelse(input$reductionKey != "", input$reductionKey, common_prefix)
        
        # Display preview
        preview_text <- paste0(
          "Selected columns: ", paste(selected_cols, collapse = ", "), "\n",
          "Reduction name: ", reduction_name, "\n",
          "Reduction key: ", reduction_key, "\n",
          "Number of cells: ", nrow(seurat_object@meta.data), "\n\n",
          "Preview of data:\n"
        )
        
        # Show first few rows
        preview_data <- head(seurat_object@meta.data[, selected_cols, drop = FALSE], 5)
        preview_text <- paste0(preview_text, capture.output(print(preview_data)), collapse = "\n")
        
        output$reductionPreview <- renderText(preview_text)
        
      }, error = function(e) {
        showNotification(paste("Error: ", e), type = "error")
      })
    })
    
    # Convert Meta to Reduction
    observeEvent(input$confirmMetaToReduction, {
      tryCatch({
        if (length(input$metaToReductionCols) < 2) {
          showNotification("Please select at least 2 metadata columns", type = "warning")
          return()
        }
        
        showModal(modalDialog(
          div('Converting metadata to reduction...', 
              style='color:#ffffff; background-color:#222d32;'), 
          footer = NULL, 
          style = 'font-size:20px; text-align:center;'
        ))
        
        # Get selected columns
        selected_cols <- input$metaToReductionCols
        
        # Extract data
        reduction_data <- as.matrix(seurat_object@meta.data[, selected_cols, drop = FALSE])
        
        # Convert to numeric
        reduction_data <- apply(reduction_data, 2, as.numeric)
        
        # Ensure rownames are set
        rownames(reduction_data) <- rownames(seurat_object@meta.data)
        
        # Check for NAs
        if (any(is.na(reduction_data))) {
          removeModal()
          showNotification("Selected columns contain non-numeric values", type = "error")
          return()
        }
        
        # Find common prefix for auto-detection
        common_prefix <- ""
        if (input$reductionName == "") {
          splits <- strsplit(selected_cols, "_")
          if (length(unique(sapply(splits, length))) == 1 && all(sapply(splits, length) > 1)) {
            common_parts <- splits[[1]]
            for (i in 1:length(common_parts)) {
              if (all(sapply(splits, function(x) x[i] == common_parts[i]))) {
                common_prefix <- paste0(common_prefix, common_parts[i], "_")
              } else {
                break
              }
            }
          }
          if (common_prefix == "" && all(grepl("_", selected_cols))) {
            common_prefix <- paste0(sub("_.*", "", selected_cols[1]), "_")
          }
        }
        
        # Set reduction name and key
        reduction_name <- ifelse(input$reductionName != "", input$reductionName, gsub("_$", "", common_prefix))
        reduction_key <- ifelse(input$reductionKey != "", input$reductionKey, 
                               ifelse(common_prefix != "", common_prefix, paste0(reduction_name, "_")))
        
        # Rename columns to match key
        suffix_numbers <- sub(paste0("^", gsub("_$", "", common_prefix), "_?"), "", selected_cols)
        new_col_names <- paste0(reduction_key, suffix_numbers)
        colnames(reduction_data) <- new_col_names
        
        # Create DimReduc object
        reduction_obj <- CreateDimReducObject(
          embeddings = reduction_data,
          key = reduction_key,
          assay = DefaultAssay(seurat_object)
        )
        
        # Add to Seurat object
        seurat_object[[reduction_name]] <<- reduction_obj
        
        removeModal()
        showNotification(paste("Reduction '", reduction_name, "' successfully created", sep = ""), 
                        type = "message")
        
        # Update UI
        updateUmapTypeChoices()
        updateUtilitiesReduction()
        updateReduction2(reduction_name, 2)
        output$reductionPreview <- renderText("")
        
      }, error = function(e) {
        removeModal()
        showNotification(paste("Error: ", e), type = "error")
      })
    })

