library(SoupX)

find_10x_directories <- function(parent_dir) {
  # Ensure the fs package is available
  if (!requireNamespace("fs", quietly = TRUE)) {
    stop("Package 'fs' is needed for this function to work. Please install it.")
  }
  
  # Find all directories recursively
  all_dirs <- fs::dir_ls(parent_dir, type = "directory", recurse = TRUE)
  
  # Filter for raw_feature_bc_matrix
#  raw_dirs <- fs::path_filter(all_dirs, regexp = "raw_feature_bc_matrix$")
  
  # Filter for sample_filtered_feature_bc_matrix
  filtered_dirs <- fs::path_filter(all_dirs, regexp = "filtered_feature_bc_matrix$")

#開始するディレクトリーも含む
 # Check if the parent directory itself matches the pattern
  if (grepl("filtered_feature_bc_matrix$", parent_dir)) {
    filtered_dirs <- c(parent_dir, filtered_dirs)
  }

  # Prepare the result list
  result <- list(
#    raw = raw_dirs,
    filtered = filtered_dirs
  )
  
  # Print summary
#  cat("Found", length(raw_dirs), "raw_feature_bc_matrix directories\n")
  cat("Found", length(filtered_dirs), "filtered_feature_bc_matrix directories\n")

    
# パスを分割する関数
split_path <- function(path) {
  strsplit(path, "/")[[1]]
}
    
    # 全てのパスを分割
split_paths <- lapply(filtered_dirs, split_path)

# 共通部分と相違部分を特定
common_parts <- Reduce(intersect, split_paths)
different_parts <- lapply(split_paths, function(x) setdiff(x, common_parts))

# 相違部分を抽出
filtered_name <- unlist(different_parts)
names(result$filtered) <- filtered_name
return(result)
}

extract_barcode <- function(cell_ids) {
  # 正規表現を使用してバーコード部分を抽出
  barcodes <- sub(".*_([ACGT]+)-[12]$", "\\1", cell_ids)
  return(barcodes)
}

