#------------scCDC

observeEvent(input$runScCDC, {
  tryCatch({
    if (identical(seurat_object, NULL)) {
      session$sendCustomMessage("handler_alert", "Please upload data via the DATA INPUT tab first.")
      return()
    }

    # Check if scCDC package is installed
    if (!requireNamespace("scCDC", quietly = TRUE)) {
      showNotification("scCDC package is not installed. Please install it first: remotes::install_github('ZJU-UoE-CCW-LAB/scCDC')",
                      type = 'error', duration = 200)
      return()
    }

    showModal(modalDialog(div('Running scCDC analysis. This may take several minutes...',
                             style='color:#ffffff; background-color:#222d32;'),
                         footer = NULL,
                         style = 'font-size:20px; text-align:center;position:absolute;'))

    library(scCDC)

    # Check and convert to Seurat v5 if needed
    if (!is_assay5(seurat_object)) {
      showNotification("Converting to Seurat v5 format for scCDC...", type = "message", duration = 5)
      seurat_object <<- UpdateSeuratObject(seurat_object)
      # Convert to v5 assay
      for (assay_name in names(seurat_object@assays)) {
        if (!is_assay5(seurat_object[[assay_name]])) {
          seurat_object[[assay_name]] <<- as(seurat_object[[assay_name]], "Assay5")
        }
      }
      showNotification("Converted to Seurat v5 format", type = "message", duration = 5)
    }

    # Set identity
    cluster_ident <- input$scCDCIdent
    if (!is.null(cluster_ident) && cluster_ident %in% colnames(seurat_object@meta.data)) {
      Idents(seurat_object) <<- cluster_ident
      showNotification(paste("Using cluster identity:", cluster_ident), type = "message", duration = 5)
    } else {
      showNotification("Invalid cluster identity. Using current Idents.", type = "warning", duration = 10)
    }

    # Check for problematic characters in identity names (underscores cause issues with Seurat's AverageExpression)
    ident_levels <- levels(Idents(seurat_object))
    has_underscore <- any(grepl("_", ident_levels))

    if (has_underscore) {
      showNotification(
        "Warning: Cluster names contain underscores ('_'). Seurat's AverageExpression converts '_' to '-', causing scCDC to fail. Converting '_' to '.' automatically.",
        type = "warning", duration = 15
      )

      # Convert underscores to dots in the meta.data column
      if (!is.null(cluster_ident) && cluster_ident %in% colnames(seurat_object@meta.data)) {
        seurat_object@meta.data[[cluster_ident]] <<- gsub("_", ".", seurat_object@meta.data[[cluster_ident]])
      }

      # Update Idents with converted names
      current_idents <- as.character(Idents(seurat_object))
      new_idents <- gsub("_", ".", current_idents)
      Idents(seurat_object) <<- factor(new_idents)

      showNotification(
        paste("Cluster names converted. Example:", ident_levels[1], "->", gsub("_", ".", ident_levels[1])),
        type = "message", duration = 10
      )
    }

    # Get parameters from UI
    restriction_factor <- input$scCDC_restriction_factor
    min_cell_detection <- input$scCDC_min_cell_detection
    percent_cutoff <- input$scCDC_percent_cutoff
    auc_thres <- input$scCDC_auc_thres
    min_cell_correction <- input$scCDC_min_cell_correction

    # Show parameters being used
    showNotification(
      paste0("Parameters: restriction_factor=", restriction_factor,
             ", min.cell(det)=", min_cell_detection,
             ", percent.cutoff=", percent_cutoff,
             ", auc_thres=", auc_thres,
             ", min.cell(cor)=", min_cell_correction),
      type = "message", duration = 10
    )

    # Step 1: Contamination Detection
    showNotification("Step 1/3: Detecting contamination-causing genes (GCGs)...", type = "message", duration = 5)
    GCGs <- ContaminationDetection(seurat_object,
                                   restriction_factor = restriction_factor,
                                   min.cell = min_cell_detection,
                                   percent.cutoff = percent_cutoff)
    num_GCGs_original <- nrow(GCGs)
    showNotification(paste("Detected", num_GCGs_original, "contamination-causing genes"), type = "message", duration = 10)

    # Parse and exclude specified genes
    exclude_genes_text <- input$scCDC_exclude_genes
    exclude_genes <- c()
    excluded_genes_found <- c()
    if (!is.null(exclude_genes_text) && nchar(trimws(exclude_genes_text)) > 0) {
      # Parse comma or newline separated genes
      exclude_genes <- unlist(strsplit(exclude_genes_text, "[,\n]+"))
      exclude_genes <- trimws(exclude_genes)
      exclude_genes <- exclude_genes[nchar(exclude_genes) > 0]

      # Find which excluded genes are in GCGs
      excluded_genes_found <- intersect(exclude_genes, rownames(GCGs))

      if (length(excluded_genes_found) > 0) {
        # Remove excluded genes from GCGs
        GCGs <- GCGs[!rownames(GCGs) %in% excluded_genes_found, , drop = FALSE]
        showNotification(
          paste("Excluded", length(excluded_genes_found), "genes from GCGs:",
                paste(excluded_genes_found, collapse = ", ")),
          type = "warning", duration = 15
        )
      }
    }

    num_GCGs <- nrow(GCGs)

    # Check if any GCGs remain
    if (num_GCGs == 0) {
      showNotification("No GCGs remaining after exclusion. Skipping correction.", type = "warning", duration = 15)
      removeModal()
      return()
    }

    # Step 2: Contamination Quantification
    showNotification("Step 2/3: Quantifying contamination ratio...", type = "message", duration = 5)
    contamination_ratio <- ContaminationQuantification(seurat_object, rownames(GCGs),
                                                       auc_thres = auc_thres,
                                                       min.cell = min_cell_correction)
    showNotification(paste("Contamination ratio:", round(contamination_ratio, 4)), type = "message", duration = 10)

    # Step 3: Contamination Correction
    showNotification("Step 3/3: Correcting contamination...", type = "message", duration = 5)
    seurat_object <<- ContaminationCorrection(seurat_object, rownames(GCGs),
                                              auc_thres = auc_thres,
                                              min.cell = min_cell_correction)

    # Join layers in Corrected assay if it's v5
    if (is_assay5(seurat_object[["Corrected"]])) {
      tryCatch({
        seurat_object[["Corrected"]] <<- JoinLayers(seurat_object[["Corrected"]])
        showNotification("Corrected assay layers are joined for SCALA compatibility", type = "message", duration = 5)
      }, error = function(e) {
        showNotification(paste("Warning: Could not join layers in Corrected assay:", e$message), type = "warning", duration = 10)
      })
    }

    # Switch to Corrected assay
    DefaultAssay(seurat_object) <<- "Corrected"
    showNotification("DefaultAssay has been switched to 'Corrected'", type = "message", duration = 10)

    # Prepare results display
    excluded_info <- ""
    if (length(excluded_genes_found) > 0) {
      excluded_info <- paste0(
        "--- Excluded genes ---\n",
        "Genes excluded from correction: ", length(excluded_genes_found), "\n",
        paste(excluded_genes_found, collapse = ", "), "\n\n"
      )
    }

    results_text <- paste0(
      "=== scCDC Analysis Results ===\n\n",
      "--- Parameters used ---\n",
      "restriction_factor: ", restriction_factor, "\n",
      "min.cell (Detection): ", min_cell_detection, "\n",
      "percent.cutoff: ", percent_cutoff, "\n",
      "auc_thres: ", auc_thres, "\n",
      "min.cell (Correction): ", min_cell_correction, "\n\n",
      "--- Results ---\n",
      "Originally detected GCGs: ", num_GCGs_original, "\n",
      excluded_info,
      "GCGs used for correction: ", num_GCGs, "\n",
      "Contamination ratio: ", round(contamination_ratio, 4), "\n\n",
      "Corrected GCGs (top 50):\n",
      paste(head(rownames(GCGs), 50), collapse = ", "), "\n\n",
      if (num_GCGs > 50) paste0("... and ", num_GCGs - 50, " more genes\n\n"),
      "\nCorrected count matrix has been stored in 'Corrected' assay.\n",
      "DefaultAssay has been automatically switched to 'Corrected'.\n",
      "You need to normalize and scale the corrected data before downstream analysis."
    )

    output$scCDCResults <- renderText({
      results_text
    })

    # Update assay selection choices
    updateUtilitiesAssays()

    showNotification("scCDC analysis completed successfully!", type = "message", duration = 15)
    showNotification("DefaultAssay switched to 'Corrected'. Please normalize and scale before use.",
                    type = "message", duration = 15)

  }, error = function(e) {
    showNotification(paste("Error in scCDC:", e$message), type = 'error', duration = 200)
    output$scCDCResults <- renderText({
      paste0("Error occurred:\n", e$message, "\n\nPlease check:\n",
            "1. scCDC package is installed\n",
            "2. Clustering information exists\n",
            "3. Seurat object is valid")
    })
  }, finally = {
    removeModal()
  })
})


#----Augur: Cell type prioritization

# Reactive value to store Augur results
augur_results <- reactiveValues(auc = NULL, plot = NULL)

observeEvent(input$runAugur, {
  tryCatch({
    if (identical(seurat_object, NULL)) {
      session$sendCustomMessage("handler_alert", "Please upload data via the DATA INPUT tab first.")
      return()
    }

    # Check if Augur package is installed
    if (!requireNamespace("Augur", quietly = TRUE)) {
      showNotification("Augur package is not installed. Please install it first: devtools::install_github('neurorestore/Augur')",
                      type = 'error', duration = 200)
      return()
    }

    showModal(modalDialog(div('Running Augur analysis. This may take several minutes depending on data size...',
                             style='color:#ffffff; background-color:#222d32;'),
                         footer = NULL,
                         style = 'font-size:20px; text-align:center;position:absolute;'))

    library(Augur)

    # Get parameters from UI
    cell_type_col <- input$augurCellTypeCol
    label_col <- input$augurLabelCol
    n_subsamples <- input$augurNsubsamples
    min_cells <- input$augurMinCells
    var_quantile <- input$augurVarQuantile

    # Validate columns exist
    if (!cell_type_col %in% colnames(seurat_object@meta.data)) {
      showNotification(paste("Cell type column not found:", cell_type_col), type = 'error', duration = 10)
      removeModal()
      return()
    }
    if (!label_col %in% colnames(seurat_object@meta.data)) {
      showNotification(paste("Condition column not found:", label_col), type = 'error', duration = 10)
      removeModal()
      return()
    }

    # Check that label column has exactly 2 levels
    label_levels <- unique(seurat_object@meta.data[[label_col]])
    if (length(label_levels) != 2) {
      showNotification(paste("Condition column must have exactly 2 levels (e.g., treatment vs control). Found:",
                            length(label_levels), "levels:", paste(label_levels, collapse = ", ")),
                      type = 'error', duration = 15)
      removeModal()
      return()
    }

    showNotification(paste("Running Augur with cell_type_col =", cell_type_col,
                          ", label_col =", label_col,
                          ", labels:", paste(label_levels, collapse = " vs ")),
                    type = "message", duration = 10)

    # Run Augur
    augur <- calculate_auc(seurat_object,
                          cell_type_col = cell_type_col,
                          label_col = label_col,
                          n_subsamples = n_subsamples,
                          min_cells = min_cells,
                          var_quantile = var_quantile)

    # Store results
    augur_results$auc <<- augur$AUC

    # Sort by AUC
    auc_df <- augur$AUC
    auc_df <- auc_df[order(auc_df$auc, decreasing = TRUE), ]

    # Generate lollipop plot
    augur_results$plot <<- plot_lollipop(augur)

    # Update output
    output$augurStatusText <- renderText({
      paste0("=== Augur Analysis Results ===\n\n",
             "Parameters used:\n",
             "  Cell type column: ", cell_type_col, "\n",
             "  Condition column: ", label_col, "\n",
             "  Conditions: ", paste(label_levels, collapse = " vs "), "\n",
             "  n_subsamples: ", n_subsamples, "\n",
             "  min_cells: ", min_cells, "\n",
             "  var_quantile: ", var_quantile, "\n\n",
             "Number of cell types analyzed: ", nrow(auc_df), "\n",
             "Top responding cell type: ", auc_df$cell_type[1], " (AUC = ", round(auc_df$auc[1], 3), ")\n",
             "Lowest responding cell type: ", auc_df$cell_type[nrow(auc_df)], " (AUC = ", round(auc_df$auc[nrow(auc_df)], 3), ")")
    })

    output$augurResultsTable <- renderTable({
      auc_df
    }, digits = 3)

    output$augurLollipopPlot <- renderPlot({
      augur_results$plot
    })

    showNotification("Augur analysis completed successfully!", type = "message", duration = 15)

  }, error = function(e) {
    showNotification(paste("Error in Augur:", e$message), type = 'error', duration = 200)
    output$augurStatusText <- renderText({
      paste0("Error occurred:\n", e$message, "\n\nPlease check:\n",
            "1. Augur package is installed (devtools::install_github('neurorestore/Augur'))\n",
            "2. Cell type column contains valid cell type annotations\n",
            "3. Condition column has exactly 2 levels (e.g., treatment vs control)\n",
            "4. Sufficient cells per cell type (min_cells parameter)")
    })
  }, finally = {
    removeModal()
  })
})

# Download handler for Augur results
output$downloadAugurResults <- downloadHandler(
  filename = function() {
    paste0("augur_auc_results_", Sys.Date(), ".csv")
  },
  content = function(file) {
    if (!is.null(augur_results$auc)) {
      write.csv(augur_results$auc, file, row.names = FALSE)
    }
  }
)

