output$downloadAugurPlot <- downloadHandler(
  filename = function() {
    paste0("augur_lollipop_plot_", Sys.Date(), ".pdf")
  },
  content = function(file) {
    if (!is.null(augur_results$plot)) {
      pdf(file, width = 8, height = 6)
      print(augur_results$plot)
      dev.off()
    }
  }
)


