observeEvent(input$confirmDemultiplex, {
    tryCatch({
            library(demuxmix)
        if (!is.null(seurat_object@assays$HTO)) {
        print('demultiplexing...')
withProgress(message = 'Calculation in progress', value=0.1, {
          showNotification("Hashtag demuliplexing using Seurat's HTODemux.")
          need_to_add <- FALSE
          tryCatch(
            {seurat_object <<- NormalizeData(seurat_object, assay = "HTO", normalization.method = "CLR")


            # HTODemux
            if (input$run_HTODemux) {
              tryCatch({ #これがすでにdemultiplexされたデータだとエラーになる カウントがゼロの細胞が多いため。
                seurat_object <<- HTODemux(seurat_object, assay = "HTO", positive.quantile = 0.99)
                  showNotification("Seurat HTODemux classifications are added to hash.ID", type = 'message', duration = 100)
               },  error = function(e){
               	showNotification("try again with adding 1 to all data")

               	tryCatch({
               	m <- GetAssayData(seurat_object, assay="HTO")
				m <- m +1
				new_assay <<- CreateAssayObject(counts=m)
				seurat_object[['HTOnew']] <<- new_assay
				seurat_object <<- NormalizeData(seurat_object, assay = "HTOnew", normalization.method = "CLR")
				seurat_object <<- HTODemux(seurat_object, assay = "HTOnew", positive.quantile = 0.99)
				need_to_add <- TRUE # demuxmixでも追加必要

			      showNotification("Seurat HTODemux classifications are added to hash.ID", type = 'message', duration = 100)
				},  error = function(e){
					showNotification("HTODemux error")
					showNotification(paste("Error :  ", e), type = 'error', duration=200)

				})
				})
            } else {
              showNotification("HTODemux skipped (not selected)", type = 'message', duration = 5)
            }

			# MULTIseqDemux
			if (input$run_MULTIseqDemux) {
			  tryCatch({ #これがすでにdemultiplexされたデータだとエラーになる カウントがゼロの細胞が多いため。
                seurat_object <<- MULTIseqDemux(seurat_object, assay = "HTO")
              showNotification("MULTIseqDemux classifications are added to MULTI_classification", type = 'message', duration = 100)
               },  error = function(e){
               	showNotification("try again with adding 1 to all data")
               	tryCatch({
               	m <- GetAssayData(seurat_object, assay="HTO")
				m <- m +1
				new_assay <<- CreateAssayObject(counts=m)
				seurat_object[['HTOnew']] <<- new_assay
				seurat_object <<- NormalizeData(seurat_object, assay = "HTOnew", normalization.method = "CLR")
				seurat_object <<- MULTIseqDemux(seurat_object, assay = "HTOnew")
				need_to_add <- TRUE # demuxmixでも追加必要
			      showNotification("MULTIseqDemux classifications are added to MULTI_classification", type = 'message', duration = 100)
				},  error = function(e){
					showNotification("MULTIseqDemux error")
					showNotification(paste("Error :  ", e), type = 'error', duration=200)

				})
				})
			} else {
			  showNotification("MULTIseqDemux skipped (not selected)", type = 'message', duration = 5)
			}

            # Generate HTOdemux plot if either HTODemux or MULTIseqDemux was run
            if (input$run_HTODemux || input$run_MULTIseqDemux) {
              tryCatch({
                print('before plot calc')
                Idents(seurat_object) <<- "HTO_maxID"
                plot <- RidgePlot(seurat_object, assay = "HTO",
                      features = rownames(seurat_object[["HTO"]])[1:dim(seurat_object@assays$HTO$counts)[1]], ncol=2)
                output$HTOdemuxPlot <- renderPlot({
                print(plot)}, height=140*(floor(dim(seurat_object@assays$HTO$counts)[1])+1), width=800)
                incProgress(0.2)
              }, error = function(e){
                showNotification("HTOdemux plot error.", type='error')
                showNotification(paste("Error :  ", e), type = 'error', duration=200)
              })
            }
          Idents(seurat_object) <<- "seurat_clusters"

          # demuxmix
          if (input$run_demuxmix) {
            showNotification("Start hashtag demuliplexing using demuxmix. This may take several minutes....")

          # Load demuxmix package on demand
          if (!"demuxmix" %in% loadedNamespaces()) {
            if (!requireNamespace("demuxmix", quietly = TRUE)) {
              showNotification("demuxmix package is not installed. Skipping demuxmix.", type='warning', duration=10)
            } else {
              suppressPackageStartupMessages(library(demuxmix))
            }
          }

          if (need_to_add){
		  hto <- as.matrix(m)
          	} else {
          hto <- as.matrix(seurat_object@assays$HTO$counts[])
      }
          rna <- as.vector(colSums(seurat_object[[DefaultAssay(seurat_object)]]$counts))
          set.seed(270123) #これがないとリモートではエラーになる
          incProgress(0.1)

          tryCatch({
            dmm <- demuxmix(hto, rna = rna)

          # Register results to meta.data first (before plot)
          incProgress(0.2)
          seurat_object@meta.data$demuxmix_hash_re <<-  factor(dmmClassify(dmm)$HTO)
          showNotification("demuxmix classifications are added to demuxmix_hash_re", type = 'message', duration = 100)

          # Plot generation
          incProgress(0.2)
          hash_num <- length(dmm@models)
          for (x in 1:hash_num){
            var_n <- paste0('p', as.character(x))
            assign(var_n, plotDmmHistogram(dmm, hto=x))
          }
          p <- if (hash_num == 1) {
            p1
          } else {
            plot_list <- mget(paste0('p', seq_len(hash_num)))
            nrow_val <- ceiling(hash_num / 3)
            cowplot::plot_grid(plotlist = plot_list, nrow = nrow_val)
          }

          incProgress(0.1)
          output$demuxmixPlot <- renderPlot({print(p)}, height=250*(floor(hash_num/3)+1), width=800)
        }, error = function(e){
          showNotification("demuxmix error. HTODemux and MULTIseqDemux results are still available.", type='warning', duration=30)
          print(paste("Demuxmix error details:", e$message))
        })
          } else {
            showNotification("demuxmix skipped (not selected)", type = 'message', duration = 5)
          }

      # hashDemux demultiplexing
      if (input$run_hashDemux) {
      showNotification("Start hashtag demuliplexing using hashDemux. This may take several minutes....")
      tryCatch({
        print("=== hashDemux: Starting demultiplexing ===")

        # Load required packages on demand
        print("hashDemux: Loading required packages...")
        required_packages <- c("dplyr", "doParallel", "foreach")
        for (pkg in required_packages) {
          if (!pkg %in% loadedNamespaces()) {
            if (!requireNamespace(pkg, quietly = TRUE)) {
              stop(paste("Required package not found:", pkg))
            }
            suppressPackageStartupMessages(library(pkg, character.only = TRUE))
          }
        }
        print("hashDemux: All required packages loaded")

        # Load hashDemux functions from local directory (Seurat5-compatible version)
        print("hashDemux: Loading demultiplexing_fixed.R...")
        source('Rfunc/demultiplexing_fixed.R')
        print("hashDemux: demultiplexing_fixed.R loaded successfully")

        # Check which assay to use
        assay_name <- if (need_to_add) "HTOnew" else "HTO"
        print(paste("hashDemux: Using assay:", assay_name))

        # Check if assay exists (compatible with Seurat v4 and v5)
        available_assays <- tryCatch({
          as.character(Assays(seurat_object))
        }, error = function(e) {
          names(seurat_object@assays)
        })
        print(paste("hashDemux: Available assays:", paste(available_assays, collapse=", ")))

        if (!assay_name %in% available_assays) {
          stop(paste("Assay not found:", assay_name))
        }
        print(paste("hashDemux: Assay", assay_name, "found with", nrow(seurat_object[[assay_name]]), "features"))

        # Ensure HTO assay is normalized with CLR (margin=2 for hashDemux)
        print("hashDemux: Normalizing data with CLR (margin=2)...")
        seurat_object <<- NormalizeData(seurat_object, assay = assay_name, normalization.method = "CLR", margin = 2)
        print("hashDemux: Normalization complete")

        # Run clustering_based_demux
        print("hashDemux: Running clustering_based_demux...")
        seurat_object <<- clustering_based_demux(seurat_object, assay = assay_name)
        print("hashDemux: clustering_based_demux complete")

        showNotification("hashDemux classifications are added to sampleBC, classification, and confidence_score", type = 'message', duration = 100)

        # Display results
        print("=== hashDemux results ===")
        print(paste0("Singlets: ", sum(seurat_object$classification == "Singlet")))
        print(paste0("Doublets: ", sum(seurat_object$classification == "Doublet")))
        print(paste0("Negatives: ", sum(seurat_object$classification == "Negative")))

        # HTO UMAP for hashDemux visualization
        tryCatch({
          # ScaleData + PCA + UMAP on HTO assay
          seurat_object <<- ScaleData(seurat_object, assay = assay_name, verbose = FALSE)
          n_features <- nrow(seurat_object[[assay_name]])
          seurat_object <<- RunPCA(seurat_object, assay = assay_name,
            features = rownames(seurat_object[[assay_name]]),
            npcs = n_features - 1, reduction.name = "hto_pca", verbose = FALSE)
          seurat_object <<- RunUMAP(seurat_object,
            dims = 1:(n_features - 1), reduction = "hto_pca",
            reduction.name = "hto_umap", seed.use = 42, verbose = FALSE)

          output$hashDemuxUMAP <- renderPlot({
            # sampleBC で色分け（Doublet は Doublet 表記に統一）
            plot_labels <- as.character(seurat_object$sampleBC)
            plot_labels[seurat_object$classification == "Doublet"] <- "Doublet"
            seurat_object$hashDemux_plot_label <<- plot_labels
            DimPlot(seurat_object, reduction = "hto_umap", group.by = "hashDemux_plot_label",
                    label = TRUE, repel = TRUE) +
              ggtitle("hashDemux: HTO-space UMAP") +
              theme(plot.title = element_text(hjust = 0.5))
          })
        }, error = function(e) {
          output$hashDemuxUMAP <- renderPlot({
            plot.new(); text(0.5, 0.5, paste("UMAP plot error:", e$message))
          })
        })

        # HTO Expression Heatmap
        tryCatch({
          output$hashDemuxHeatmap <- renderPlot({
            hto_data <- GetAssayData(seurat_object, assay = assay_name, layer = "data")
            hto_matrix <- as.matrix(hto_data)
            # sampleBC ごとの平均発現
            sample_labels <- as.character(seurat_object$sampleBC)
            sample_labels[seurat_object$classification == "Doublet"] <- "Doublet"
            unique_labels <- sort(unique(sample_labels))
            avg_expr <- sapply(unique_labels, function(lab) {
              cells <- which(sample_labels == lab)
              if (length(cells) > 1) rowMeans(hto_matrix[, cells, drop=FALSE])
              else hto_matrix[, cells]
            })
            colnames(avg_expr) <- unique_labels
            pheatmap::pheatmap(avg_expr, cluster_rows = FALSE, cluster_cols = FALSE,
              main = "hashDemux: Average HTO Expression by Assignment",
              color = colorRampPalette(c("white", "orange", "red"))(100))
          })
        }, error = function(e) {
          output$hashDemuxHeatmap <- renderPlot({
            plot.new(); text(0.5, 0.5, paste("Heatmap error:", e$message))
          })
        })

        # Confidence Score Distribution
        tryCatch({
          output$hashDemuxConfidence <- renderPlot({
            if ("confidence_score" %in% colnames(seurat_object@meta.data)) {
              df <- data.frame(
                confidence = as.numeric(as.character(seurat_object$confidence_score)),
                classification = as.character(seurat_object$classification)
              )
              ggplot(df, aes(x = confidence, fill = classification)) +
                geom_histogram(bins = 50, alpha = 0.7, position = "identity") +
                scale_fill_manual(values = c("Singlet"="#2196F3", "Doublet"="#f44336", "Negative"="#9E9E9E")) +
                theme_bw() +
                labs(x = "Confidence Score", y = "Count",
                     title = "hashDemux: Confidence Score Distribution")
            } else {
              plot.new(); text(0.5, 0.5, "Confidence score not available (single knn/resolution)")
            }
          })
        }, error = function(e) {
          output$hashDemuxConfidence <- renderPlot({
            plot.new(); text(0.5, 0.5, paste("Confidence plot error:", e$message))
          })
        })

        # Output to UI
        output$hashDemuxText <- renderText({
          paste0("hashDemux Results:\n",
                 "Singlets: ", sum(seurat_object$classification == "Singlet"), "\n",
                 "Doublets: ", sum(seurat_object$classification == "Doublet"), "\n",
                 "Negatives: ", sum(seurat_object$classification == "Negative"))
        })

      }, error = function(e){
        error_msg <- paste("hashDemux error:", e$message)
        print("===========================================")
        print(error_msg)
        print("Full error traceback:")
        print(traceback())
        print("===========================================")
        showNotification(paste("hashDemux error:", e$message, "- HTODemux, MULTIseqDemux and demuxmix results are still available."), type='warning', duration=30)
      })
      } else {
        showNotification("hashDemux skipped (not selected)", type = 'message', duration = 5)
      }

      # deMULTIplex2 demultiplexing
      if (input$run_deMULTIplex2) {
      showNotification("Start hashtag demuliplexing using deMULTIplex2. This may take several minutes....")
      tryCatch({
        print("=== deMULTIplex2: Starting demultiplexing ===")

        # Load deMULTIplex2 package on demand
        # First check if already loaded
        if (!"deMULTIplex2" %in% loadedNamespaces()) {
          if (!requireNamespace("deMULTIplex2", quietly = TRUE)) {
            stop("deMULTIplex2 package is not installed. Please install it using: devtools::install_github('Gartner-Lab/deMULTIplex2')")
          }
          suppressPackageStartupMessages(library(deMULTIplex2))
          print("deMULTIplex2: Package loaded successfully")
        } else {
          print("deMULTIplex2: Package already loaded")
        }

        # Determine which assay to use
        assay_name <- if (need_to_add) "HTOnew" else "HTO"
        print(paste("deMULTIplex2: Using assay:", assay_name))

        # Get HTO data and transpose to cells x tags format (deMULTIplex2 requires this)
        hto_data <- GetAssayData(object = seurat_object, assay = assay_name, layer = "counts")
        tag_mtx <- t(as.matrix(hto_data))
        print(paste("deMULTIplex2: Tag matrix prepared with", nrow(tag_mtx), "cells and", ncol(tag_mtx), "tags"))

        # Run deMULTIplex2
        print("deMULTIplex2: Running demultiplexTags...")
        demux2_res <- demultiplexTags(tag_mtx,
                                      plot.umap = "residual",  # Generate UMAP for diagnostic plots
                                      plot.diagnostics = FALSE)
        print("deMULTIplex2: demultiplexTags complete")

        # Add results to Seurat object metadata
        # Check structure and extract appropriately
        if (!is.null(demux2_res$final_assign)) {
          seurat_object$deMULTIplex2_assign <<- demux2_res$final_assign
        }

        # Try different ways to get the Type information
        if (!is.null(demux2_res$assign_table)) {
          if ("Type" %in% colnames(demux2_res$assign_table)) {
            seurat_object$deMULTIplex2_type <<- demux2_res$assign_table$Type
          } else if ("type" %in% colnames(demux2_res$assign_table)) {
            seurat_object$deMULTIplex2_type <<- demux2_res$assign_table$type
          }
        }

        # If Type column not found, classify based on final_assign
        if (!"deMULTIplex2_type" %in% colnames(seurat_object@meta.data) && !is.null(demux2_res$final_assign)) {
          seurat_object$deMULTIplex2_type <<- ifelse(
            grepl("_", demux2_res$final_assign), "multiplet",
            ifelse(demux2_res$final_assign == "Negative", "negative", "singlet")
          )
        }

        # Count results
        if ("deMULTIplex2_type" %in% colnames(seurat_object@meta.data)) {
          n_singlet <- sum(seurat_object$deMULTIplex2_type == "singlet", na.rm = TRUE)
          n_multiplet <- sum(seurat_object$deMULTIplex2_type == "multiplet", na.rm = TRUE)
          n_negative <- sum(seurat_object$deMULTIplex2_type == "negative", na.rm = TRUE)
        } else {
          n_singlet <- sum(!grepl("_", demux2_res$final_assign) & demux2_res$final_assign != "Negative", na.rm = TRUE)
          n_multiplet <- sum(grepl("_", demux2_res$final_assign), na.rm = TRUE)
          n_negative <- sum(demux2_res$final_assign == "Negative", na.rm = TRUE)
        }

        print("=== deMULTIplex2 results ===")
        print(paste0("Singlets: ", n_singlet))
        print(paste0("Multiplets: ", n_multiplet))
        print(paste0("Negatives: ", n_negative))

        showNotification("deMULTIplex2 classifications are added to deMULTIplex2_assign and deMULTIplex2_type", type = 'message', duration = 100)

        # Generate tagHist plot
        print("deMULTIplex2: Generating tagHist plot...")
        output$deMULTIplex2_tagHist <- renderPlot({
          tryCatch({
            tagHist(tag_mtx = tag_mtx, minUMI = 10, plotnUMI = TRUE)
          }, error = function(e) {
            plot.new()
            text(0.5, 0.5, paste("tagHist plot error:", e$message))
          })
        })

        # Generate tagCallHeatmap
        print("deMULTIplex2: Generating tagCallHeatmap...")
        output$deMULTIplex2_heatmap <- renderPlot({
          tryCatch({
            tagCallHeatmap(tag_mtx = tag_mtx, calls = demux2_res$final_assign)
          }, error = function(e) {
            plot.new()
            text(0.5, 0.5, paste("Heatmap plot error:", e$message))
          })
        })

        # Diagnostic: Per-tag posterior probability distribution
        tryCatch({
          output$deMULTIplex2_posterior <- renderPlot({
            prob_mtx <- demux2_res$prob_mtx
            tag_names <- colnames(prob_mtx)
            df_post <- data.frame(
              probability = as.vector(prob_mtx),
              tag = rep(tag_names, each = nrow(prob_mtx))
            )
            ggplot(df_post, aes(x = probability)) +
              geom_histogram(bins = 50, fill = "#2196F3", alpha = 0.7, color = "white") +
              geom_vline(xintercept = 0.5, color = "red", linetype = "dashed", linewidth = 0.8) +
              facet_wrap(~ tag, scales = "free_y") +
              theme_bw() +
              labs(x = "Posterior Probability", y = "Count",
                   title = "deMULTIplex2: Per-tag Posterior Probability Distribution",
                   subtitle = "Red line = 0.5 threshold. Peaks near 0.5 indicate uncertain classification")
          })
        }, error = function(e) {
          output$deMULTIplex2_posterior <- renderPlot({
            plot.new(); text(0.5, 0.5, paste("Posterior plot error:", e$message))
          })
        })

        # Diagnostic: Per-tag UMAP colored by posterior probability
        tryCatch({
          output$deMULTIplex2_umapPosterior <- renderPlot({
            umap_coords <- demux2_res$umap
            prob_mtx <- demux2_res$prob_mtx
            tag_names <- colnames(prob_mtx)
            df_umap <- do.call(rbind, lapply(tag_names, function(tag) {
              data.frame(
                UMAP_1 = umap_coords[, 1],
                UMAP_2 = umap_coords[, 2],
                posterior = prob_mtx[, tag],
                tag = tag
              )
            }))
            ggplot(df_umap, aes(x = UMAP_1, y = UMAP_2, color = posterior)) +
              geom_point(size = 0.3, alpha = 0.6) +
              scale_color_gradientn(colors = c("grey90", "blue", "green", "red"),
                                    values = c(0, 0.3, 0.6, 1),
                                    name = "Posterior") +
              facet_wrap(~ tag) +
              theme_bw() +
              theme(aspect.ratio = 1) +
              labs(title = "deMULTIplex2: Per-tag UMAP by Posterior Probability",
                   subtitle = "Scattered high-posterior cells suggest background contamination")
          })
        }, error = function(e) {
          output$deMULTIplex2_umapPosterior <- renderPlot({
            plot.new(); text(0.5, 0.5, paste("UMAP posterior plot error:", e$message))
          })
        })

        # Output text summary
        output$deMULTIplex2Text <- renderText({
          paste0("deMULTIplex2 Results:\n",
                 "Singlets: ", n_singlet, "\n",
                 "Multiplets: ", n_multiplet, "\n",
                 "Negatives: ", n_negative)
        })

      }, error = function(e){
        error_msg <- paste("deMULTIplex2 error:", e$message)
        print("===========================================")
        print(error_msg)
        print("Full error traceback:")
        print(traceback())
        print("===========================================")
        showNotification(paste("deMULTIplex2 error:", e$message, "- Other demultiplexing results are still available."), type='warning', duration=30)
      })
      } else {
        showNotification("deMULTIplex2 skipped (not selected)", type = 'message', duration = 5)
      }

      # ===== Algorithm Comparison Visualizations =====
      cat("\n=== Generating Algorithm Comparison Visualizations ===\n")

      # Helper function: Get detailed classification (keep HTO tags for singlets)
      # Modified to use hashDemux singlet determination as reference:
      # - If hashDemux identifies a cell as Singlet, use detailed tag info
      # - Otherwise (Multiplet/Negative), collapse all to "Non-Singlet"
      get_detailed_classification <- function(classification, tag_assignment, algorithm_name, hashDemux_singlets = NULL) {
        if (algorithm_name == "HTODemux") {
          # Keep tag name for singlets, "Doublet" becomes "Multiplet"
          result <- as.character(tag_assignment)
          result[classification == "Doublet"] <- "Multiplet"
          result[classification == "Negative"] <- "Negative"
        } else if (algorithm_name == "MULTIseqDemux") {
          # Keep tag name for singlets, tags with "_" become "Multiplet"
          result <- as.character(classification)
          result[grepl("_", classification)] <- "Multiplet"
        } else if (algorithm_name == "demuxmix") {
          # Keep tag name for singlets, tags with "," become "Multiplet"
          result <- as.character(classification)
          result[grepl(",", classification)] <- "Multiplet"
          result[classification %in% c("negative", "uncertain")] <- "Negative"
        } else if (algorithm_name == "hashDemux") {
          # Keep tag name for singlets, "Doublet" becomes "Multiplet"
          result <- as.character(tag_assignment)
          result[classification == "Doublet"] <- "Multiplet"
          result[classification == "Negative"] <- "Negative"
        } else if (algorithm_name == "deMULTIplex2") {
          # Keep tag name for singlets
          result <- as.character(tag_assignment)
          result[grepl("_", tag_assignment)] <- "Multiplet"
          result[tag_assignment == "Negative"] <- "Negative"
        } else {
          result <- as.character(classification)
        }

        # Apply hashDemux singlet filter if provided
        if (!is.null(hashDemux_singlets)) {
          # For cells NOT identified as singlet by hashDemux, replace with "Non-Singlet"
          result[!hashDemux_singlets] <- "Non-Singlet"
        }

        return(result)
      }

      # Collect available algorithm results (detailed classification with HTO tags)
      algorithms_available <- list()

      # Determine hashDemux singlets (if hashDemux was run)
      hashDemux_singlets <- NULL
      if ("classification" %in% colnames(seurat_object@meta.data)) {
        hashDemux_singlets <- (seurat_object$classification == "Singlet")
        cat(paste("Using hashDemux singlet determination:", sum(hashDemux_singlets, na.rm=TRUE), "singlets out of", length(hashDemux_singlets), "cells\n"))
      }

      if ("HTO_classification.global" %in% colnames(seurat_object@meta.data) &&
          "HTO_maxID" %in% colnames(seurat_object@meta.data)) {
        algorithms_available$HTODemux <- get_detailed_classification(
          seurat_object$HTO_classification.global,
          seurat_object$HTO_maxID,
          "HTODemux",
          hashDemux_singlets)
      }
      if ("MULTI_classification" %in% colnames(seurat_object@meta.data)) {
        algorithms_available$MULTIseqDemux <- get_detailed_classification(
          seurat_object$MULTI_classification,
          seurat_object$MULTI_classification,
          "MULTIseqDemux",
          hashDemux_singlets)
      }
      if ("demuxmix_hash_re" %in% colnames(seurat_object@meta.data)) {
        algorithms_available$demuxmix <- get_detailed_classification(
          seurat_object$demuxmix_hash_re,
          seurat_object$demuxmix_hash_re,
          "demuxmix",
          hashDemux_singlets)
      }
      if ("classification" %in% colnames(seurat_object@meta.data) &&
          "sampleBC" %in% colnames(seurat_object@meta.data)) {
        algorithms_available$hashDemux <- get_detailed_classification(
          seurat_object$classification,
          seurat_object$sampleBC,
          "hashDemux",
          NULL)  # hashDemux doesn't filter itself
      }
      if ("deMULTIplex2_assign" %in% colnames(seurat_object@meta.data)) {
        algorithms_available$deMULTIplex2 <- get_detailed_classification(
          seurat_object$deMULTIplex2_assign,
          seurat_object$deMULTIplex2_assign,
          "deMULTIplex2",
          hashDemux_singlets)
      }

      # Only generate visualizations if we have at least 2 algorithms
      if (length(algorithms_available) >= 2) {
        cat(paste("Found", length(algorithms_available), "algorithms to compare\n"))

        # === 1. Agreement Heatmap with Clustering ===
        output$demuxAgreementHeatmap <- renderPlot({
          tryCatch({
            if (!requireNamespace("pheatmap", quietly = TRUE)) {
              plot.new()
              text(0.5, 0.5, "pheatmap package required")
              return(NULL)
            }
            suppressPackageStartupMessages(library(pheatmap))

            n_alg <- length(algorithms_available)
            agreement_matrix <- matrix(0, nrow = n_alg, ncol = n_alg)
            rownames(agreement_matrix) <- colnames(agreement_matrix) <- names(algorithms_available)

            for (i in 1:n_alg) {
              for (j in 1:n_alg) {
                alg1 <- algorithms_available[[i]]
                alg2 <- algorithms_available[[j]]
                agreement_matrix[i, j] <- sum(alg1 == alg2, na.rm = TRUE) /
                                         sum(!is.na(alg1) & !is.na(alg2))
              }
            }

            pheatmap(agreement_matrix,
                     display_numbers = TRUE,
                     number_format = "%.3f",
                     cluster_rows = TRUE,
                     cluster_cols = TRUE,
                     clustering_distance_rows = as.dist(1 - agreement_matrix),
                     clustering_distance_cols = as.dist(1 - agreement_matrix),
                     color = colorRampPalette(c("white", "lightblue", "blue"))(100),
                     main = "Agreement Between Demultiplexing Algorithms",
                     fontsize = 12,
                     fontsize_number = 10)
          }, error = function(e) {
            plot.new()
            text(0.5, 0.5, paste("Error generating heatmap:", e$message))
          })
        })

        # === 2. UpSet Plot ===
        output$demuxUpsetPlot <- renderPlot({
          tryCatch({
            if (!requireNamespace("UpSetR", quietly = TRUE)) {
              plot.new()
              text(0.5, 0.5, "UpSetR package required\nInstall with: install.packages('UpSetR')")
              return(NULL)
            }
            suppressPackageStartupMessages(library(UpSetR))

            # Create binary matrix: 1 if cell is assigned to specific tag, 0 otherwise
            # Exclude Multiplet and Negative, keep individual HTO tags
            upset_data <- as.data.frame(lapply(algorithms_available, function(x) {
              as.integer(!(x %in% c("Multiplet", "Negative", "Non-Singlet")))
            }))

            upset(upset_data,
                  sets = names(algorithms_available),
                  nsets = length(algorithms_available),
                  nintersects = NA,
                  empty.intersections = "on",
                  order.by = "freq",
                  text.scale = c(1.3, 1.3, 1, 1, 1.5, 1.2),
                  mainbar.y.label = "Number of Cells with Agreement",
                  sets.x.label = "Total Assigned Cells per Algorithm",
                  main.bar.color = "steelblue",
                  sets.bar.color = "darkgreen")
          }, error = function(e) {
            plot.new()
            text(0.5, 0.5, paste("Error generating UpSet plot:", e$message))
          })
        })

        # === 3. Alluvial Diagram ===
        output$demuxAlluvialPlot <- renderPlot({
          tryCatch({
            if (!requireNamespace("ggalluvial", quietly = TRUE) ||
                !requireNamespace("dplyr", quietly = TRUE)) {
              plot.new()
              text(0.5, 0.5, "ggalluvial and dplyr packages required\nInstall with: install.packages('ggalluvial')")
              return(NULL)
            }
            suppressPackageStartupMessages(library(ggalluvial))
            suppressPackageStartupMessages(library(dplyr))
            suppressPackageStartupMessages(library(ggplot2))

            # Create comparison dataframe
            comparison_df <- as.data.frame(algorithms_available)
            comparison_df$count <- 1

            # Aggregate by unique combinations
            comparison_summary <- comparison_df %>%
              group_by(across(names(algorithms_available))) %>%
              summarise(count = sum(count), .groups = "drop")

            # Create alluvial plot
            p <- ggplot(comparison_summary,
                       aes_string(y = "count",
                                 axis1 = names(algorithms_available)[1],
                                 axis2 = if(length(algorithms_available) >= 2) names(algorithms_available)[2] else NULL,
                                 axis3 = if(length(algorithms_available) >= 3) names(algorithms_available)[3] else NULL,
                                 axis4 = if(length(algorithms_available) >= 4) names(algorithms_available)[4] else NULL,
                                 axis5 = if(length(algorithms_available) >= 5) names(algorithms_available)[5] else NULL)) +
              geom_alluvium(aes_string(fill = names(algorithms_available)[1]), width = 1/12, alpha = 0.8) +
              geom_stratum(width = 1/12, fill = "white", color = "black") +
              geom_text(stat = "stratum", aes(label = after_stat(stratum)), size = 3) +
              scale_x_discrete(limits = names(algorithms_available), expand = c(.05, .05)) +
              scale_fill_brewer(palette = "Set2") +
              theme_minimal() +
              labs(title = "Classification Flow Across Algorithms",
                   y = "Number of Cells",
                   fill = names(algorithms_available)[1]) +
              theme(axis.text.x = element_text(angle = 45, hjust = 1, size = 10),
                    legend.position = "bottom")

            print(p)
          }, error = function(e) {
            plot.new()
            text(0.5, 0.5, paste("Error generating Alluvial plot:", e$message))
          })
        })

        showNotification("Algorithm comparison visualizations generated", type = 'message', duration = 5)
      } else {
        cat("Not enough algorithms to compare (need at least 2)\n")
        output$demuxAgreementHeatmap <- renderPlot({
          plot.new()
          text(0.5, 0.5, "Run at least 2 algorithms to compare results")
        })
        output$demuxUpsetPlot <- renderPlot({
          plot.new()
          text(0.5, 0.5, "Run at least 2 algorithms to compare results")
        })
        output$demuxAlluvialPlot <- renderPlot({
          plot.new()
          text(0.5, 0.5, "Run at least 2 algorithms to compare results")
        })
      }

      updateSelInpColor()
      session$sendCustomMessage("handler_enableTabs", c(" UTILITY IDENTITY & ASSAY", " UTILITY CLUSTER"))
            }, error = function(e){
              showNotification("Demultiplexing error")
              showNotification(paste("Error :  ", e), type = 'error', duration=200)
            }
          ) # tryCatch (7647行目) の終わり
        }) # withProgress (7644行目) の終わり
        } # if (!is.null(seurat_object@assays$HTO)) (7642行目) の終わり
    }, error = function(e){
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
    }) # tryCatch (7640行目) の終わり
})  # observeEvent (7639行目) の終わり


   observeEvent(input$confirmDiet, {
 # これだとサイズ変わらない   seurat_object <<- DietSeurat(seurat_object, scale.data = TRUE, assays = 'RNA', dimreducs = names(seurat_object@reductions) )
 tryCatch({   seurat_object <<- DietSeurat(seurat_object, assays = DefaultAssay(seurat_object) )

 #    init_seurat_object  <<- seurat_object
        showNotification("Finished dieting")
    print(str(seurat_object))
    }, error = function(e) {
      showNotification("DietSeurat error.", type='error')
      showNotification("You may try Seurat V.5")
      })
    })

  output$DownloadExp <- downloadHandler(
    filename = function() {
      paste0("Expr_", format(Sys.Date(), "%Y%m%d"), ".zip")
    },
    content = function(file) {
      withProgress(message = 'Preparing download', value = 0, {
        tryCatch({
          if (input$Exprtranspose){
       #     expr <- t(seurat_object[[seurat_object@active.assay]][input$selectExp])
       expr <- t(GetAssayData(seurat_object, layer = input$selectExp))
          } else {
       #     expr <- seurat_object[[seurat_object@active.assay]][input$selectExp]
       expr <- GetAssayData(seurat_object, layer = input$selectExp)
          }
          expr <- as.matrix(expr)
          
          incProgress(0.3, detail = "Processing data")

          if (input$typeExp == "csv"){
            sep <- ','
          } else {
            sep <- '\t'
          }
          
          # 一時的なTSVファイルを作成
          temp_tsv <- tempfile(fileext = paste0(".",input$typeExp))
          write.table(expr, temp_tsv, sep = sep, quote = FALSE, col.names = NA)
          
          incProgress(0.3, detail = "Creating TSV file")
          
          # ZIPファイル内のTSVファイル名を設定
          tsv_filename <- paste0("Expr_", format(Sys.Date(), "%Y%m%d"), ".", input$typeExp)
          
          # TSVファイルをZIP圧縮（ファイル名を指定）
          zip(zipfile = file, files = setNames(temp_tsv, tsv_filename))
          
          incProgress(0.4, detail = "Compressing file")
          
          # 一時ファイルを削除
          unlink(temp_tsv)
        }, error = function(e) {
          showNotification(paste("Error: ", e$message), type = 'error', duration = NULL)
        })
      })
    },
    contentType = "application/zip"
  )

