    content = function(file) {
      write.table(seurat_object[[]], file, sep = "\t", quote=FALSE, col.names=NA)
    })



read_meta_file <- function(file_info) {
  # Get file extension
  file_ext <- tolower(tools::file_ext(file_info$name))
  
  if (file_ext == "rds") {
    return(readRDS(file_info$datapath))
  } else if (file_ext == "gz") {
    # For gzipped files, detect the delimiter in the uncompressed content
    con <- gzfile(file_info$datapath, "rt")
    first_line <- readLines(con, n = 1)
    close(con)
    
    con <- gzfile(file_info$datapath, "rt")
    if (grepl(",", first_line)) {
      meta <- read.table(con, header = TRUE, row.names = 1, sep = ",", stringsAsFactors = FALSE)
    } else if (grepl("\t", first_line)) {
      meta <- read.table(con, header = TRUE, row.names = 1, sep = "\t", stringsAsFactors = FALSE)
    } else {
      meta <- read.table(con, header = TRUE, row.names = 1, sep = " ", stringsAsFactors = FALSE)
    }
    close(con)
    
    # Convert numeric columns
    meta <- type.convert(meta, as.is = TRUE)
    return(meta)
  } else {
    # For regular files, try different delimiters
    tryCatch({
      # Try tab first (original behavior)
      meta <- read.table(file_info$datapath, header = TRUE, row.names = 1, sep = "\t", stringsAsFactors = FALSE)
      meta <- type.convert(meta, as.is = TRUE)
      return(meta)
    }, error = function(e1) {
      tryCatch({
        # Try comma next
        meta <- read.table(file_info$datapath, header = TRUE, row.names = 1, sep = ",", stringsAsFactors = FALSE)
        meta <- type.convert(meta, as.is = TRUE)
        return(meta)
      }, error = function(e2) {
        # Finally try space
        meta <- read.table(file_info$datapath, header = TRUE, row.names = 1, sep = " ", stringsAsFactors = FALSE)
        meta <- type.convert(meta, as.is = TRUE)
        return(meta)
      })
    })
  }
}

