## Load cellranger annotate results
observeEvent(input$loadCellrangerAnnotate, {
  tryCatch({
    if (is.integer(input$cellrangerAnnotateFile)) {
      showNotification("Please select a cell_types.csv file first", type = "error")
      return()
    }

    showModal(modalDialog(
      div('Loading cellranger annotate results...',
          style='color:#ffffff; background-color:#222d32;'),
      footer = NULL))

    file_selected <- parseFilePaths(volumes, input$cellrangerAnnotateFile)
    file_path <- as.character(file_selected$datapath)

    # cell_types.csv を読み込み (barcode が named column)
    meta <- read.csv(file_path, stringsAsFactors = FALSE)

    # barcode 列をチェック
    if (!"barcode" %in% colnames(meta)) {
      removeModal()
      showNotification("barcode column not found in file", type = "error")
      return()
    }

    # barcode を rownames に設定
    rownames(meta) <- meta$barcode
    meta$barcode <- NULL
    # umi_count は既存の nCount_RNA と重複するので除外
    meta$umi_count <- NULL

    # 既存メタデータ
    meta_org <- seurat_object[[]]
    meta_org['meta_org.row.names'] <- row.names(meta_org)

    # barcode マッチング
    current_cells <- rownames(meta_org)
    meta_cells <- rownames(meta)

    # 1. exact match
    exact_matched <- sum(meta_cells %in% current_cells)
    exact_match_ratio <- exact_matched / length(meta_cells)

    if (exact_match_ratio >= 0.5) {
      showNotification(
        paste("Exact match:", exact_matched, "/", length(meta_cells), "cells"),
        type = "message", duration = 5)
    } else {
      # 2. barcode extraction fallback
      extract_barcode <- function(cell_names) {
        barcodes <- sub("^.*_", "", cell_names)
        barcodes <- gsub("-[0-9]+$", "", barcodes)
        return(barcodes)
      }
      current_barcodes <- extract_barcode(current_cells)
      meta_barcodes <- extract_barcode(meta_cells)

      barcode_to_current <- setNames(current_cells, current_barcodes)
      matched_barcodes <- meta_barcodes[meta_barcodes %in% current_barcodes]

      if (length(matched_barcodes) == 0) {
        removeModal()
        showNotification("No matching barcodes found", type = "error")
        return()
      }

      # meta の rownames を current_cells に合わせる
      new_rownames <- barcode_to_current[meta_barcodes]
      valid <- !is.na(new_rownames)
      meta <- meta[valid, , drop = FALSE]
      rownames(meta) <- new_rownames[valid]

      showNotification(
        paste("Barcode match:", sum(valid), "/", length(meta_barcodes), "cells"),
        type = "message", duration = 5)
    }

    # 新規カラムのみ追加
    new_columns <- setdiff(colnames(meta), colnames(meta_org))
    if (length(new_columns) == 0) {
      removeModal()
      showNotification("No new columns to add (all columns already exist)", type = "warning")
      return()
    }

    meta <- meta[new_columns]
    meta['meta.row.names'] <- row.names(meta)

    # merge
    meta_new <- merge(meta_org, meta,
                      by.x = 'meta_org.row.names', by.y = 'meta.row.names',
                      all.x = TRUE)
    rownames(meta_new) <- meta_new$meta_org.row.names
    meta_new$meta_org.row.names <- NULL
    meta_new <- meta_new[row.names(meta_org), ]

    # cell type カラムは factor に変換
    for (col in new_columns) {
      if (col %in% colnames(meta_new)) {
        vals <- meta_new[[col]]
        if (is.character(vals)) {
          meta_new[[col]] <- as.factor(vals)
        } else if (is.numeric(vals)) {
          meta_new[[col]] <- as.numeric(vals)
        }
      }
    }

    # Seurat に適用
    seurat_object[[]] <<- meta_new
    updateMetadata()
    updateSelInpColor()

    removeModal()
    showNotification(
      paste("Added", length(new_columns), "columns:", paste(new_columns, collapse = ", ")),
      type = "message", duration = 10)

  }, error = function(e) {
    removeModal()
    showNotification(paste("Error:", e$message), type = "error", duration = 10)
  })
})

observeEvent(input$uploadMeta, {
  tryCatch({
    if (!is.null(input$metaUploadFile)) {
      # Read metadata file with extended format support
       showModal(modalDialog(div('Adding metadata. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%
      meta <- read_meta_file(input$metaUploadFile)
      print("Loaded metadata head:")
      print(head(meta))
      
      # Get current metadata
      meta_org <- seurat_object[[]]
      meta_org['meta_org.row.names'] <- row.names(meta_org)
      
      # Check if ignore order option is selected
      if (input$ignoreOrderMeta) {
        # Add metadata in order regardless of cell names
        if (nrow(meta) != nrow(meta_org)) {
          removeModal()
          showNotification(
            paste("Error: Number of cells in metadata (", nrow(meta), ") does not match Seurat object (", nrow(meta_org), ")"), 
            type = "error",
            duration = 10
          )
          return()
        }
        
        # Add metadata in order
        rownames(meta) <- rownames(meta_org)
        
      } else {
        # Check cell name matching
        current_cells <- rownames(meta_org)
        meta_cells <- rownames(meta)

        # First, check if cell names match exactly (no barcode extraction needed)
        exact_matched <- sum(meta_cells %in% current_cells)
        exact_match_ratio <- exact_matched / length(meta_cells)

        if (exact_match_ratio >= 0.5) {
          # Use exact matching - no barcode extraction
          showNotification(
            paste("Exact cell name matching:", exact_matched, "out of", length(meta_cells),
                  "cells matched (", round(exact_match_ratio * 100, 1), "%)"),
            type = "message",
            duration = 5
          )
          # Keep original rownames - they already match
          # No need to modify rownames(meta)
        } else {
          # Fallback to barcode extraction matching
          # Extract barcode part (remove prefix and suffix)
          # Remove prefix: everything up to and including the last underscore
          # Remove suffix: hyphen followed by numbers at the end
          # Example: EC_8w_1_AAACGAAAGCCGAACA-1 -> AAACGAAAGCCGAACA
          extract_barcode <- function(cell_names) {
            # Remove prefix (everything up to and including last underscore)
            barcodes <- sub("^.*_", "", cell_names)
            # Remove suffix (hyphen followed by numbers)
            barcodes <- gsub("-[0-9]+$", "", barcodes)
            return(barcodes)
          }

          current_barcodes <- extract_barcode(current_cells)
          meta_barcodes <- extract_barcode(meta_cells)

          # Count total matching cells by barcode
          total_matched <- sum(meta_barcodes %in% current_barcodes)
          match_ratio <- total_matched / length(meta_barcodes)

          if (total_matched == 0) {
            removeModal()
            showNotification(
              "Error: No matching cell barcodes found between metadata and Seurat object",
              type = "error",
              duration = 10
            )
            return()
          }

          # Show warning if match ratio is low
          if (match_ratio < 0.5) {
            showNotification(
              paste("Warning:", total_matched, "out of", length(meta_barcodes),
                    "cells matched by barcode (", round(match_ratio * 100, 1), "%). Proceeding with matched cells only."),
              type = "warning",
              duration = 10
            )
          } else {
            showNotification(
              paste("Barcode matching:", total_matched, "out of", length(meta_barcodes), "cells matched (",
                    round(match_ratio * 100, 1), "%)"),
              type = "message",
              duration = 5
            )
          }

          # Create barcode-to-rowname mapping for matching
          # This will be used later to match cells by barcode
          current_barcode_map <- setNames(current_cells, current_barcodes)
          meta_barcode_map <- setNames(meta_cells, meta_barcodes)

          # Update rownames in meta to match current_cells using barcode matching
          matched_barcodes <- meta_barcodes[meta_barcodes %in% current_barcodes]
          new_rownames <- character(nrow(meta))

          for (i in 1:nrow(meta)) {
            barcode <- meta_barcodes[i]
            if (barcode %in% current_barcodes) {
              # Use the corresponding cell name from current object
              new_rownames[i] <- current_barcode_map[barcode]
            } else {
              # Keep original if no match
              new_rownames[i] <- meta_cells[i]
            }
          }

          rownames(meta) <- new_rownames
        }
      }
      
      # Find new columns
      new_columns <- setdiff(colnames(meta), colnames(meta_org))
      print('New columns to be added:')
      print(new_columns)
      
      if (length(new_columns) == 0) {
        showNotification("No new columns found in metadata file", type = "warning")
        return()
      }
      
      # Select only new columns
      meta <- meta[new_columns]
      meta['meta.row.names'] <- row.names(meta)
      print('Uploaded metadata (new columns only):')
      print(head(meta))
      print('Row names in uploaded metadata:')
      print(head(meta['meta.row.names']))
      
      # Merge metadata
      meta_new <- merge(meta_org, meta, 
                       by.x = 'meta_org.row.names', 
                       by.y = 'meta.row.names', 
                       all.x = TRUE)
      
      # Process merged metadata
      row.names(meta_new) <- meta_new$meta_org.row.names
      meta_new$meta_org.row.names <- NULL
      
      # Ensure original order
      meta_new <- meta_new[row.names(meta_org),]
      
      # No NA replacement for any columns - keep all NA values as is

# Apply type conversion to new columns
for (col in new_columns) {
  if (col %in% colnames(meta_new)) {
    col_data <- as.character(meta_new[[col]])
    col_data_clean <- trimws(col_data)
    non_na_values <- col_data_clean[!is.na(col_data_clean) & col_data_clean != ""]
    
    if (length(non_na_values) > 0) {
      numeric_test <- suppressWarnings(as.numeric(non_na_values))
      
      if (all(!is.na(numeric_test))) {
        # 数値に変換可能な場合でも、unique値で判定
        unique_count <- length(unique(non_na_values))
        total_count <- length(non_na_values)
        uniqueness_ratio <- unique_count / total_count
        
        if (uniqueness_ratio > 0.5) {
          # unique値が多い → 真の数値データ
          meta_new[[col]] <- suppressWarnings(as.numeric(col_data_clean))
          print(paste(col, ": converted to numeric (unique ratio:", 
                     round(uniqueness_ratio, 2), ")"))
        } else {
          # unique値が少ない → カテゴリカルな数値（クラスターなど）
          meta_new[[col]] <- factor(col_data_clean)
          print(paste(col, ": converted to factor (numeric but categorical,", 
                     unique_count, "levels, ratio:", round(uniqueness_ratio, 2), ")"))
        }
      } else {
        # 文字列データの処理
        unique_count <- length(unique(non_na_values))
        total_count <- length(non_na_values)
        uniqueness_ratio <- unique_count / total_count
        
        if (col %in% c("Cell_id", "barcode", "sample_id") ||  
            uniqueness_ratio > 0.5) {
          # as.is = TRUE (characterのまま)
          meta_new[[col]] <- type.convert(col_data_clean, as.is = TRUE)
          print(paste(col, ": kept as character (unique ratio:", 
                     round(uniqueness_ratio, 2), ")"))
        } else {
          # as.is = FALSE (factorに変換)
          meta_new[[col]] <- type.convert(col_data_clean, as.is = FALSE)
          print(paste(col, ": converted to factor (", unique_count, "levels)"))
        }
      }
    }
  }
}
     
      # Update Seurat object
      seurat_object[[]] <<- meta_new

      showNotification("Metadata successfully added")
      
      # Update UI
      updateMetadata()
      updateSelInpColor()
    }
  }, error = function(e) {
    print(paste("Error in metadata processing:", e))
    showNotification(
      paste("Error loading metadata: ", e), 
      type = 'error',
      duration = 10
    )
  }, finally = {
      removeModal()
  } )
})


####=============Spatial Utility


# 基本的な画像の読み込みと座標範囲の取得
observeEvent(input$ShowSpatialImage, {
  tryCatch({
  withProgress(message = 'Loading data...', {
    incProgress(0.2, detail = "Getting coordinates")
    
    # 空間座標を取得
    coord_data <- GetTissueCoordinates(seurat_object, scale = "lowres")

    # データセット名を取得
    img_name <- names(seurat_object@images)[1]
    # オブジェクトのクラス確認
    img_class <- class(seurat_object@images[[img_name]])[1]
    
    # VisiumV2フォーマットの場合、x/yをimagerow/imagecolとして扱う
    if (img_class == "VisiumV2") {
      print("VisiumV2")
      # VisiumV2では、x/y座標を使用
      x_col <- "x"
      y_col <- "y"
    } else {
      # その他のフォーマット（VisiumV1など）ではimagerow/imagecolを使用
      x_col <- "imagecol"
      y_col <- "imagerow"
    }
    
    img_raster <- GetImage(
      object = seurat_object,
      mode = "raster"
    )
    img_width <<- dim(img_raster)[2]
    img_height <<- dim(img_raster)[1]
    # 座標範囲の計算
    spatial_x_range <- range(coord_data[[x_col]])
    spatial_y_range <- range(coord_data[[y_col]])
    
    # 入力欄を更新
    if (input$FlipXY){ #XY flipに対応
    updateSliderInput(session, "spatial_x_min", 
                      value = round(spatial_y_range[1]),
                      min = floor(spatial_y_range[1]), 
                      max = ceiling(spatial_y_range[2]))
                      
    updateSliderInput(session, "spatial_x_max", 
                      value = round(spatial_y_range[2]),
                      min = floor(spatial_y_range[1]), 
                      max = ceiling(spatial_y_range[2]))
                      
    updateSliderInput(session, "spatial_y_min", 
                      value = round(spatial_x_range[1]),
                      min = floor(spatial_x_range[1]), 
                      max = ceiling(spatial_x_range[2]))
                      
    updateSliderInput(session, "spatial_y_max", 
                      value = round(spatial_x_range[2]),
                      min = floor(spatial_x_range[1]), 
                      max = ceiling(spatial_x_range[2])  )
    } else {
    updateSliderInput(session, "spatial_x_min", 
                      value = round(spatial_x_range[1]),
                      min = floor(spatial_x_range[1]), 
                      max = ceiling(spatial_x_range[2]))
                      
    updateSliderInput(session, "spatial_x_max", 
                      value = round(spatial_x_range[2]),
                      min = floor(spatial_x_range[1]), 
                      max = ceiling(spatial_x_range[2]))
                      
    updateSliderInput(session, "spatial_y_min", 
                      value = round(spatial_y_range[1]),
                      min = floor(spatial_y_range[1]), 
                      max = ceiling(spatial_y_range[2]))
                      
    updateSliderInput(session, "spatial_y_max", 
                      value = round(spatial_y_range[2]),
                      min = floor(spatial_y_range[1]), 
                      max = ceiling(spatial_y_range[2])  )
    }

    if (input$FlipXY){ #XY flipに対応 
    cells_in_region <- rownames(coord_data)[
      coord_data[ x_col ] >= img_height - input$spatial_y_max & 
      coord_data[ x_col ] <= img_height - input$spatial_y_min &
      coord_data[ y_col ] >= input$spatial_x_min & 
      coord_data[ y_col ] <= input$spatial_x_max
    ] } else{
      cells_in_region <- rownames(coord_data)[
      coord_data[ x_col ] >= input$spatial_x_min & 
      coord_data[ x_col ] <= input$spatial_x_max &
      coord_data[ y_col ] >= img_height - input$spatial_y_max &
      coord_data[ y_col ] <= img_height - input$spatial_y_min
      ]
    }

   
    # 選択情報を表示
    output$spatial_selection_info <- renderPrint({
      cat(sprintf("Available coordinate range:\n"))
      cat(sprintf("X range: %.2f to %.2f\n", spatial_x_range[1], spatial_x_range[2]))
      cat(sprintf("Y range: %.2f to %.2f\n", spatial_y_range[1], spatial_y_range[2]))
      cat("Selected cells: ")
      cat(length(cells_in_region))
    })
    
    incProgress(0.4, detail = "Loading image data")
    
    # SpatialImageを取得
    DefaultAssay(seurat_object) <- "Spatial"
    
    

    showNotification("It may take a while to show plot...")

    
    # プロットを表示
    output$spatial_plot <-  renderPlot({

    # 余白を削除
    par(mar = c(0, 0, 0, 0))
    
    # イメージを表示
    plot(img_raster, axes = FALSE, ann = FALSE)
    
    # 矩形を追加（Y座標補正）
    rect(
      xleft = input$spatial_x_min,
      ybottom = input$spatial_y_max, 
      xright = input$spatial_x_max,  
      ytop = input$spatial_y_min, 
      border = 'black',
      lwd = 2
    )
    
  })
         incProgress(1.0, detail = "Complete")
         gc(full = TRUE)

  })}, error = function(e) {
    print(paste("Error in metadata processing:", e))
    showNotification(
      paste("Error loading metadata: ", e), 
      type = 'error',
      duration = 10
    )
  })
   })


