#なぜか上記のコードだとうまくいかない。直接seurat_objectをそうさするばあいはうまくいく

      incProgress(0.6, detail = "Updating UI")

#      print(sub)
#      print(str(sub))

      
               
      incProgress(0.8, detail = "Generating plots")
      showNotification("It may take a while to show plot...")
      
      # 結果表示 - シンプルなポイントのみのプロット（高速化）
  #    output$subset_plot <- renderPlot({
  #      p <- SpatialDimPlot(sub, crop = TRUE, pt.size.factor = 1, image.scale = "lowres")
   #     return(p)
    #  })
        # 一時的なメタデータカラムを作成
    temp_group <- rep("Not Selected", ncol(seurat_object))
    names(temp_group) <- colnames(seurat_object)
    temp_group[cells_in_region] <- "Selected"
    
    # メタデータに追加
    seurat_object$preview_selection <<- temp_group
    
    # Idents を更新（オプション）
    Idents(seurat_object) <- "preview_selection"
    
    # プレビュープロットを表示
    output$subset_plot <- renderPlot({
      p <- SpatialDimPlot(seurat_object, 
                          group.by = "preview_selection", 
                          crop = TRUE, 
                          pt.size.factor = 1, 
                          image.scale = "lowres",
                          cols = c("Selected" = "red", "Not Selected" = "lightgray"))
      return(p)
    })
    
    # 情報表示
    output$spatial_selection_info <- renderPrint({
      cat(sprintf("Preview: %d cells selected\n", length(cells_in_region)))
    })

      seurat_object$preview_selection <<- NULL

      
      # 最新の情報を表示
      output$spatial_selection_info <- renderPrint({
        cat("Subsetting completed successfully\n")
        cat(sprintf("Number of cells in the final object: %d\n", ncol(seurat_object)))
      })
      
      showNotification(paste0("Subsetting completed with ", length(cells_in_region), " cells"), type = "message")
    } else {
      showNotification("No cells in the selected region", type = "error")

    }
    
    incProgress(1.0, detail = "Complete")

    showNotification("It would take a while to show plot...", duration=60)
    sub <- NULL
    gc(full = TRUE)
  })}, error = function(e) {
    print(paste("Error in metadata processing:", e))
    showNotification(
      paste("Error loading metadata: ", e), 
      type = 'error',
      duration = 10
    )
  })
})


# サブセット確定ボタンのイベント
observeEvent(input$spatial_confirm_subsetting, {
  req(input$spatial_x_min, input$spatial_x_max, input$spatial_y_min, input$spatial_y_max)
  tryCatch({
  withProgress(message = 'Subsetting...', {
    incProgress(0.2, detail = "Selecting cells")
    
    # 空間座標を取得
    coord_data <- GetTissueCoordinates(seurat_object, scale = "lowres")
        # データセット名を取得
    img_name <- names(seurat_object@images)[1]
    # オブジェクトのクラス確認
    img_class <- class(seurat_object@images[[img_name]])[1]
    # VisiumV2フォーマットの場合、x/yをimagerow/imagecolとして扱う
    if (img_class == "VisiumV2") {
      print("VisiumV2")
      # VisiumV2では、x/y座標を使用
      x_col <- "x"
      y_col <- "y"
    } else {
      # その他のフォーマット（VisiumV1など）ではimagerow/imagecolを使用
      x_col <- "imagecol"
      y_col <- "imagerow"
    }

    if (input$FlipXY){ #XY flipに対応 
    cells_in_region <- rownames(coord_data)[
      coord_data[ x_col ] >= img_height - input$spatial_y_max & 
      coord_data[ x_col ] <= img_height - input$spatial_y_min &
      coord_data[ y_col ] >= input$spatial_x_min & 
      coord_data[ y_col ] <= input$spatial_x_max
    ] } else{
      cells_in_region <- rownames(coord_data)[
      coord_data[ x_col ] >= input$spatial_x_min & 
      coord_data[ x_col ] <= input$spatial_x_max &
      coord_data[ y_col ] >= img_height - input$spatial_y_max &
      coord_data[ y_col ] <= img_height - input$spatial_y_min
      ]
    }
    # セルが選択されていることを確認
    if (length(cells_in_region) > 0) {
      incProgress(0.4, detail = "Creating subset")
      
      # seurat_objectを更新（確定）
      seurat_object <<- subset(seurat_object, cells = cells_in_region)
      
      incProgress(0.6, detail = "Updating UI")
      
      # 必要な関数を呼び出してUIを更新
      updateMetadata()
      updateSelInpColor()
      updateInputLRclusters()
      
      # 新しい座標データを取得
   #   new_coords <- GetTissueCoordinates(seurat_object)
   #   new_coords$ident <- as.factor(Idents(seurat_object)[rownames(new_coords)])
      
      incProgress(0.8, detail = "Generating plots")
      showNotification("It may take a while to show plot...", duration=60)
      
      # 結果表示 - シンプルなポイントのみのプロット（高速化）
      output$subset_plot <- renderPlot({
        p <- SpatialDimPlot(seurat_object, crop = TRUE, pt.size.factor = 1, image.scale = "lowres")
        return(p)
      })
      
      
      showNotification(paste0("Subsetting completed with ", length(cells_in_region), " cells"), type = "message")
    } else {
      showNotification("No cells in the selected region", type = "error")

    }
    
    incProgress(1.0, detail = "Complete")
    showNotification("It would take a while to show plot...")
    gc(full = TRUE)
  })}, error = function(e) {
    print(paste("Error in metadata processing:", e))
    showNotification(
      paste("Error loading metadata: ", e), 
      type = 'error',
      duration = 10
    )
  })
})

