observeEvent(input$uploadCell, {
 tryCatch({
  if (!is.null(input$cellUploadFile)){
    print("uploading cells")

  meta <-read.table(input$cellUploadFile$datapath,  header = T, row.names = 1)
  print(head(meta))
  seurat_object <<- RenameCells(seurat_object, new.names = meta[['cell']])
  showNotification("cell names are changed.")
  updateMetadata()
  updateSelInpColor()

  }

    }, error = function(e) {
      showNotification(paste("Error :  ", e), type='error')
      })
    })




  #------------------CellBender---------------------------------------

  #------------------CellBender---------------------------------------
  # Reactive values for CellBender
  cellbender_log <- reactiveVal("")
  cellbender_running <- reactiveVal(FALSE)
  cellbender_log_file <- reactiveVal(NULL)
  cellbender_output_file <- reactiveVal(NULL)

  # Render CellBender status
  output$CellBenderStatus <- renderText({
    if (cellbender_running()) {
      "🔄 CellBender is running... Check log below for progress."
    } else {
      ""
    }
  })

  # Render CellBender log output
  output$CellBenderLog <- renderText({
    cellbender_log()
  })

  # Render dynamic box title for Data Input
  output$data_input_box_title <- renderUI({
    if (!is.null(input$mainUploadTabs) && input$mainUploadTabs == "CellBender") {
      "CellBender Information"
    } else {
      "Metadata table"
    }
  })

  # Monitor CellBender log file - show last 10 lines
  observe({
    invalidateLater(2000, session)  # Check every 2 seconds

    if (cellbender_running() && !is.null(cellbender_log_file())) {
      log_path <- cellbender_log_file()
      if (file.exists(log_path)) {
        tryCatch({
          # Always show last 10 lines using tail command for efficiency
          log_lines <- system(paste("tail -n 10", shQuote(log_path)), intern = TRUE)

          if (length(log_lines) > 0) {
            cellbender_log(paste(log_lines, collapse = "\n"))
          } else {
            cellbender_log("Waiting for CellBender output...")
          }
        }, error = function(e) {
          cellbender_log("Log file not available yet...")
        })
      }
    } else if (!cellbender_running()) {
      # Clear log when not running
      cellbender_log("")
    }
  })

  # Run CellBender remove-background
  observeEvent(input$RunCellBender, {
    tryCatch({
      session$sendCustomMessage("handler_startLoader", c("cellbender_loader", 10))
      showNotification("Starting CellBender remove-background...", type = "message")
      cellbender_running(TRUE)
      cellbender_log("Initializing CellBender...\n")

      # Get input file path
      input_file <- NULL
      if (!is.null(input$CellBenderRawFile)) {
        input_file <- input$CellBenderRawFile$datapath
      } else if (!is.null(input$CellBenderRawFileServer)) {
        if (!is.integer(input$CellBenderRawFileServer)) {
          file_selected <- parseFilePaths(volumes, input$CellBenderRawFileServer)
          if (nrow(file_selected) > 0) {
            input_file <- as.character(file_selected$datapath)
          }
        }
      }

      if (is.null(input_file)) {
        session$sendCustomMessage("handler_finishLoader", "cellbender_loader")
        cellbender_running(FALSE)
        showNotification("Please select a raw_feature_bc_matrix.h5 file", type = "error")
        return()
      }

      if (!file.exists(input_file)) {
        session$sendCustomMessage("handler_finishLoader", "cellbender_loader")
        cellbender_running(FALSE)
        showNotification("Input file does not exist", type = "error")
        return()
      }

      # Get output directory
      output_dir <- NULL
      if (!is.null(input$CellBenderOutputDir)) {
        if (!is.integer(input$CellBenderOutputDir)) {
          dir_selected <- parseDirPath(volumes, input$CellBenderOutputDir)
          if (length(dir_selected) > 0) {
            output_dir <- as.character(dir_selected)
          }
        }
      }

      if (is.null(output_dir)) {
        session$sendCustomMessage("handler_finishLoader", "cellbender_loader")
        cellbender_running(FALSE)
        showNotification("Please select an output directory", type = "error")
        return()
      }

      # Create output file path
      output_name <- input$CellBenderOutputName
      if (is.null(output_name) || output_name == "") {
        output_name <- "cellbender_output"
      }
      output_file <- file.path(output_dir, paste0(output_name, ".h5"))
      filtered_file_check <- sub("\\.h5$", "_filtered.h5", output_file)

      # Warn if previous results exist (completion monitor would detect them immediately)
      if (file.exists(filtered_file_check)) {
        session$sendCustomMessage("handler_finishLoader", "cellbender_loader")
        cellbender_running(FALSE)
        showNotification(
          paste0("Output directory に既存の結果があります: ", basename(filtered_file_check),
                 "\n出力先を変更するか、既存ファイルを削除してから再実行してください。"),
          type = "warning", duration = NULL)
        return()
      }

      # Get parameters
      expected_cells <- input$CellBenderExpectedCells
      total_droplets <- input$CellBenderTotalDroplets
      epochs <- input$CellBenderEpochs
      learning_rate <- input$CellBenderLearningRate
      fpr <- input$CellBenderFPR
      use_cuda <- input$CellBenderUseCUDA

      # Create log file
      log_file <- file.path(output_dir, paste0(output_name, "_log.txt"))
      cellbender_log_file(log_file)

      # Remove old checkpoint file to prevent workflow hash conflicts
      checkpoint_file <- "ckpt.tar.gz"
      if (file.exists(checkpoint_file)) {
        file.remove(checkpoint_file)
      }

      # Build CellBender command
      cuda_flag <- if (use_cuda) "--cuda" else ""

      # GPU configuration
      # PyTorch 2.7.1+cu128 supports sm_120 (RTX 5060)
      # IMPORTANT: CUDA_VISIBLE_DEVICES uses different indexing than nvidia-smi
      # CUDA_VISIBLE_DEVICES=0 → RTX 5060 on 2-GPU systems (nvidia-smi GPU 1)
      # CUDA_VISIBLE_DEVICES=0 → The only GPU on 1-GPU systems
      gpu_id <- "0"

      cmd <- sprintf(
        "CUDA_VISIBLE_DEVICES=%s PYTHONUNBUFFERED=1 ~/anaconda3/envs/cellbender_stable/bin/cellbender remove-background --input '%s' --output '%s' --expected-cells %d --total-droplets-included %d --fpr %.4f --epochs %d --learning-rate %.6f %s > '%s' 2>&1",
        gpu_id,
        input_file,
        output_file,
        expected_cells,
        total_droplets,
        fpr,
        epochs,
        learning_rate,
        cuda_flag,
        log_file
      )

      cellbender_log("")  # Start with empty log, only show on error
      showNotification(paste("Running CellBender in background..."), type = "message", duration = 5)

      # Disable sidebar menu during execution
      shinyjs::runjs("$('.sidebar-menu').css('pointer-events', 'none').css('opacity', '0.5');")

      # Update progress bar to show starting
      session$sendCustomMessage("handler_startLoader", c("cellbender_loader", 20))

      # Run CellBender in background
      system(cmd, wait = FALSE)

      # Store output file path for completion check
      cellbender_output_file(output_file)

      # Update progress bar to show running (stay at 50% until completion)
      Sys.sleep(0.5)
      session$sendCustomMessage("handler_startLoader", c("cellbender_loader", 50))

    }, error = function(e) {
      session$sendCustomMessage("handler_finishLoader", "cellbender_loader")
      cellbender_running(FALSE)
      # Re-enable sidebar menu
      shinyjs::runjs("$('.sidebar-menu').css('pointer-events', 'auto').css('opacity', '1');")
      showNotification(paste("Error running CellBender:", e$message), type = "error", duration = NULL)
      cellbender_log(paste("ERROR:", e$message))
      print(paste("CellBender error:", e))
    })
  })

  # Monitor CellBender completion - check every 5 seconds
  observe({
    invalidateLater(5000, session)  # Check every 5 seconds

    if (cellbender_running() && !is.null(cellbender_output_file())) {
      output_file <- cellbender_output_file()
      log_file <- cellbender_log_file()
      filtered_file <- sub("\\.h5$", "_filtered.h5", output_file)

      if (file.exists(filtered_file)) {
        # CellBender completed
        session$sendCustomMessage("handler_finishLoader", "cellbender_loader")
        cellbender_running(FALSE)

        # Re-enable sidebar menu
        shinyjs::runjs("$('.sidebar-menu').css('pointer-events', 'auto').css('opacity', '1');")

        # Check final log for errors
        if (file.exists(log_file)) {
          final_log <- readLines(log_file, warn = FALSE)
          has_error <- any(grepl("Error|ERROR|Traceback|Exception|FAILED|Failed", final_log))

          if (has_error) {
            # Show error log
            if (length(final_log) > 50) {
              final_log <- tail(final_log, 50)
            }
            cellbender_log(paste(c(final_log, "\n\n=== COMPLETED WITH ERRORS ==="), collapse = "\n"))
          } else {
            # Clear log on successful completion
            cellbender_log("")

            # Remove checkpoint file on successful completion
            output_dir <- dirname(output_file)
            checkpoint_file <- file.path(output_dir, "ckpt.tar.gz")
            if (file.exists(checkpoint_file)) {
              tryCatch({
                file.remove(checkpoint_file)
                showNotification("Checkpoint file removed for clean next run", type = "message", duration = 5)
              }, error = function(e) {
                showNotification(paste("Could not remove checkpoint file:", e$message), type = "warning", duration = 5)
              })
            }
          }
        }

        showNotification("CellBender completed successfully!", type = "message", duration = NULL)
        showNotification(paste("Output file:", output_file), type = "message", duration = NULL)
        showNotification(paste("Filtered output:", filtered_file), type = "message", duration = NULL)
        showNotification("Load the filtered.h5 file in the Upload tab.", type = "warning", duration = NULL)

        # Clear output file path
        cellbender_output_file(NULL)
      }
    }
  })

  # Download CellBender results as zip
  output$downloadCellBenderResults <- downloadHandler(
    filename = function() {
      paste0("cellbender_results_", format(Sys.time(), "%Y%m%d_%H%M%S"), ".zip")
    },
    content = function(file) {
      # Get the output directory from the last run
      output_dir <- NULL
      if (!is.null(input$CellBenderOutputDir)) {
        if (!is.integer(input$CellBenderOutputDir)) {
          dir_selected <- parseDirPath(volumes, input$CellBenderOutputDir)
          if (length(dir_selected) > 0) {
            output_dir <- as.character(dir_selected)
          }
        }
      }

      if (is.null(output_dir)) {
        showNotification("Output directory not specified. Cannot download results.", type = "error", duration = 10)
        return(NULL)
      }

      # Define the output file prefix
      output_name <- input$CellBenderOutputName
      if (is.null(output_name) || output_name == "") {
        output_name <- "cellbender_output"
      }
      output_prefix <- file.path(output_dir, output_name)

      # Define files to include in zip
      files_to_zip <- c(
        paste0(output_prefix, "_log.txt"),
        paste0(output_prefix, "_filtered.h5"),
        paste0(output_prefix, ".pdf")
      )

      # Check which files exist
      existing_files <- files_to_zip[file.exists(files_to_zip)]

      if (length(existing_files) == 0) {
        showNotification("No CellBender output files found. Please run CellBender first.", type = "error", duration = 10)
        return(NULL)
      }

      # Create zip file
      tryCatch({
        # Use zip command to create archive
        old_wd <- getwd()
        setwd(dirname(existing_files[1]))

        zip_result <- system2("zip",
                             args = c("-j", shQuote(file), basename(existing_files)),
                             stdout = TRUE,
                             stderr = TRUE)

        setwd(old_wd)

        showNotification(paste("Downloaded", length(existing_files), "file(s)"), type = "message", duration = 5)
      }, error = function(e) {
        showNotification(paste("Error creating zip:", e$message), type = "error", duration = 10)
      })
    }
  )

  #------------------Quality Control tab--------------------------------
  observeEvent(input$qcDisplay, {
    session$sendCustomMessage("handler_startLoader", c("qc_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "qcDisplay")
    tryCatch({
      if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
      else{
        shinyjs::show("nFeatureViolin_loader")
        shinyjs::show("totalCountsViolin_loader")
        shinyjs::show("mitoViolin_loader")
        shinyjs::show("genesCounts_loader")
        shinyjs::show("mtCounts_loader")
        showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%

# Calculate nCount and nFeature if they don't exist in metadata
# nCount_RNA, nFeature_RNAがmetadataにない場合はcountsから計算する
tryCatch({
  assay_name <- DefaultAssay(seurat_object)
  ncount_col <- paste0("nCount_", assay_name)
  nfeature_col <- paste0("nFeature_", assay_name)

  # Check if counts matrix exists
  has_counts <- FALSE
  if (is_assay5(seurat_object)) {
    has_counts <- length(seurat_object[[assay_name]]$counts) > 0
  } else {
    has_counts <- nrow(seurat_object[[assay_name]]@counts) > 0
  }

  # Calculate nCount if missing
  if (!ncount_col %in% colnames(seurat_object@meta.data)) {
    message(paste0(ncount_col, " not found in metadata. Calculating..."))
    if (has_counts) {
      seurat_object@meta.data[[ncount_col]] <<- Matrix::colSums(seurat_object[[assay_name]]$counts)
      message(paste0("Calculated ", ncount_col, " from counts matrix"))
    } else {
      # Use data matrix as fallback
      seurat_object@meta.data[[ncount_col]] <<- Matrix::colSums(seurat_object[[assay_name]]$data)
      message(paste0("Calculated ", ncount_col, " from data matrix (counts not available)"))
    }
  }

  # Calculate nFeature if missing
  if (!nfeature_col %in% colnames(seurat_object@meta.data)) {
    message(paste0(nfeature_col, " not found in metadata. Calculating..."))
    if (has_counts) {
      seurat_object@meta.data[[nfeature_col]] <<- Matrix::colSums(seurat_object[[assay_name]]$counts > 0)
      message(paste0("Calculated ", nfeature_col, " from counts matrix"))
    } else {
      seurat_object@meta.data[[nfeature_col]] <<- Matrix::colSums(seurat_object[[assay_name]]$data > 0)
      message(paste0("Calculated ", nfeature_col, " from data matrix (counts not available)"))
    }
  }

  # Calculate percent.mt if missing
  if (!"percent.mt" %in% colnames(seurat_object@meta.data)) {
    message("percent.mt not found in metadata. Calculating...")
    mt_pattern <- if (organism == "human") "^MT-" else "^mt-"
    seurat_object[["percent.mt"]] <<- PercentageFeatureSet(seurat_object, pattern = mt_pattern)
    message("Calculated percent.mt")
  }
}, error = function(e) {
  message(paste("Error calculating QC metrics:", e$message))
})

