          }
        )
        session$sendCustomMessage("handler_startLoader", c("qc_loader", 35))
        
        # Convert QC columns to numeric if they are not already
        critical_qc_cols <- c("nCount_RNA", "nFeature_RNA", "percent.mt")
        for (col in critical_qc_cols) {
          if (col %in% colnames(init_seurat_object@meta.data)) {
            if (!is.numeric(init_seurat_object@meta.data[[col]])) {
              init_seurat_object@meta.data[[col]] <<- suppressWarnings(as.numeric(as.character(init_seurat_object@meta.data[[col]])))
            }
          }
        }
        
        # Also convert QC columns for seurat_object if it exists
        if (!is.null(seurat_object)) {
          for (col in critical_qc_cols) {
            if (col %in% colnames(seurat_object@meta.data)) {
              if (!is.numeric(seurat_object@meta.data[[col]])) {
                seurat_object@meta.data[[col]] <<- suppressWarnings(as.numeric(as.character(seurat_object@meta.data[[col]])))
              }
            }
          }
        }

        output$mitoViolin <- renderPlotly(
          {
            p <- VlnPlot(init_seurat_object, features = c("percent.mt"), pt.size = pt.size, group.by = input$qcColorBy,
                         cols = colorRampPalette(brewer.pal(12, "Paired"))(length(unique(init_seurat_object@meta.data[, input$qcColorBy])))) +
              theme_bw() +
              #scale_y_continuous(labels = number_format(accuracy = 0.001)) +
             # geom_hline(yintercept= as.numeric(input$maxMtReads), linetype="dashed", color = "red", size=1) +
              theme(
                plot.title = element_blank(),
                axis.title.x = element_blank(),
                legend.position = "none")+
              labs(title = "", y="% of reads mapped to mitochonrial genome/cell")
            plotly::ggplotly(p, tooltip = c("x", "y")) %>% config(staticPlot = TRUE) #%>%
              #layout(yaxis = list(hoverformat = ".2f"))
          }
        )
        session$sendCustomMessage("handler_startLoader", c("qc_loader", 50))

        output$mtCounts <- renderPlotly(
          {
            p <- FeatureScatter(init_seurat_object, feature1 = paste0("nCount_", DefaultAssay(init_seurat_object)), feature2 = "percent.mt", group.by = input$qcColorBy, pt.size=0.5,
                                cols = colorRampPalette(brewer.pal(12, "Paired"))(length(unique(init_seurat_object@meta.data[, input$qcColorBy]))))
            gp <- plotly::ggplotly(p)%>% config(staticPlot = TRUE)
            print(gp)
          }
        )
        session$sendCustomMessage("handler_startLoader", c("qc_loader", 60))

        output$genesCounts <- renderPlotly(
          {
            p <- FeatureScatter(init_seurat_object, feature1 =paste0("nCount_", DefaultAssay(init_seurat_object)), feature2 = paste0("nFeature_", DefaultAssay(init_seurat_object)), group.by = input$qcColorBy, pt.size=0.5,
                                cols = colorRampPalette(brewer.pal(12, "Paired"))(length(unique(init_seurat_object@meta.data[,  input$qcColorBy]))))
            gp <- plotly::ggplotly(p)%>% config(staticPlot = TRUE)
            print(gp)
          }
        )
        session$sendCustomMessage("handler_startLoader", c("qc_loader", 75))

        output$cellStats <- renderPrint(
          {
            cat(paste0("Total number of cells: ", nrow(init_seurat_object@meta.data)))
          }
        )
      }
    }, error = function(e) {
      print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
      session$sendCustomMessage("handler_alert", "The selected Quality Control arguments cannot produce meaningful visualizations.")
    }, finally = {
