  observeEvent(input$changeMitoOrganism, {
    tryCatch({
        if ((identical(seurat_object, NULL)) ) session$sendCustomMessage("handler_alert", "Please, upload some data or selct orig.ident.")
        else{
          # Update global organism variable
          organism <<- input$MitoOrganism
          updateSpecies()

          if(input$MitoOrganism == "mouse")
          {
            print('mouse')
            seurat_object[["percent.mt"]] <<- PercentageFeatureSet(seurat_object, pattern = "^mt-")
          if (!is.null(init_seurat_object)) {
            init_seurat_object[["percent.mt"]] <<- PercentageFeatureSet(init_seurat_object, pattern = "^mt-")
            }
            showNotification("Species changed to mouse", type = "message")
          }
          else if (input$MitoOrganism == "human") {
            print('human')
            seurat_object[["percent.mt"]] <<- PercentageFeatureSet(seurat_object, pattern = "^MT-")
           if (!is.null(init_seurat_object)) {
            init_seurat_object[["percent.mt"]] <<- PercentageFeatureSet(init_seurat_object, pattern = "^MT-")
              }
            showNotification("Species changed to human", type = "message")
          }
        }
        }, error = function(e) {
  showNotification("Mito calc error", type='error')
      })
  })


