      plotAs = "violin",
      alpha = 0.4,
      addBoxPlot = TRUE
    )
    output$TSS_plot <- renderPlotly( expr =  ggplot(p1$data, aes(x=x, y=y, fill=x)) + geom_violin() + theme_bw() + labs(y="TSS Enrichment"))

    session$sendCustomMessage("handler_startLoader", c("qc_loader3", 50))

    #nFrags plot
    p2 <- plotGroups(
