    session$sendCustomMessage("handler_enableTabs", c("sidebarMenu", " FILE", " QUALITY CONTROL", " PCA/LSI", " DOUBLETS' DETECTION", " UTILITY IDENTITY & ASSAY", " UTILITY CLUSTER", " UTILITY DATA MANIPULATION", " SEURAT OBJECT STRUCTURE"))
      }
