if (length(seurat_object[[DefaultAssay(seurat_object)]]$counts) == 0){
  showNotification("No counts. Please use 'Run scaling only", type = 'error', duration=60 )
  return()
}

split.by = NULL
if (input$ScaleIndividual & (length(levels(as.factor(seurat_object[[]][[input$BatchIdent2]]))) > 1) ) {
  split.by = input$BatchIdent2
    showNotification("Scaling data individually within each sample...")
}

if (DefaultAssay(seurat_object) == "SCENIC"){
  showNotification("SCENICのcounts/dataはある程度正規化されています。SCENICが終了した段階では、counts/dataともにSCENICの同じデータが入っています。", duration =120)
}

 withProgress(message = 'Normalizing...', value = 0, {

        shinyjs::show("hvgScatter_loader")
        showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%
print("normalization 0")
        if ((input$logSCT == 'Log') | (input$logSCT == 'log1p'))  {
    #      seurat_object@active.assay <<- 'RNA'
        normalize_normMethod <- "LogNormalize"
        normalize_normScaleFactor <- input$normScaleFactor
print("normalization 01")
        if (input$logSCT == 'log1p') {
          seurat_object[[DefaultAssay(seurat_object)]]$data <<- log1p(seurat_object[[DefaultAssay(seurat_object)]]$counts)
        }
        else {
        seurat_object <<- NormalizeData(seurat_object, normalization.method = normalize_normMethod, scale.factor = as.numeric(normalize_normScaleFactor))
      }
        session$sendCustomMessage("handler_log", "Finished performing log-normalization.")
        session$sendCustomMessage("handler_startLoader", c("normalize_loader", 25))

        normalize_hvgMethod <<- input$radioHVG
        normalize_hvgNGenes <<- input$nHVGs

incProgress(0.2)
print("normalization 1")

        # Clear old variable features and scale data BEFORE FindVariableFeatures
        tryCatch({
          assay_name <- DefaultAssay(seurat_object)

