          genes_to_add <- genes_to_add[genes_to_add %in% rownames(seurat_object)]
          if (length(genes_to_add) > 0) {
            # Combine and remove duplicates
            new_hvgs <- unique(c(current_hvgs, genes_to_add))
            VariableFeatures(seurat_object) <<- new_hvgs
