              scale_size()+
              theme_bw() +
              theme(axis.text.x = element_text(face = "bold", color = "black", size = 12, angle = 0), #25
                    axis.text.y = element_text(face = "bold", color = "black", size = 12, angle = 0),
                    axis.title.y = element_text(face = "bold", color = "black", size = 12),
                    axis.title.x = element_text(face = "bold", color = "black", size = 12),
                    legend.text = element_text(face = "bold", color = "black", size = 8),
                    legend.title = element_text(face = "bold", color = "black", size = 8),
                    legend.position="right",panel.grid.minor.x = element_blank() , panel.grid.minor.y = element_blank()  ,
                 panel.grid.major.x = element_blank() , panel.grid.major.y = element_blank(),
                    title = element_text(face = "bold", color = "black", size = 12, angle = 0)) +
              labs(x="PC 1", y="PC 2", title = "", fill="Color")
            print(plotly::ggplotly(p))
          }
        )
        session$sendCustomMessage("handler_enableTabs", c("sidebarMenu", " CLUSTERING", " UMAP etc", " CELL CYCLE PHASE ANALYSIS", " FEATURE INSPECTION"))
      }
    }, error = function(e) {
      print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
      session$sendCustomMessage("handler_alert", "There was an error with the PCA analysis.")
    }, finally = {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("PCA1_loader", 75))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "PCA1_loader")
      session$sendCustomMessage("handler_enableAllButtons", "PCrunPCA")
      session$sendCustomMessage("handler_log", " ### Finished PCA Analysis ###")
    })
  })

  observeEvent(input$PCconfirm, {
    session$sendCustomMessage("handler_log", " ### Starting PC Exploration ###")
    session$sendCustomMessage("handler_startLoader", c("PCA2_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "PCconfirm")
    tryCatch({
      if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
      else if (!str_detect(paste(names(seurat_object), collapse=""), pattern = "pca")) session$sendCustomMessage("handler_alert", "Please, first Run PCA above.")
      else {
        shinyjs::show("PCAloadings_loader")
        shinyjs::show("PCAheatmap_loader")
        showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%

        activePC <- as.numeric(input$PCin)

        output$PCAloadings <- renderPlotly(
          {
            plot1 <- VizDimLoadings(seurat_object, dims = activePC, reduction = ReductionUse, balanced = TRUE)
            plot1_data <- plot1$data
            plot1_data$orig.ident <- unique(seurat_object@meta.data$orig.ident)
            colnames(plot1_data)[1] <- "LoadingScore"
            activePC <- paste0("PC", "_", activePC)

            export_loadingScoresTable_RNA <<- plot1$data

            p <- ggplot(plot1_data, aes(x=LoadingScore, y=feature, color=orig.ident))+
              geom_point() +
              theme_bw() +
              scale_color_manual(values="blue")+
              theme(legend.position = "none")+
              labs(x=activePC, y="")

            gp <- plotly::ggplotly(p, tooltip = c("x", "y"))
            print(gp)
          }
        )

        session$sendCustomMessage("handler_startLoader", c("PCA2_loader", 75))
        output$PCAheatmap <- renderPlotly(
          {
            p <- DimHeatmap(seurat_object, dims = activePC, cells = 500, balanced = TRUE, fast = F)
            p
            plotly::ggplotly(p)
          }
        )
      }
    }, error = function(e) {
      print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
      session$sendCustomMessage("handler_alert", "There was an error with the PCA analysis.")
    }, finally = {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("PCA2_loader", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "PCA2_loader")
      session$sendCustomMessage("handler_enableAllButtons", "PCconfirm")
      session$sendCustomMessage("handler_log", " ### Finished PC Exploration ###")
    })
  })

  output$pcaRNAExport <- downloadHandler(
    filename = function() {
      paste("loadingScoresTableRNA-", Sys.Date(), ".txt", sep="")
    },
    content = function(file) {
      write.table(export_loadingScoresTable_RNA, file, sep = "\t", quote = F, row.names = F)
    })

  # ===== PC Covariate Analysis =====
  # Reactive values to store results
  pcCovResults <- reactiveValues(
    analysis_results = NULL,
    selected_covariates = NULL,
    reduction_name = NULL
  )

  # Update covariate choices in plot tab when analysis is run
  observeEvent(pcCovResults$selected_covariates, {
    if (!is.null(pcCovResults$selected_covariates)) {
      updateSelectInput(session, "pcCovPlotCovariate",
                       choices = pcCovResults$selected_covariates,
                       selected = pcCovResults$selected_covariates[1])
    }
  })

  # Reset PC Covariate Analysis selections
  observeEvent(input$pcCovReset, {
    updateSelectInput(session, "pcCovCovariate1", selected = "")
    updateSelectInput(session, "pcCovCovariate2", selected = "")
    updateSelectInput(session, "pcCovCovariate3", selected = "")
    updateSelectInput(session, "pcCovCovariate4", selected = "")
    updateSelectInput(session, "pcCovRandomEffect1", selected = "")
    updateSelectInput(session, "pcCovRandomEffect2", selected = "")
    updateCheckboxInput(session, "pcCovIncludeInteractions", value = FALSE)
    session$sendCustomMessage("handler_alert", "All selections have been reset.")
  })

  # Run PC Covariate Analysis
  observeEvent(input$pcCovRun, {
    session$sendCustomMessage("handler_log", " ### Starting PC Covariate Analysis ###")
    session$sendCustomMessage("handler_startLoader", c("pcCov_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "pcCovRun")

    tryCatch({
      # Load analysis functions
      source("Rfunc/pc_covariate_analysis.R")

      if (is.null(seurat_object)) {
        session$sendCustomMessage("handler_alert", "Please upload data first.")
        return()
      }

      # Get selected covariates
      covariates <- c(
        input$pcCovCovariate1,
        input$pcCovCovariate2,
        input$pcCovCovariate3,
        input$pcCovCovariate4
      )
      covariates <- covariates[covariates != ""]

      if (length(covariates) == 0) {
        session$sendCustomMessage("handler_alert", "Please select at least one covariate.")
        return()
      }

      # Check interaction requirements
      if (input$pcCovIncludeInteractions) {
        if (length(covariates) < 2 || covariates[1] == "" || covariates[2] == "") {
          session$sendCustomMessage("handler_alert",
            "To include interaction, both Covariate 1 and Covariate 2 must be selected.")
          return()
        }
      }

      # Get random effects
      random_effects <- c()
      if (input$pcCovRandomEffect1 != "") {
        random_effects <- c(random_effects, input$pcCovRandomEffect1)
      }
      if (input$pcCovRandomEffect2 != "") {
        random_effects <- c(random_effects, input$pcCovRandomEffect2)
      }
      random_effect <- if (length(random_effects) > 0) random_effects else NULL

      # Get reduction name
      reduction_name <- input$pcCovReduction

      # Check if reduction exists
      if (!reduction_name %in% names(seurat_object@reductions)) {
        session$sendCustomMessage("handler_alert",
                                 paste("Reduction", reduction_name, "not found. Please run PCA first."))
        return()
      }

      showModal(modalDialog(
        div('Analysis in Progress. This may take several minutes, please wait...',
            style='color:#ffffff; background-color:#222d32;'),
        footer = NULL,
        style = 'font-size:20px; text-align:center;position:absolute;'
      ))

      session$sendCustomMessage("handler_startLoader", c("pcCov_loader", 30))

      # Determine PCs to use based on reduction key
      num_pcs <- input$pcCovNumPCs
      reduction_key <- seurat_object@reductions[[reduction_name]]@key
      pcs_to_use <- paste0(reduction_key, 1:num_pcs)

      # Run analysis
      results <- analyze_pc_covariates(
        obj = seurat_object,
        reduction_name = reduction_name,
        fixed_covariates = covariates,
        random_effect = random_effect,
        pcs_to_use = pcs_to_use,
        include_interactions = input$pcCovIncludeInteractions
      )

      # Store results
      pcCovResults$analysis_results <- results
      pcCovResults$selected_covariates <- covariates
      pcCovResults$reduction_name <- reduction_name

      session$sendCustomMessage("handler_startLoader", c("pcCov_loader", 70))

      # Display summary table
      output$pcCovStatsTable <- renderDataTable({
        results$per_pc_stats
      }, options = list(scrollX = TRUE, pageLength = 20))

      # Display model comparison table
      output$pcCovModelCompTable <- renderDataTable({
        model_details <- results$model_details
        all_comparisons <- list()

        for (pc_name in names(model_details)) {
          # Get linear model comparisons
          if (!is.null(model_details[[pc_name]]$model_comparison)) {
            for (term_name in names(model_details[[pc_name]]$model_comparison)) {
              comparison_df <- model_details[[pc_name]]$model_comparison[[term_name]]
              comparison_df$pc <- pc_name
              comparison_df$model_type <- "Linear Model"

              # Add mixed model results if available
              if (!is.null(model_details[[pc_name]]$lmer_model_comparison) &&
                  term_name %in% names(model_details[[pc_name]]$lmer_model_comparison)) {
                mixed_comp <- model_details[[pc_name]]$lmer_model_comparison[[term_name]]
                comparison_df$mixed_r2m <- mixed_comp$full_model_r2m
                comparison_df$mixed_r2c <- mixed_comp$full_model_r2c
                comparison_df$mixed_delta_aic <- mixed_comp$delta_aic
                comparison_df$chisq_statistic <- mixed_comp$chisq_statistic
                comparison_df$lrt_pvalue <- mixed_comp$lrt_pvalue
              } else {
                comparison_df$mixed_r2m <- NA
                comparison_df$mixed_r2c <- NA
                comparison_df$mixed_delta_aic <- NA
                comparison_df$chisq_statistic <- NA
                comparison_df$lrt_pvalue <- NA
              }

              all_comparisons[[length(all_comparisons) + 1]] <- comparison_df
            }
          }
        }

        if (length(all_comparisons) > 0) {
          comparison_table <- do.call(rbind, all_comparisons)
          # Reorder columns for better readability
          comparison_table <- comparison_table[, c("pc", "term_removed", "term_type", "model_type",
                                                   "full_model_r2", "reduced_model_r2", "partial_r2",
                                                   "full_model_adj_r2", "reduced_model_adj_r2",
                                                   "full_model_aic", "reduced_model_aic", "delta_aic",
                                                   "f_statistic", "f_test_pvalue",
                                                   "mixed_r2m", "mixed_r2c", "mixed_delta_aic",
                                                   "chisq_statistic", "lrt_pvalue")]
          comparison_table
        } else {
          data.frame(message = "No model comparison data available")
        }
      }, options = list(scrollX = TRUE, pageLength = 20))

      # Generate heatmaps
      session$sendCustomMessage("handler_startLoader", c("pcCov_loader", 80))

      output$pcCovR2Heatmap <- renderPlot({
        plot_partial_r2_heatmap(results)
      })

      output$pcCovPvalHeatmap <- renderPlot({
        plot_pvalue_heatmap(results)
      })

      session$sendCustomMessage("handler_startLoader", c("pcCov_loader", 90))

      # Update PC choices for individual plots
      updateSelectInput(session, "pcCovPlotPC",
                       choices = results$per_pc_stats$pc,
                       selected = results$per_pc_stats$pc[1])

      showNotification("Analysis completed successfully!", type = "message")

    }, error = function(e) {
      print(paste("Error in PC Covariate Analysis:", e))
      showNotification(paste("Error:", e$message), type = "error", duration = 200)
      session$sendCustomMessage("handler_alert",
                               paste("There was an error:", e$message))
    }, finally = {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("pcCov_loader", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "pcCov_loader")
      session$sendCustomMessage("handler_enableAllButtons", "pcCovRun")
      session$sendCustomMessage("handler_log", " ### Finished PC Covariate Analysis ###")
    })
  })

  # Generate individual PC plot
  observeEvent(input$pcCovPlotGenerate, {
    tryCatch({
      # Load analysis functions
      source("Rfunc/pc_covariate_analysis.R")

      if (is.null(pcCovResults$analysis_results)) {
        showNotification("Please run the analysis first.", type = "warning")
        return()
      }

      output$pcCovIndividualPlot <- renderPlot({
        plot_pc_vs_covariate(
          obj = seurat_object,
          reduction_name = pcCovResults$reduction_name,
          pc = input$pcCovPlotPC,
          covariate = input$pcCovPlotCovariate,
          analysis_results = pcCovResults$analysis_results
        )
      })

    }, error = function(e) {
      print(paste("Error generating plot:", e))
      showNotification(paste("Error:", e$message), type = "error")
    })
  })

  # Download handlers
  output$pcCovStatsDownload <- downloadHandler(
