  output$pcCovIndivPlotDownload <- downloadHandler(
    filename = function() {
      paste0("pc_", input$pcCovPlotPC, "_vs_", input$pcCovPlotCovariate, "_", Sys.Date(), ".pdf")
    },
    content = function(file) {
      if (!is.null(pcCovResults$analysis_results)) {
        source("Rfunc/pc_covariate_analysis.R")
        pdf(file, width = 8, height = 6)
        print(plot_pc_vs_covariate(
          obj = seurat_object,
          reduction_name = pcCovResults$reduction_name,
          pc = input$pcCovPlotPC,
          covariate = input$pcCovPlotCovariate,
          analysis_results = pcCovResults$analysis_results
        ))
        dev.off()
      }
    }
  )

  # Download all results as ZIP
  output$pcCovDownload <- downloadHandler(
    filename = function() {
      paste0("pc_covariate_analysis_", Sys.Date(), ".zip")
    },
    content = function(file) {
      if (is.null(pcCovResults$analysis_results)) {
        showNotification("No analysis results to download", type = "warning")
        return()
      }

      # Load analysis functions
      source("Rfunc/pc_covariate_analysis.R")

      # Create temporary directory
      temp_dir <- tempdir()

      # Save statistics table
      write.csv(pcCovResults$analysis_results$per_pc_stats,
               file.path(temp_dir, "statistics_table.csv"),
               row.names = FALSE)

      # Save plot data
      write.csv(pcCovResults$analysis_results$plot_data,
               file.path(temp_dir, "plot_data.csv"),
               row.names = FALSE)

      # Save model comparison tables (integrated version)
      model_details <- pcCovResults$analysis_results$model_details
      all_comparisons <- list()

      for (pc_name in names(model_details)) {
        # Get linear model comparisons
        if (!is.null(model_details[[pc_name]]$model_comparison)) {
          for (term_name in names(model_details[[pc_name]]$model_comparison)) {
            comparison_df <- model_details[[pc_name]]$model_comparison[[term_name]]
            comparison_df$pc <- pc_name
            comparison_df$model_type <- "Linear Model"

            # Add mixed model results if available
            if (!is.null(model_details[[pc_name]]$lmer_model_comparison) &&
                term_name %in% names(model_details[[pc_name]]$lmer_model_comparison)) {
              mixed_comp <- model_details[[pc_name]]$lmer_model_comparison[[term_name]]
              comparison_df$mixed_r2m <- mixed_comp$full_model_r2m
              comparison_df$mixed_r2c <- mixed_comp$full_model_r2c
              comparison_df$mixed_delta_aic <- mixed_comp$delta_aic
              comparison_df$chisq_statistic <- mixed_comp$chisq_statistic
              comparison_df$lrt_pvalue <- mixed_comp$lrt_pvalue
            } else {
              comparison_df$mixed_r2m <- NA
              comparison_df$mixed_r2c <- NA
              comparison_df$mixed_delta_aic <- NA
              comparison_df$chisq_statistic <- NA
              comparison_df$lrt_pvalue <- NA
            }

            all_comparisons[[length(all_comparisons) + 1]] <- comparison_df
          }
        }
      }

      if (length(all_comparisons) > 0) {
        comparison_table <- do.call(rbind, all_comparisons)
        # Reorder columns for better readability
        comparison_table <- comparison_table[, c("pc", "term_removed", "term_type", "model_type",
                                                 "full_model_r2", "reduced_model_r2", "partial_r2",
                                                 "full_model_adj_r2", "reduced_model_adj_r2",
                                                 "full_model_aic", "reduced_model_aic", "delta_aic",
                                                 "f_statistic", "f_test_pvalue",
                                                 "mixed_r2m", "mixed_r2c", "mixed_delta_aic",
                                                 "chisq_statistic", "lrt_pvalue")]
        write.csv(comparison_table,
                 file.path(temp_dir, "model_comparison_integrated.csv"),
                 row.names = FALSE)
      }

      # Save detailed model summaries for each PC
      for (pc_name in names(model_details)) {
        pc_dir <- file.path(temp_dir, "model_details", pc_name)
        dir.create(pc_dir, recursive = TRUE, showWarnings = FALSE)

        # Save full model summary
        if (!is.null(model_details[[pc_name]]$lm_summary)) {
          sink(file.path(pc_dir, "full_model_summary.txt"))
          cat("=== FULL MODEL SUMMARY ===\n\n")
          cat("Formula:\n")
          cat(paste(deparse(model_details[[pc_name]]$lm_model$call), collapse = "\n"), "\n\n")
          print(model_details[[pc_name]]$lm_summary)
          cat("\n\n=== ANOVA TABLE ===\n\n")
          print(model_details[[pc_name]]$anova_table)
          sink()
        }

        # Save reduced model summaries
        if (!is.null(model_details[[pc_name]]$reduced_models)) {
          for (cov_name in names(model_details[[pc_name]]$reduced_models)) {
            sink(file.path(pc_dir, paste0("reduced_model_without_", cov_name, ".txt")))
            cat(paste0("=== REDUCED MODEL (without ", cov_name, ") ===\n\n"))
            cat("Formula:\n")
            cat(model_details[[pc_name]]$reduced_models[[cov_name]]$formula, "\n\n")
            print(model_details[[pc_name]]$reduced_models[[cov_name]]$summary)
            sink()
          }
        }

        # Save ANOVA comparisons (F-tests)
        if (!is.null(model_details[[pc_name]]$anova_comparisons)) {
          for (cov_name in names(model_details[[pc_name]]$anova_comparisons)) {
            sink(file.path(pc_dir, paste0("anova_ftest_", cov_name, ".txt")))
            cat(paste0("=== ANOVA F-test: Full vs Reduced (without ", cov_name, ") ===\n\n"))
            cat("Testing whether adding '", cov_name, "' significantly improves the model\n\n")
            print(model_details[[pc_name]]$anova_comparisons[[cov_name]])
            sink()
          }
        }

        # Save mixed model summary if exists
        if (!is.null(model_details[[pc_name]]$lmer_summary)) {
          sink(file.path(pc_dir, "mixed_model_summary.txt"))
          cat("=== MIXED EFFECTS MODEL SUMMARY ===\n\n")
          print(model_details[[pc_name]]$lmer_summary)
          sink()
        }

        # Save reduced mixed models if exists
        if (!is.null(model_details[[pc_name]]$lmer_reduced_models)) {
          for (cov_name in names(model_details[[pc_name]]$lmer_reduced_models)) {
            sink(file.path(pc_dir, paste0("reduced_mixed_model_without_", cov_name, ".txt")))
            cat(paste0("=== REDUCED MIXED MODEL (without ", cov_name, ") ===\n\n"))
            cat("Formula:\n")
            cat(model_details[[pc_name]]$lmer_reduced_models[[cov_name]]$formula, "\n\n")
            print(model_details[[pc_name]]$lmer_reduced_models[[cov_name]]$summary)
            sink()
          }
        }

        # Save LRT comparisons if exists
        if (!is.null(model_details[[pc_name]]$lrt_comparisons)) {
          for (cov_name in names(model_details[[pc_name]]$lrt_comparisons)) {
            sink(file.path(pc_dir, paste0("lrt_test_", cov_name, ".txt")))
            cat(paste0("=== Likelihood Ratio Test: Full vs Reduced (without ", cov_name, ") ===\n\n"))
            cat("Testing whether adding '", cov_name, "' significantly improves the mixed model\n\n")
            print(model_details[[pc_name]]$lrt_comparisons[[cov_name]])
            sink()
          }
        }
      }

      # Save heatmaps
      pdf(file.path(temp_dir, "partial_r2_heatmap.pdf"), width = 10, height = 8)
      print(plot_partial_r2_heatmap(pcCovResults$analysis_results))
      dev.off()

      pdf(file.path(temp_dir, "pvalue_heatmap.pdf"), width = 10, height = 8)
      print(plot_pvalue_heatmap(pcCovResults$analysis_results))
      dev.off()

      # Save individual plots for each covariate
      for (cov in pcCovResults$selected_covariates) {
        pdf(file.path(temp_dir, paste0("plots_", cov, ".pdf")), width = 12, height = 8)

        # Create multi-panel plot
        n_pcs <- length(pcCovResults$analysis_results$per_pc_stats$pc)
        n_cols <- min(3, n_pcs)
        n_rows <- ceiling(n_pcs / n_cols)

        par(mfrow = c(min(4, n_rows), n_cols))

        for (pc in head(pcCovResults$analysis_results$per_pc_stats$pc, 12)) {
          tryCatch({
            p <- plot_pc_vs_covariate(
              obj = seurat_object,
              reduction_name = pcCovResults$reduction_name,
              pc = pc,
              covariate = cov,
              analysis_results = pcCovResults$analysis_results
            )
            print(p)
          }, error = function(e) {
            print(paste("Error plotting", pc, "vs", cov))
          })
        }
        dev.off()
      }

      # Create README
      readme_content <- paste0(
        "PC Covariate Analysis Results\n",
        "==============================\n\n",
        "Analysis Date: ", Sys.Date(), "\n",
        "Reduction: ", pcCovResults$reduction_name, "\n",
        "Covariates: ", paste(pcCovResults$selected_covariates, collapse = ", "), "\n",
        "Number of PCs: ", nrow(pcCovResults$analysis_results$per_pc_stats), "\n\n",
        "Files and Directories:\n",
        "----------------------\n\n",
        "1. statistics_table.csv\n",
        "   Summary statistics for each PC-covariate combination\n",
        "   Includes: coefficients, p-values, partial R², full model R²\n\n",
        "2. model_comparison_integrated.csv\n",
        "   Integrated comparison table for both linear and mixed models\n",
        "   For each PC and term (main effect or interaction):\n",
        "   \n",
        "   Common columns:\n",
        "   - pc: Principal component ID\n",
        "   - term_removed: Covariate or interaction term being tested\n",
        "   - term_type: 'main_effect' or 'interaction'\n",
        "   - model_type: Always 'Linear Model' (for compatibility)\n",
        "   \n",
        "   Linear Model columns:\n",
        "   - full_model_r2, full_model_adj_r2, full_model_aic\n",
        "   - reduced_model_r2, reduced_model_adj_r2, reduced_model_aic\n",
        "   - partial_r2: Contribution of the removed term (full R² - reduced R²)\n",
        "   - delta_aic: Change in AIC (reduced - full; negative = term improves model)\n",
        "   - f_statistic, f_test_pvalue: ANOVA F-test results\n",
        "   \n",
        "   Mixed Model columns (if random effect specified):\n",
        "   - mixed_r2m: Marginal R² (variance explained by fixed effects only)\n",
        "   - mixed_r2c: Conditional R² (variance explained by fixed + random effects)\n",
        "   - mixed_delta_aic: Delta AIC for mixed model\n",
        "   - chisq_statistic: Chi-square statistic from Likelihood Ratio Test (LRT)\n",
        "   - lrt_pvalue: p-value from LRT (tests if term significantly improves model)\n\n",
        "3. model_details/[PC_name]/\n",
        "   Detailed model summaries for each PC:\n",
        "   - full_model_summary.txt: Complete summary of the full model\n",
        "     (includes all covariates, coefficients, R², F-statistic, ANOVA table)\n",
        "   - reduced_model_without_[term].txt: Summary of reduced model\n",
        "     (model without that specific term)\n",
        "   - anova_ftest_[term].txt: ANOVA F-test comparing full vs reduced model\n",
        "   - mixed_model_summary.txt: Mixed effects model (if random effect specified)\n",
        "   - reduced_mixed_model_without_[term].txt: Reduced mixed model\n",
        "   - lrt_test_[term].txt: Likelihood Ratio Test for mixed models\n\n",
        "4. plot_data.csv\n",
        "   Data used for plotting (effect sizes, p-values, partial R²)\n\n",
        "5. partial_r2_heatmap.pdf\n",
        "   Heatmap showing partial R² for each PC-covariate combination\n\n",
        "6. pvalue_heatmap.pdf\n",
        "   Heatmap showing -log10(p-value) for significance\n\n",
        "7. plots_[covariate].pdf\n",
        "   Individual scatter/box plots for each covariate across PCs\n\n",
        "Interpretation Guide:\n",
        "---------------------\n",
        "- Partial R²: Proportion of PC variance explained by a specific covariate\n",
        "  (0 = no contribution, 1 = explains all variance)\n",
        "- Delta AIC: Change in model fit when removing a covariate\n",
        "  (negative = covariate improves model, positive = covariate worsens model)\n",
        "- F-test (ANOVA): Tests whether adding a covariate significantly improves the linear model\n",
        "  Low p-value (< 0.05) = covariate significantly improves model fit\n",
        "- Likelihood Ratio Test (LRT): Tests whether adding a covariate improves the mixed model\n",
        "  Low p-value (< 0.05) = covariate significantly improves model fit\n",
        "- High partial R² + low p-value = strong association\n",
        "- Compare full vs reduced model R² to assess covariate importance\n"
      )
      writeLines(readme_content, file.path(temp_dir, "README.txt"))

      # Create Japanese README
      readme_ja_content <- paste0(
        "PC共変量解析 結果\n",
        "==================\n\n",
        "解析日: ", Sys.Date(), "\n",
        "Reduction: ", pcCovResults$reduction_name, "\n",
        "共変量: ", paste(pcCovResults$selected_covariates, collapse = ", "), "\n",
        "PC数: ", nrow(pcCovResults$analysis_results$per_pc_stats), "\n\n",
        "■ ファイルとディレクトリ:\n",
        "========================\n\n",
        "1. statistics_table.csv\n",
        "   各PC×共変量の統計サマリー\n",
        "   含まれる情報：回帰係数、p値、Partial R²、モデル全体のR²\n\n",
        "2. model_comparison.csv\n",
        "   線形モデルと混合効果モデルの統合比較テーブル\n",
        "   各PCと項（主効果または交互作用）について：\n",
        "   \n",
        "   線形モデルの列：\n",
        "   - Full model R²、Adjusted R²、AIC\n",
        "   - Reduced model R²、Adjusted R²、AIC（その項を除いた場合）\n",
        "   - Partial R²（その項の寄与度）\n",
        "   - Delta AIC（reduced - full；負の値 = 項がモデルを改善）\n",
        "   - F統計量とp値（ANOVA F検定）\n",
        "   \n",
        "   混合効果モデルの列（ランダム効果を指定した場合）：\n",
        "   - mixed_r2m: 周辺R²（固定効果のみ）\n",
        "   - mixed_r2c: 条件付きR²（固定効果+ランダム効果）\n",
        "   - mixed_delta_aic: 混合効果モデルのΔAIC\n",
        "   - chisq_statistic: χ²統計量（LRT）\n",
        "   - lrt_pvalue: 尤度比検定のp値\n\n",
        "3. mixed_model_comparison.csv（ランダム効果を指定した場合）\n",
        "   混合効果モデルの詳細比較テーブル（別ファイル）\n",
        "   （model_comparison.csvの混合効果モデル列と同じ情報）\n\n",
        "4. model_details/[PC名]/\n",
        "   各PCの詳細なモデルサマリー：\n",
        "   - full_model_summary.txt: フルモデルの完全なサマリー\n",
        "     （すべての共変量を含む、係数、R²、F統計量、ANOVAテーブル）\n",
        "   - reduced_model_without_[共変量].txt: 縮小モデルのサマリー\n",
        "     （特定の共変量を除いたモデル）\n",
        "   - anova_ftest_[共変量].txt: ANOVA F検定（フルモデル vs 縮小モデル）\n",
        "   - mixed_model_summary.txt: 混合効果モデル（ランダム効果を指定した場合）\n",
        "   - reduced_mixed_model_without_[共変量].txt: 縮小混合効果モデル\n",
        "   - lrt_test_[共変量].txt: 尤度比検定（混合効果モデル用）\n\n",
        "5. plot_data.csv\n",
        "   プロット用データ（効果量、p値、Partial R²）\n\n",
        "6. partial_r2_heatmap.pdf\n",
        "   各PC×共変量のPartial R²を示すヒートマップ\n\n",
        "7. pvalue_heatmap.pdf\n",
        "   統計的有意性を示す-log10(p値)のヒートマップ\n\n",
        "8. plots_[共変量].pdf\n",
        "   各共変量についてのPC別の散布図/箱ひげ図\n\n",
        "■ 結果の解釈ガイド:\n",
        "====================\n\n",
        "【Partial R²（部分決定係数）】\n",
        "- PCの分散のうち、特定の共変量で説明される割合\n",
        "- 範囲：0〜1（0% 〜 100%）\n",
        "- 解釈の目安：\n",
        "  * 0.01〜0.05: 小さい効果\n",
        "  * 0.06〜0.13: 中程度の効果\n",
        "  * 0.14以上: 大きい効果\n",
        "- 例：PC_1のpartial_r2_cell_type = 0.35\n",
        "  → PC1の分散の35%が細胞タイプで説明される（大きい効果）\n\n",
        "【Delta AIC】\n",
        "- 共変量を除いた場合のモデル適合度の変化\n",
        "- 解釈：\n",
        "  * 正で大きい（例：+150）→ 共変量を除くとモデルが悪化（重要な共変量）\n",
        "  * 正で小さい（例：+10）→ わずかに悪化（やや重要）\n",
        "  * 負（例：-5）→ 共変量を除いてもモデルが改善（不要な共変量）\n",
        "- 一般的な基準：\n",
        "  * |ΔAIC| < 2: ほとんど差がない\n",
        "  * 2 < |ΔAIC| < 7: 適度な差\n",
        "  * |ΔAIC| > 10: 大きな差\n\n",
        "【P値】\n",
        "- 統計的有意性の指標\n",
        "- p < 0.05: 統計的に有意（*マーク）\n",
        "- p < 0.01: 強い有意性\n",
        "- p < 0.001: 非常に強い有意性\n",
        "- 注意：サンプル数が多いと、小さい効果でも有意になる\n",
        "  → 必ずPartial R²（効果量）も確認すること！\n\n",
        "【F検定（ANOVA F-test）】\n",
        "- 線形モデルにおいて、共変量を追加することでモデルが有意に改善するかを検定\n",
        "- 帰無仮説：共変量を追加してもモデルの適合度は変わらない\n",
        "- 解釈：\n",
        "  * F統計量が大きい + p値が小さい（< 0.05）→ 共変量を追加するとモデルが有意に改善\n",
        "  * p値が大きい（> 0.05）→ 共変量を追加してもモデルはほとんど改善しない\n",
        "- 例：F = 125.3, p < 0.001 → その共変量は非常に重要（モデルに必須）\n\n",
        "【尤度比検定（LRT: Likelihood Ratio Test）】\n",
        "- 混合効果モデルにおいて、固定効果の共変量を追加することでモデルが改善するかを検定\n",
        "- ランダム効果は固定したまま、固定効果ブロックの寄与を評価\n",
        "- 帰無仮説：共変量を追加してもモデルの適合度は変わらない\n",
        "- 解釈：\n",
        "  * χ²統計量が大きい + p値が小さい（< 0.05）→ 共変量を追加するとモデルが有意に改善\n",
        "  * p値が大きい（> 0.05）→ 共変量を追加してもモデルはほとんど改善しない\n",
        "- 例：χ² = 87.5, p < 0.001 → その共変量は混合効果モデルに重要\n\n",
        "【Marginal R²とConditional R²（混合効果モデル）】\n",
        "- mixed_r2m（周辺R²）：固定効果のみで説明される分散\n",
        "  * 共変量の純粋な効果を表す\n",
        "- mixed_r2c（条件付きR²）：固定効果+ランダム効果で説明される分散\n",
        "  * モデル全体の説明力\n",
        "- mixed_r2c - mixed_r2m = ランダム効果の寄与度\n",
        "  * 例：mixed_r2c = 0.45, mixed_r2m = 0.30 → ランダム効果（ドナー等）が15%寄与\n\n",
        "【重要度の判断】\n",
        "以下の組み合わせで判断：\n",
        "\n",
        "線形モデルの場合：\n",
        "1. Partial R²が高い（> 0.1）+ F検定p値が小さい（< 0.05）\n",
        "   → 確実に重要な項\n",
        "2. Delta AICが大きく正（> 50）+ F検定p値が小さい\n",
        "   → モデルに必要な項\n",
        "3. Partial R²は低いがF検定p値は有意\n",
        "   → 統計的には有意だが効果は小さい（実質的な重要性は低い可能性）\n",
        "\n",
        "混合効果モデルの場合（ランダム効果指定時）：\n",
        "1. LRTのp値が小さい（< 0.05）\n",
        "   → ランダム効果を考慮しても項が有意に寄与（真に重要）\n",
        "2. F検定は有意だがLRTは非有意\n",
        "   → グルーピング構造（ドナー等）を考慮すると有意でなくなる（疑似相関の可能性）\n",
        "3. 両方とも有意（F検定 < 0.05, LRT < 0.05）\n",
        "   → グルーピング構造に関係なく確実に重要な項\n\n",
        "■ 具体的な使用例:\n",
        "==================\n\n",
        "【例1：バッチ効果の確認】\n",
        "目的：どのPCがバッチで説明されるか確認\n",
        "見方：\n",
        "- partial_r2_heatmap.pdfでbatch列を確認\n",
        "- Partial R²が高いPC（例：PC3で0.25）を発見\n",
        "→ 結論：PC3はバッチ効果の影響を強く受けている\n",
        "→ 対応：そのPCをクラスタリングから除外するか、バッチ補正を検討\n\n",
        "【例2：生物学的要因の特定】\n",
        "目的：どのPCが細胞タイプの違いを捉えているか\n",
        "見方：\n",
        "- partial_r2_heatmap.pdfでcell_type列を確認\n",
        "- PC1とPC2でPartial R²が高い（0.35, 0.28）\n",
        "→ 結論：PC1とPC2は細胞タイプの主要な違いを表現\n",
        "→ 対応：これらのPCは重要なので、クラスタリングに含める\n\n",
        "【例3：モデル比較による評価】\n",
        "model_comparison.csvで各共変量の重要性を確認：\n",
        "\n",
        "PC_1, cell_type:  partial_r2=0.35, delta_aic=150\n",
        "  → 非常に重要（除くとモデルが大幅に悪化）\n",
        "\n",
        "PC_1, batch:      partial_r2=0.05, delta_aic=15\n",
        "  → やや重要だが効果は小さい\n",
        "\n",
        "PC_1, age:        partial_r2=0.01, delta_aic=-2\n",
        "  → ほぼ不要（除いてもモデルに影響なし）\n\n",
        "【例4：クラスタリングへの応用】\n",
        "1. バッチや技術的要因で説明されるPCを特定\n",
        "2. それらのPCをクラスタリングから除外\n",
        "3. 生物学的要因（細胞タイプ、疾患状態など）で説明されるPCのみを使用\n",
        "→ より生物学的に意味のあるクラスタリング結果が得られる\n\n",
        "【例5：混合効果モデルによる評価（ランダム効果：donor）】\n",
        "目的：ドナー間変動を考慮した上で、細胞タイプの効果が真に重要かを判定\n",
        "見方：\n",
        "- model_comparison.csvでcell_typeの行を確認\n",
        "\n",
        "結果の例：\n",
        "PC_1, cell_type:\n",
        "  - partial_r2 = 0.30, f_test_pvalue < 0.001 (線形モデル)\n",
        "  - lrt_pvalue < 0.001 (混合効果モデル)\n",
        "  - mixed_r2m = 0.35, mixed_r2c = 0.42\n",
        "\n",
        "解釈：\n",
        "- F検定もLRTも有意 → ドナー間変動を考慮しても細胞タイプは重要\n",
        "- mixed_r2c - mixed_r2m = 0.07 → ドナー効果が7%寄与\n",
        "→ 結論：PC1は主に細胞タイプの違いを捉えており、ドナー効果は小さい\n",
        "→ 対応：このPCはクラスタリングに重要\n\n",
        "【例6：疑似相関の検出（ランダム効果：batch）】\n",
        "結果の例：\n",
        "PC_3, treatment:\n",
        "  - partial_r2 = 0.18, f_test_pvalue = 0.001 (線形モデル)\n",
        "  - lrt_pvalue = 0.12 (混合効果モデル、非有意)\n",
        "\n",
        "解釈：\n",
        "- F検定は有意だがLRTは非有意\n",
        "→ バッチ構造を考慮すると処置効果は有意でなくなる\n",
        "→ 処置とバッチが交絡している可能性（疑似相関）\n",
        "→ 対応：バッチ補正を行うか、処置効果の解釈に注意が必要\n\n",
        "■ よくある質問:\n",
        "================\n\n",
        "Q1: Partial R²とR²の違いは？\n",
        "A1: \n",
        "- R²：モデル全体の説明力（すべての共変量の合計）\n",
        "- Partial R²：特定の共変量だけの寄与度\n",
        "- 全共変量のPartial R²の合計 ≠ R²（共変量間の相関があるため）\n\n",
        "Q2: p値は有意だがPartial R²が小さい場合は？\n",
        "A2: \n",
        "- 統計的には有意だが、実質的な効果は小さい\n",
        "- サンプル数が多い場合によく起こる\n",
        "- Partial R²（効果量）を重視して判断すべき\n\n",
        "Q3: Delta AICが負の共変量は完全に不要？\n",
        "A3: \n",
        "- 必ずしもそうではない\n",
        "- 他の共変量との相互作用がある可能性\n",
        "- 生物学的に重要な場合は残すことを検討\n\n",
        "Q4: どのPCをクラスタリングに使うべき？\n",
        "A4: \n",
        "1. 生物学的要因（細胞タイプなど）でPartial R²が高いPCを使用\n",
        "2. バッチや技術的要因でPartial R²が高いPCは除外を検討\n",
        "3. Elbow plotと合わせて総合的に判断\n\n",
        "Q5: F検定は有意だがLRTは非有意の場合、どう解釈する？\n",
        "A5: \n",
        "- グルーピング構造（ドナー、バッチ等）を考慮すると効果が消える\n",
        "- 共変量とランダム効果が交絡している可能性（疑似相関）\n",
        "- 真の効果ではない可能性が高いため、慎重に解釈すべき\n",
        "- 対応：バッチ補正や層別解析を検討\n\n",
        "Q6: mixed_r2m（周辺R²）とmixed_r2c（条件付きR²）の差が大きい場合は？\n",
        "A6: \n",
        "- ランダム効果（ドナー、バッチ等）の寄与が大きい\n",
        "- 個体間・バッチ間の変動が大きい\n",
        "- 例：mixed_r2c = 0.50, mixed_r2m = 0.25 → ランダム効果が25%寄与\n",
        "- 対応：ランダム効果を無視できないため、混合効果モデルの使用が適切\n\n",
        "Q7: 交互作用項が有意な場合、主効果はどう解釈する？\n",
        "A7: \n",
        "- 交互作用が有意な場合、主効果の解釈は注意が必要\n",
        "- 主効果は「もう一方の共変量が基準レベルの時の効果」を表す\n",
        "- 例：cell_type:treatmentが有意 → 処置効果が細胞タイプによって異なる\n",
        "- 対応：層別解析や可視化で詳細を確認すべき\n\n",
        "==================\n",
        "作成日: ", Sys.Date(), "\n",
        "解析ツール: SCALA PC Covariate Analysis\n"
      )
      writeLines(readme_ja_content, file.path(temp_dir, "README_ja.txt"))

      # Create ZIP file (include all files and model_details directory)
      files_to_zip <- c(
        list.files(temp_dir, pattern = "^(statistics|plot_data|model_comparison|partial|pvalue|plots_|README)", full.names = TRUE),
        list.dirs(file.path(temp_dir, "model_details"), full.names = TRUE, recursive = TRUE)
      )
      # Also include all files in model_details subdirectories
      model_detail_files <- list.files(file.path(temp_dir, "model_details"),
                                       recursive = TRUE,
                                       full.names = TRUE)
      files_to_zip <- c(files_to_zip, model_detail_files)
      files_to_zip <- unique(files_to_zip[file.exists(files_to_zip)])

      zip::zip(file, files = files_to_zip, mode = "cherry-pick")
    }
  )
  # ===== End PC Covariate Analysis =====

  #ATAC LSI
  observeEvent(input$lsiConfirm, {
    session$sendCustomMessage("handler_log", " ### Starting PC Exploration ###")
    session$sendCustomMessage("handler_startLoader", c("lsi_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "lsiConfirm")
    tryCatch({
      if (identical(proj_default, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
