max_dims <- ncol(seurat_object@reductions[[input$utilitiesActiveReduction]]@cell.embeddings)

if (as.numeric(snn_dims) > max_dims) {showNotification(paste0("The dimension set is larger than the existing dimensions. Dim for calc is set to ", max_dims), type="error") }

# snn_dimsと実際の最大次元数の小さい方を使用
actual_dims <- min(as.numeric(snn_dims), max_dims)

        # Seurat v5: Fix cell order in reductions to match main object
        # This is required because Seurat v5 has strict validation
        reduction_name <- input$utilitiesActiveReduction
        obj_cells <- colnames(seurat_object)
        red_cells <- rownames(seurat_object@reductions[[reduction_name]]@cell.embeddings)

        if (!identical(obj_cells, red_cells)) {
          print(paste("Fixing cell order in reduction:", reduction_name))
          # Check if all cells exist
          if (all(obj_cells %in% red_cells)) {
            # Reorder reduction embeddings to match object cell order
            seurat_object@reductions[[reduction_name]]@cell.embeddings <<-
              seurat_object@reductions[[reduction_name]]@cell.embeddings[obj_cells, , drop = FALSE]
            print("Cell order fixed successfully")
          } else {
            missing_cells <- setdiff(obj_cells, red_cells)
            showNotification(paste("Warning: Some cells missing in reduction:", length(missing_cells), "cells"), type = "warning")
          }
