    #updateInpuTrajectoryClustersATAC()
    session$sendCustomMessage("handler_enableTabs", c("sidebarMenu", " UMAP etc", " CLUSTERING"," LIGAND - RECEPTOR\nANALYSIS", " TRAJECTORY ANALYSIS"," CLUSTERS' ANNOTATION",
     " MARKERS' IDENTIFICATION"," DEG ANALYSIS", " PSEUDOBULK", " GENE SET SCORE",  " CELL CYCLE PHASE ANALYSIS", " DOUBLETS' DETECTION"))
    session$sendCustomMessage("handler_disableAllButtons", "umapConfirmATAC")
    }
      }, error = function(e) {
        print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
