    updateReductionATAC()
  })

  observeEvent(input$umapRunUmap, {
    session$sendCustomMessage("handler_startLoader", c("dim_red1_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "umapRunUmap")
    session$sendCustomMessage("handler_disableAllButtons", "umapRunTsne")
    session$sendCustomMessage("handler_disableAllButtons", "umapRunDFM")
    session$sendCustomMessage("handler_disableAllButtons", "umapRunPhate")
    tryCatch({
      if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
#      else if ( !(str_detect(paste(names(seurat_object@reductions), collapse = ""), pattern = 'pca') | str_detect(paste(names(seurat_object@reductions), collapse = ""), pattern = 'mnn') ) ) {session$sendCustomMessage("handler_alert", "Please, first execute PRINCIPAL COMPONENT ANALYSIS.")}
      else {
        showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%
        session$sendCustomMessage("handler_startLoader", c("dim_red1_loader", 25))

        ReductionUse <<- input$utilitiesActiveReduction2


        if (input$useAllDims) {
          dim_use <- dim(seurat_object@reductions[[ReductionUse]]@cell.embeddings)[2]
          showNotification(paste0(as.character(dim_use), " dimensions are used to calculate"), type='warning', duration = 100)
          } else {
            dim_use <- as.numeric(input$umapPCs)
          }

        print('ReductionUse')
        print(ReductionUse)

        if (input$densmap){
          umap.key <- "densMAP"
          umap.low.key <- 'densmap'
        } else {
          umap.low.key <- 'umap'
          umap.key <- 'UMAP'
        }

        # reduction nameを決める
        if (ReductionUse == 'pca') {
          reduction.name <- umap.low.key
          reduction.key.name <- paste0(umap.key, '_')
        } else {if (ReductionUse == 'seurat.pca') {
          ReductionUse <- paste0('seurat.', umap.low.key)
          reduction.key.name <- paste0('seurat.', umap.key)
        } else {
          reduction.name <- paste0( ReductionUse, '.', umap.low.key)
          reduction.key.name <- paste0( ReductionUse,'.', umap.key, '_')
        }}

        if (input$umap_n_neighbors != 30){ #n_neighborを調整したときは名前につける
          reduction.name <- paste0( reduction.name, '.n_neighbor', as.character(input$umap_n_neighbors) )

        }


        if (input$umapOutComponents>2) {
          reduction.name <- paste0( reduction.name,as.character(input$umapOutComponents),'D')
        }

        print('ReductionUse')
        print(ReductionUse)
        print('reduction.name')
        print(reduction.name)
        print('reduction.key.name')
        print(reduction.key.name)


        seurat_object <<- RunUMAP(seurat_object, dims = 1:dim_use, seed.use = as.numeric(input$umapSeed), n.components = as.numeric(input$umapOutComponents), reduction =  ReductionUse, reduction.name = reduction.name , reduction.key = reduction.key.name, n.neighbors = input$umap_n_neighbors, min.dist = input$umap_min_dist, densmap = input$densmap, dens.frac = input$dens.frac, dens.lambda = input$dens.lambda )

        showNotification(paste0("Umap was calclulated based on ", ReductionUse, " and stored as ", reduction.name), duration = 120)
        session$sendCustomMessage("handler_enableTabs", c("sidebarMenu", " TRAJECTORY ANALYSIS", " GENE REGULATORY NETWORK\nANALYSIS"))
        updateUmapTypeChoices(reduction.name)
        updateReduction2(reduction.name, 2)
      #  updateUtilitiesReduction()
        updatePCs_selection(as.numeric(input$umapPCs)) #numPCを合わせる
      }
    }, error = function(e) {
      print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
      session$sendCustomMessage("handler_alert", "There was an error with the UMAP procedure. May need to change 'reduction for calc UMAP'")
    }, finally = {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("dim_red1_loader", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "dim_red1_loader")
      session$sendCustomMessage("handler_enableAllButtons", "umapRunUmap")
      session$sendCustomMessage("handler_enableAllButtons", "umapRunTsne")
      session$sendCustomMessage("handler_enableAllButtons", "umapRunDFM")
      session$sendCustomMessage("handler_enableAllButtons", "umapRunPhate")
    })
  })

