  # ===== ForceAtlas2 Handler =====
  observeEvent(input$umapRunFA2, {
    session$sendCustomMessage("handler_startLoader", c("dim_red1_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "umapRunUmap")
    session$sendCustomMessage("handler_disableAllButtons", "umapRunTsne")
    session$sendCustomMessage("handler_disableAllButtons", "umapRunDFM")
    session$sendCustomMessage("handler_disableAllButtons", "umapRunPhate")
    tryCatch({
      if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
      else if (!("snn" %in% names(seurat_object@graphs) || any(grepl("_snn", names(seurat_object@graphs))))) {
        session$sendCustomMessage("handler_alert", "Please, run Find Neighbors first to compute SNN graph.")
      }
      else {
        showModal(modalDialog(div('ForceAtlas2 in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;'))
        session$sendCustomMessage("handler_startLoader", c("dim_red1_loader", 25))

        ReductionUse <<- input$utilitiesActiveReduction2

        # reduction nameを決める
        if (ReductionUse == 'pca') {
          reduction.name <- 'fa2'
          reduction.key.name <- 'FA2_'
        } else {
          reduction.name <- paste0(ReductionUse, '.fa2')
          reduction.key.name <- paste0(ReductionUse, '.FA2_')
        }

        print('Running ForceAtlas2 (Python fa2)')
        print(paste('ReductionUse:', ReductionUse))
        print(paste('reduction.name:', reduction.name))

        # Get SNN graph
        snn_graph_name <- names(seurat_object@graphs)[grep("_snn", names(seurat_object@graphs))[1]]
        if (is.na(snn_graph_name)) snn_graph_name <- "snn"
        snn_matrix <- seurat_object@graphs[[snn_graph_name]]
        n_cells <- ncol(seurat_object)

        # Convert sparse matrix to edge list for Python fa2
        library(Matrix)
        library(reticulate)

        # Get upper triangle to avoid duplicate edges
        snn_upper <- triu(snn_matrix)

        # Import Python modules
        fa2_module <- import("fa2_modified")
        nx <- import("networkx")

        # Create networkx graph from scipy sparse matrix (fast)
        scipy_sparse <- import("scipy.sparse")
        snn_coo <- scipy_sparse$coo_matrix(as.matrix(snn_upper))
        G <- nx$from_scipy_sparse_array(snn_coo)
        print(paste("Graph created with", G$number_of_nodes(), "nodes and", G$number_of_edges(), "edges"))

        # Create ForceAtlas2 object (with Barnes-Hut optimization for speed)
        forceatlas2 <- fa2_module$ForceAtlas2(
          outboundAttractionDistribution = TRUE,
          linLogMode = input$fa2_linlog,
          adjustSizes = input$fa2_prevent_overlap,
          edgeWeightInfluence = 1.0,
          jitterTolerance = 1.0,
          barnesHutOptimize = TRUE,
          barnesHutTheta = 1.2,
          scalingRatio = 2.0,
          strongGravityMode = FALSE,
          gravity = 1.0,
          verbose = TRUE
        )

        # Run ForceAtlas2
        print(paste("Running ForceAtlas2 with", input$fa2_iterations, "iterations..."))
        fa2_layout <- forceatlas2$forceatlas2_networkx_layout(
          G,
          pos = NULL,
          iterations = as.integer(input$fa2_iterations)
        )

        # Convert dict to matrix
        fa2_matrix <- matrix(0, nrow = n_cells, ncol = 2)
        for (i in 0:(n_cells - 1)) {
          coords <- fa2_layout[[as.character(i)]]
          fa2_matrix[i + 1, ] <- as.numeric(coords)
        }

        # Create dimension reduction object
        rownames(fa2_matrix) <- colnames(seurat_object)
        colnames(fa2_matrix) <- c(paste0(reduction.key.name, "1"), paste0(reduction.key.name, "2"))

        seurat_object[[reduction.name]] <<- CreateDimReducObject(
          embeddings = fa2_matrix,
          key = reduction.key.name,
          assay = DefaultAssay(seurat_object)
        )

        showNotification(paste0("ForceAtlas2 was calculated based on SNN graph and stored as ", reduction.name), duration = 120)
        session$sendCustomMessage("handler_enableTabs", c("sidebarMenu", " TRAJECTORY ANALYSIS", " GENE REGULATORY NETWORK\nANALYSIS"))
        updateUmapTypeChoices(reduction.name)
        updateReduction2(reduction.name, 2)
        updatePCs_selection(as.numeric(input$umapPCs))
      }
    }, error = function(e) {
      print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
      session$sendCustomMessage("handler_alert", "There was an error with the ForceAtlas2 procedure.")
    }, finally = {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("dim_red1_loader", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "dim_red1_loader")
      session$sendCustomMessage("handler_enableAllButtons", "umapRunUmap")
      session$sendCustomMessage("handler_enableAllButtons", "umapRunTsne")
      session$sendCustomMessage("handler_enableAllButtons", "umapRunDFM")
      session$sendCustomMessage("handler_enableAllButtons", "umapRunPhate")
    })
  })

  # ===== TriMap Handler =====
  observeEvent(input$umapRunTrimap, {
    session$sendCustomMessage("handler_startLoader", c("dim_red1_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "umapRunUmap")
    session$sendCustomMessage("handler_disableAllButtons", "umapRunTsne")
    session$sendCustomMessage("handler_disableAllButtons", "umapRunDFM")
    session$sendCustomMessage("handler_disableAllButtons", "umapRunPhate")
    tryCatch({
      if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
      else {
        showModal(modalDialog(div('TriMap in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;'))
        session$sendCustomMessage("handler_startLoader", c("dim_red1_loader", 25))

        ReductionUse <<- input$utilitiesActiveReduction2

        if (input$useAllDims) {
          dim_use <- dim(seurat_object@reductions[[ReductionUse]]@cell.embeddings)[2]
          showNotification(paste0(as.character(dim_use), " dimensions are used to calculate"), type='warning', duration = 100)
        } else {
          dim_use <- as.numeric(input$umapPCs)
        }

        # reduction nameを決める
        if (ReductionUse == 'pca') {
          reduction.name <- 'trimap'
          reduction.key.name <- 'TriMap_'
        } else {
          reduction.name <- paste0(ReductionUse, '.trimap')
          reduction.key.name <- paste0(ReductionUse, '.TriMap_')
        }

        if (input$umapOutComponents > 2) {
          reduction.name <- paste0(reduction.name, as.character(input$umapOutComponents), 'D')
        }

        print('Running TriMap')
        print(paste('ReductionUse:', ReductionUse))
        print(paste('reduction.name:', reduction.name))

        # Get PCA embeddings
        pca_embeddings <- seurat_object@reductions[[ReductionUse]]@cell.embeddings[, 1:dim_use]

        # Run TriMap via reticulate
        library(reticulate)
        trimap <- import("trimap")

        trimap_model <- trimap$TRIMAP(
          n_dims = as.integer(input$umapOutComponents),
          n_inliers = as.integer(input$trimap_n_inliers),
          n_outliers = as.integer(input$trimap_n_outliers),
          n_random = as.integer(input$trimap_n_random),
          n_iters = as.integer(input$trimap_n_iters)
        )

        trimap_result <- trimap_model$fit_transform(pca_embeddings)

        # Create dimension reduction object
        rownames(trimap_result) <- rownames(pca_embeddings)
        col_names <- paste0(reduction.key.name, 1:ncol(trimap_result))
        colnames(trimap_result) <- col_names

        seurat_object[[reduction.name]] <<- CreateDimReducObject(
          embeddings = trimap_result,
          key = reduction.key.name,
          assay = DefaultAssay(seurat_object)
        )

        showNotification(paste0("TriMap was calculated based on ", ReductionUse, " and stored as ", reduction.name), duration = 120)
        session$sendCustomMessage("handler_enableTabs", c("sidebarMenu", " TRAJECTORY ANALYSIS", " GENE REGULATORY NETWORK\nANALYSIS"))
        updateUmapTypeChoices(reduction.name)
        updateReduction2(reduction.name, 2)
        updatePCs_selection(as.numeric(input$umapPCs))
      }
    }, error = function(e) {
      print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
      session$sendCustomMessage("handler_alert", "There was an error with the TriMap procedure. Make sure trimap is installed in r-scvi conda env.")
    }, finally = {
