# Feature Inspection Heatmap
observeEvent(input$heatmapConfirm, {
  session$sendCustomMessage("handler_startLoader", c("heatmap_loader", 10))
  session$sendCustomMessage("handler_disableAllButtons", "heatmapConfirm")
  tryCatch({
    if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
    else {
      showModal(modalDialog(div('Generating heatmap...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;'))

      # Determine genes to plot
      if (input$heatmapGeneSource == "hvg") {
        # Use top HVGs (Assay5対応)
        hvg_info <- get_meta_features(seurat_object, seurat_object@active.assay)
        if ("vst.variance.standardized" %in% colnames(hvg_info)) {
          top_hvgs <- hvg_info %>%
            arrange(desc(vst.variance.standardized)) %>%
            head(input$heatmapHVGNum) %>%
            rownames()
          genes_to_plot <- top_hvgs
        } else {
          session$sendCustomMessage("handler_alert", "HVGs not found. Please run FindVariableFeatures first.")
          removeModal()
          session$sendCustomMessage("handler_enableAllButtons", "heatmapConfirm")
          return()
        }
      } else {
        # Parse gene list from text area input (same algorithm as violin plot)
        varTextarea <- input$heatmapGeneList
        split_values <- unlist(strsplit(varTextarea, "[[:space:],\n\t]+"))
        # Remove any empty strings
        split_values <- split_values[split_values != ""]
        # Trim leading and trailing whitespace
        split_values <- trimws(split_values)
        # Assign the result to input_markers
        input_markers <- as.vector(split_values)

        # インデックスを取得して元の表記を保持
        idx <- match(tolower(input_markers), tolower(rownames(seurat_object)))
        # NAを除外して一意な遺伝子名を取得
        markers <- unique(rownames(seurat_object)[idx[!is.na(idx)]])

        # もしテキストエリアに遺伝子がない場合はselectizeで選択されているものを使用
        if (length(markers) == 0) {
          if (!is.null(input$heatmapGeneSelect) && length(input$heatmapGeneSelect) > 0) {
            genes_to_plot <- input$heatmapGeneSelect
          } else {
            session$sendCustomMessage("handler_alert", "Please select or enter at least one gene.")
            removeModal()
            session$sendCustomMessage("handler_enableAllButtons", "heatmapConfirm")
            return()
          }
        } else {
          genes_to_plot <- markers
        }
      }

      # Filter genes that exist in the data
      available_genes <- rownames(seurat_object[[seurat_object@active.assay]])
      genes_to_plot <- intersect(genes_to_plot, available_genes)

      if (length(genes_to_plot) == 0) {
        session$sendCustomMessage("handler_alert", "None of the selected genes were found in the data.")
        removeModal()
        session$sendCustomMessage("handler_enableAllButtons", "heatmapConfirm")
        return()
      }

      # Set group.by
      group_by_var <- input$heatmapGroupBy
      if (!(group_by_var %in% colnames(seurat_object@meta.data))) {
        group_by_var <- "seurat_clusters"
      }

      # Temporarily set Idents for grouping
      original_idents <- Idents(seurat_object)
      Idents(seurat_object) <- group_by_var

      # Prepare colors
      if (isTRUE(input$hm2UseUmapColors)) {
        shared <- shared_cluster_cols()
        if (!is.null(shared$cols) && identical(shared$colorBy, input$heatmapGroupBy)) {
          cols <- shared$cols
        } else {
          cols <- brewer.pal(12, "Set3")
        }
      } else {
      if (input$heatmapColorPalette2 == "Set1") {
        if (length(levels(factor(Idents(seurat_object))))<10) {
          cols = brewer.pal(9, input$heatmapColorPalette2)
        } else {
          cols = colorRampPalette(brewer.pal(9, input$heatmapColorPalette2))(length(levels(factor(Idents(seurat_object)))))
        }
      }

      if (input$heatmapColorPalette2 == "Set2") {
        if ((length(levels(factor(Idents(seurat_object)))))<9) {
          cols = brewer.pal(8, input$heatmapColorPalette2)
        } else {
          cols = colorRampPalette(brewer.pal(8, input$heatmapColorPalette2))(length(levels(factor(Idents(seurat_object)))))
        }
      }

      if (input$heatmapColorPalette2 == "Set3" | input$heatmapColorPalette2 == "Paired") {
        if ((length(levels(factor(Idents(seurat_object)))))<13) {
          cols = brewer.pal(12, input$heatmapColorPalette2)
        } else {
          cols = colorRampPalette(brewer.pal(12, input$heatmapColorPalette2))(length(levels(factor(Idents(seurat_object)))))
        }
      }
      }

      # Check if clustering is requested
      use_clustering <- input$heatmapClusterRows || input$heatmapClusterCols

      if (use_clustering) {
        # Use pheatmap for clustering
        showNotification("Using pheatmap for clustering visualization")

        # Extract expression data (v5対応: GetAssayDataを使用)
        if (input$heatmapSlot == "scale.data") {
          scale_data <- tryCatch({
            Seurat::GetAssayData(seurat_object, assay = seurat_object@active.assay, layer = "scale.data")
          }, error = function(e) {
            Seurat::GetAssayData(seurat_object, assay = seurat_object@active.assay, slot = "scale.data")
          })
          scaled_genes <- rownames(scale_data)
          missing_genes <- setdiff(genes_to_plot, scaled_genes)

          if (length(missing_genes) > 0) {
            showNotification("Scaling additional genes...")
            seurat_object <<- ScaleData(
              seurat_object,
              features = missing_genes,
              verbose = FALSE
            )
            # Re-fetch after scaling
            scale_data <- tryCatch({
              Seurat::GetAssayData(seurat_object, assay = seurat_object@active.assay, layer = "scale.data")
            }, error = function(e) {
              Seurat::GetAssayData(seurat_object, assay = seurat_object@active.assay, slot = "scale.data")
            })
          }
          expr_data <- as.matrix(scale_data[genes_to_plot, , drop = FALSE])
        } else {
          # Use data slot (v5対応)
          data_mat <- tryCatch({
            Seurat::GetAssayData(seurat_object, assay = seurat_object@active.assay, layer = "data")
          }, error = function(e) {
            Seurat::GetAssayData(seurat_object, assay = seurat_object@active.assay, slot = "data")
          })
          expr_data <- as.matrix(data_mat[genes_to_plot, , drop = FALSE])
        }

        # Downsample if requested
        if (input$heatmapDownsample && input$heatmapDownNum < ncol(expr_data)) {
          sampled_cells <- sample(colnames(expr_data), input$heatmapDownNum)
          expr_data <- expr_data[, sampled_cells, drop = FALSE]
        }

        # Prepare annotation for cells
        cell_anno <- data.frame(
          Cluster = seurat_object@meta.data[colnames(expr_data), group_by_var],
          row.names = colnames(expr_data)
        )
        colnames(cell_anno)[1] <- group_by_var

        # Remove cells with NA annotations
        cells_with_anno <- !is.na(cell_anno[[group_by_var]])
        if (sum(!cells_with_anno) > 0) {
          showNotification(paste("Removing", sum(!cells_with_anno), "cells with NA annotation"))
          cell_anno <- cell_anno[cells_with_anno, , drop = FALSE]
          expr_data <- expr_data[, cells_with_anno, drop = FALSE]
        }

        # Prepare annotation colors
        anno_colors <- list()
        # Only include non-NA levels in the color palette
        valid_levels <- levels(factor(cell_anno[[group_by_var]]))
        valid_levels <- valid_levels[!is.na(valid_levels)]
        anno_colors[[group_by_var]] <- setNames(cols[1:length(valid_levels)], valid_levels)

        # Create pheatmap
        output$featureHeatmap <- renderPlot({
          feature_heatmap_plot <<- pheatmap(
            expr_data,
            cluster_rows = input$heatmapClusterRows,
            cluster_cols = input$heatmapClusterCols,
            annotation_col = cell_anno,
            annotation_colors = anno_colors,
            show_colnames = FALSE,
            color = colorRampPalette(c("blue", "white", "red"))(100),
            breaks = seq(-2.5, 2.5, length.out = 101),
            fontsize_row = 10,
            fontsize = 9,
            border_color = NA
          )
        }, height=as.numeric(input$heatmapHeight2), width=as.numeric(input$heatmapWidth2))

      } else {
        # Use DoHeatmap (no clustering)
        showNotification("Using DoHeatmap (no clustering)")

        # Check if rasterization is needed
        features_count <- length(genes_to_plot)
        cells_count <- ncol(seurat_object)
        use_raster <- FALSE
        if (features_count * cells_count > 100000) {
          use_raster <- TRUE
          showNotification("Large heatmap detected, using rasterization.")
        }

        # If using scale.data, ensure genes are scaled (v5対応)
        if (input$heatmapSlot == "scale.data") {
          scale_data <- tryCatch({
            Seurat::GetAssayData(seurat_object, assay = seurat_object@active.assay, layer = "scale.data")
          }, error = function(e) {
            Seurat::GetAssayData(seurat_object, assay = seurat_object@active.assay, slot = "scale.data")
          })
          scaled_genes <- rownames(scale_data)
          missing_genes <- setdiff(genes_to_plot, scaled_genes)

          if (length(missing_genes) > 0) {
            showNotification("Scaling additional genes...")
            seurat_object <<- ScaleData(
              seurat_object,
              features = missing_genes,
              verbose = FALSE
            )
          }
        }

        # Generate heatmap with DoHeatmap
        if (input$heatmapDownsample && input$heatmapDownNum < ncol(seurat_object)) {
          p <- DoHeatmap(
            seurat_object,
            features = genes_to_plot,
            cells = sample(Cells(seurat_object), input$heatmapDownNum),
            group.bar = TRUE,
            group.colors = cols,
            disp.min = -2.5,
            disp.max = NULL,
            slot = input$heatmapSlot,
            label = TRUE,
            size = 5.5,
            angle = 45,
            draw.lines = TRUE,
            lines.width = NULL,
            group.bar.height = 0.02,
            raster = use_raster
          )
        } else {
          p <- DoHeatmap(
            seurat_object,
            features = genes_to_plot,
            group.bar = TRUE,
            group.colors = cols,
            disp.min = -2.5,
            disp.max = NULL,
            slot = input$heatmapSlot,
            label = TRUE,
            size = 5.5,
            angle = 45,
            draw.lines = TRUE,
            lines.width = NULL,
            group.bar.height = 0.02,
            raster = use_raster
          )
        }

        # Render plot
        output$featureHeatmap <- renderPlot(p, height=as.numeric(input$heatmapHeight2), width=as.numeric(input$heatmapWidth2))
      }

      # Restore original idents
      Idents(seurat_object) <- original_idents

      removeModal()
    }
  }, error = function(e) {
    session$sendCustomMessage("handler_alert", paste("Error:", e$message))
    removeModal()
  })
  session$sendCustomMessage("handler_enableAllButtons", "heatmapConfirm")
})

