#markers <- unique(input_markers[tolower(input_markers) %in% tolower(rownames(seurat_object))])
  #      showNotification(paste0('Genes are: ', as.character(markers)), duration=60)

# インデックスを取得して元の表記を保持
idx <- match(tolower(input_markers), tolower(rownames(seurat_object)))
# NAを除外して一意な遺伝子名を取得
markers <- unique(rownames(seurat_object)[idx[!is.na(idx)]])
  print(markers)

  #          plot <- VlnPlot(seurat_object, features = markers,
  #                          group.by = input$vlnGroupBy, stack = T, flip = T)
print("2=======")

#もしbox内に遺伝子がない場合は上で入れているものを表示する
#ベタが気に対応
if (length(markers) == 0) {

            geneS <- c("")
            if(input$findMarkersViolinFeaturesSignature == "gene")
            {
              geneS <- input$findMarkersGeneSelect2
            }
            else
            {
              geneS <- input$findMarkersViolinSignatureSelect
            }
            print(geneS)
            markers <- geneS

} else { geneS <- markers}

print('geneS')
print(geneS)

gl_geneS <<- geneS[1]


# 遺伝子名がcluster名に使われているときへの対応
if(input$findMarkersViolinFeaturesSignature == "gene") {
metaname <- names(seurat_object[[]])
print('metaname')
print(metaname)
for (x in c(1:length(geneS))) {
    if (geneS[x] %in% metaname){
        geneS[x] <- paste0(tolower(DefaultAssay(seurat_object)),"_",geneS[x])
    }
}
}
print("Modified genes")
print(geneS)

        #prepare metadata
        meta <- seurat_object@meta.data
        meta <- meta[, ]

        #prepare colors
        color_length <- length(unique(meta[, input$vlnGroupBy]))

      # Use UMAP colors if checkbox is checked and colorBy matches
      if (isTRUE(input$vlnUseUmapColors)) {
        shared <- shared_cluster_cols()
        if (!is.null(shared$cols) && identical(shared$colorBy, input$vlnGroupBy)) {
          cols <- shared$cols
          col_vector <- unname(shared$cols)
        } else {
          # Fallback to default palette
          col_vector <- brewer.pal(min(20, brewer.pal.info["Set1", "maxcolors"]), "Set1")
          if (length(col_vector) < color_length) {
            cols <- colorRampPalette(col_vector)(color_length)
          } else {
            cols <- col_vector
          }
        }
      } else {
      if (input$vlnColorPalette %in% c("Set1", "Set2", "Set3",  "Paired", "Dark2", "Accent","Spectral")){
      col_vector <- brewer.pal(min(20, brewer.pal.info[input$vlnColorPalette, "maxcolors"]), input$vlnColorPalette)
      } else {
      col_vector <- get(input$vlnColorPalette)
      }

      if (length(col_vector) < color_length) {
          cols <- colorRampPalette(col_vector)(color_length )
      } else {
          cols <- col_vector
      }
      }



# geom_jitterでsize 0でもpointが見える 0のときはalphaを0にする
# Force point size to 0 if show data point is unchecked
effective_point_size <- if (input$vlnShowDataPoint) as.numeric(input$findMarkersViolinPtSize) else 0

if (effective_point_size == 0) { pointalpha = 0}
  else {pointalpha =as.numeric(input$vlnDotOpacity) }
SplitBy  <- NULL
          if ( (input$vlnSplitByFlag ) && ( input$vlnGroupBy != input$vlnSplitBy ) ) {
            SplitBy  <- input$vlnSplitBy  } # Boolは&&

            # split.by がある場合、cols は split レベル数に合わせる
            if (!is.null(SplitBy)) {
              split_levels <- length(unique(meta[, SplitBy]))
              if (length(col_vector) < split_levels) {
                cols <- colorRampPalette(col_vector)(split_levels)
              } else {
                cols <- col_vector[1:split_levels]
              }
            }

            print('split.by')
            print(SplitBy)

            ftsize1 <- 12 * as.numeric(input$vlnFontScale)
            ftsize2 <- 8 * as.numeric(input$vlnFontScale)


if (input$vlnClean) {
            plot <- VlnPlot(seurat_object, features = geneS, pt.size = 0, slot=input$vlnSlot,
                            cols = cols, group.by = input$vlnGroupBy, split.by=SplitBy,  add.noise = input$addnoise) &
                  geom_jitter(size=effective_point_size, alpha= pointalpha, width = as.numeric(input$vlnJitterWidth)) &
              theme_classic() &
              theme(axis.text.y = element_text(face = "plain", color = "black", size = ftsize1, angle = 0),
                    panel.grid.major.x = element_blank() , panel.grid.major.y = element_blank()  ,
                    panel.grid.minor.x = element_blank() , panel.grid.minor.y = element_blank()  ,
                    axis.title.x=element_blank(), axis.ticks.x=element_blank(),
                    axis.text.x=element_blank(),legend.position = "none", axis.title.y=element_blank(),
               , plot.title=element_blank() )

} else {

if (!is.null(SplitBy)){ # jitterはsplitすると中央に表示されるため、splitの場合はSeuratを使う
            plot <- VlnPlot(seurat_object, features = geneS, pt.size = effective_point_size,slot=input$vlnSlot,
                            cols = cols, group.by = input$vlnGroupBy, split.by=SplitBy,  add.noise = input$addnoise) &
              theme_classic() &
              theme(axis.text.x = element_text(face = "plain", color = "black", size = ftsize1, angle = 0),
                    axis.text.y = element_text(face = "plain", color = "black", size = ftsize1, angle = 0),
                    axis.title.y = element_text(face = "plain", color = "black", size = ftsize1),
                    axis.title.x = element_text(face = "plain", color = "black", size = ftsize1),
                    title = element_text(face = "bold.italic", color = "black", size = ftsize1*1.2),
                    panel.grid.major.x = element_blank() , panel.grid.major.y = element_blank()  ,
                    panel.grid.minor.x = element_blank() , panel.grid.minor.y = element_blank()  ,
                    plot.title = element_text(hjust = 0.5)   )  &
                    theme(legend.position = "right")

} else {
              plot <- VlnPlot(seurat_object, features = geneS, pt.size = 0,slot=input$vlnSlot,
                            cols = cols, group.by = input$vlnGroupBy, split.by=SplitBy,  add.noise = input$addnoise) &
                geom_jitter(size=effective_point_size, alpha= pointalpha, width = as.numeric(input$vlnJitterWidth)) &
              theme_classic() &
              theme(axis.text.x = element_text(face = "plain", color = "black", size = ftsize1, angle = 0),
                    axis.text.y = element_text(face = "plain", color = "black", size = ftsize1, angle = 0),
                    axis.title.y = element_text(face = "plain", color = "black", size = ftsize1),
                    axis.title.x = element_text(face = "plain", color = "black", size = ftsize1),
                    title = element_text(face = "bold.italic", color = "black", size = ftsize1*1.2),
                    panel.grid.major.x = element_blank() , panel.grid.major.y = element_blank()  ,
                    panel.grid.minor.x = element_blank() , panel.grid.minor.y = element_blank()  ,
                    plot.title = element_text(hjust = 0.5)   )  &
                    theme(legend.position = "none")
}


}

            # Add statistical test if requested - recreate plots manually
            if (input$vlnAddStatTest) {
              # Determine which groups to compare based on split.by
              if (!is.null(SplitBy)) {
                # If split.by is used, compare between split groups within each group.by category
                compare_groups <- unique(seurat_object@meta.data[[SplitBy]])
              } else {
                # If no split.by, compare between group.by groups
                compare_groups <- unique(seurat_object@meta.data[[input$vlnGroupBy]])
              }
              
              # Check if ZIQRank is selected and validate group number
              if (input$vlnStatMethod == "ziqrank") {
                if (length(compare_groups) != 2) {
                  showNotification(paste("ZIQRank is only applicable for 2-group comparisons. Current number of groups:", length(compare_groups), 
                                       ". Please use Wilcoxon/Kruskal-Wallis method or select only 2 groups."), 
                                 type = 'error', duration = 10)
                  return()
                }
                
                # Load ZIQRank functions from external file
                tryCatch({
                  source("Rfunc/ZIQRank.R")
                }, error = function(e) {
                  showNotification(paste("Failed to load ZIQRank functions:", e$message), type = 'error', duration = 10)
                  return()
                })
              }
              
              # Create all pairwise comparisons
              if (length(compare_groups) >= 2) {
                comparisons <- combn(as.character(compare_groups), 2, simplify = FALSE)
                
                # Use only the first gene for statistical comparison
                gene <- geneS[1]
                
                if (!is.null(SplitBy)) {
                  # With split.by
                  plot_data <- FetchData(seurat_object, vars = c(gene, input$vlnGroupBy, SplitBy), layer = input$vlnSlot)
                  colnames(plot_data)[1] <- "expression"
                    
                    # Add noise to expression values if requested (similar to Seurat's add.noise)
                    if (input$addnoise) {
                      noise_factor <- max(plot_data$expression) * 0.01  # 1% of max expression
                      plot_data$expression <- plot_data$expression + rnorm(nrow(plot_data), mean = 0, sd = noise_factor)
                    }
                    
                    # Create a combined grouping variable for positioning
                    plot_data$group_split <- interaction(plot_data[[input$vlnGroupBy]], plot_data[[SplitBy]], sep = "_")
                    
                    # Create proper ordering: group by categories first, then split within each group
                    group_categories <- sort(unique(plot_data[[input$vlnGroupBy]]))
                    split_categories <- sort(unique(plot_data[[SplitBy]]))
                    
                    # Create ordered levels
                    ordered_levels <- c()
                    for (group_cat in group_categories) {
                      for (split_cat in split_categories) {
                        ordered_levels <- c(ordered_levels, paste(group_cat, split_cat, sep = "_"))
                      }
                    }
                    
                    # Set factor levels to control ordering
                    plot_data$group_split <- factor(plot_data$group_split, levels = ordered_levels)
                    
                    # Create comparisons for each group.by category
                    my_comparisons <- list()
                    for (group_cat in group_categories) {
                      for (comp in comparisons) {
                        my_comparisons <- append(my_comparisons, list(paste(group_cat, comp, sep = "_")))
                      }
                    }
                    
                    # Statistical test processing based on method
                    if (input$vlnStatMethod == "ziqrank") {
                      # ZIQRank implementation for split.by case
                      print("Using ZIQRank test for split.by case")
                      
                      # ZIQRank pairwise comparisons (same structure as Wilcoxon)
                      all_pvals <- c()
                      
                      for (group_cat in group_categories) {
                        for (comp in comparisons) {
                          # Get data for this specific comparison within group.by category
                          group_data <- plot_data[plot_data[[input$vlnGroupBy]] == group_cat, ]
                          
                          # Filter for the two split groups being compared
                          comp_data <- group_data[group_data[[SplitBy]] %in% comp, ]
                          
                          if (nrow(comp_data) > 10) { # Minimum sample size requirement
                            # Prepare data for ZIQRank
                            ziq_data <- data.frame(
                              expression = comp_data$expression,
                              condition = factor(comp_data[[SplitBy]], levels = comp)
                            )
                            
                            # Run ZIQRank for this specific pairwise comparison
                            tryCatch({
                              ziq_result <- ZIQRank(
                                formula.logistic = expression ~ condition,
                                formula.quantile = expression ~ condition,
                                C = "condition",
                                y_CorD = "C",
                                data = ziq_data,
                                taus = c(0.1, 0.25, 0.5, 0.75, 0.9)
                              )
                              
                              # Combine p-values using Cauchy method (default for ZIQRank)
                              final_pval <- Combination(ziq_result, method = "Cauchy")
                              all_pvals <- c(all_pvals, final_pval)
                              
                              print(paste("ZIQRank p-value for", group_cat, comp[1], "vs", comp[2], ":", final_pval))
                              
                            }, error = function(e) {
                              print(paste("ZIQRank failed for group", group_cat, comp[1], "vs", comp[2], ":", e$message))
                              all_pvals <<- c(all_pvals, 1)  # Assign non-significant p-value on error
                            })
                          } else {
                            all_pvals <- c(all_pvals, 1)  # Not enough data
                            print(paste("Not enough data for", group_cat, comp[1], "vs", comp[2]))
                          }
                        }
                      }
                      
                      # Apply FDR correction if requested
                      if (input$vlnUseFDR) {
                        final_pvals <- p.adjust(all_pvals, method = "fdr")
                        print("FDR-adjusted p-values (ZIQRank):")
                        print(final_pvals)
                      } else {
                        final_pvals <- all_pvals
                        print("Raw p-values (ZIQRank):")
                        print(final_pvals)
                      }
                      
                    } else {
                      # Wilcoxon/Kruskal-Wallis implementation for split.by case
                      # Choose test based on number of split groups
                      if (length(split_categories) == 2) {
                        # Two split groups: use Wilcoxon test for each group.by category
                        print("Using Wilcoxon test for 2 split groups")
                        
                        pvals <- c()
                        for (comp in my_comparisons) {
                          group1_data <- plot_data$expression[as.character(plot_data$group_split) == comp[1]]
                          group2_data <- plot_data$expression[as.character(plot_data$group_split) == comp[2]]
                          
                          print(paste("Comparing", comp[1], "vs", comp[2]))
                          print(paste("Group 1 size:", length(group1_data)))
                          print(paste("Group 2 size:", length(group2_data)))
                          
                          if (length(group1_data) > 0 && length(group2_data) > 0) {
                            pval <- wilcox.test(group1_data, group2_data)$p.value
                          } else {
                            pval <- 1  # No data, set p-value to 1
                          }
                          pvals <- c(pvals, pval)
                        }
                        
                        print("Original p-values:")
                        print(pvals)
                        
                        # Apply FDR correction if requested
                        if (input$vlnUseFDR) {
                          final_pvals <- p.adjust(pvals, method = "fdr")
                          print("FDR-adjusted p-values:")
                          print(final_pvals)
                      } else {
                        final_pvals <- pvals
                        print("Using raw p-values (no FDR correction)")
                      }
                    } else {
                      # Three or more split groups: use Kruskal-Wallis for each group.by category
                      print(paste("Using Kruskal-Wallis test for", length(split_categories), "split groups"))
                      
                      pvals <- c()
                      # Process each group.by category separately
                      for (group_cat in group_categories) {
                        # Get data for this group.by category
                        group_data <- plot_data[plot_data[[input$vlnGroupBy]] == group_cat, ]
                        
                        if (nrow(group_data) > 0) {
                          # Perform Kruskal-Wallis test for this group
                          kw_test <- kruskal.test(expression ~ get(SplitBy), data = group_data)
                          print(paste("Kruskal-Wallis p-value for", group_cat, ":", kw_test$p.value))
                          
                          # Perform pairwise Wilcoxon tests
                          pw_test <- pairwise.wilcox.test(group_data$expression, 
                                                          group_data[[SplitBy]], 
                                                          p.adjust.method = "none")
                          
                          # Extract p-values for this group's comparisons
                          for (comp in comparisons) {
                            comp_full <- paste(group_cat, comp, sep = "_")
                            if (comp_full[1] %in% my_comparisons[[which(sapply(my_comparisons, function(x) comp_full[1] %in% x))]]) {
                              # Extract p-value from pairwise test
                              row_idx <- comp[2]
                              col_idx <- comp[1]
                              if (row_idx %in% rownames(pw_test$p.value) && col_idx %in% colnames(pw_test$p.value)) {
                                pval <- pw_test$p.value[row_idx, col_idx]
                              } else if (col_idx %in% rownames(pw_test$p.value) && row_idx %in% colnames(pw_test$p.value)) {
                                pval <- pw_test$p.value[col_idx, row_idx]
                              } else {
                                pval <- 1
                              }
                              pvals <- c(pvals, pval)
                            }
                          }
                        }
                      }
                      
                      print("Original p-values from pairwise.wilcox.test:")
                      print(pvals)
                      
                      # Apply FDR correction if requested
                      if (input$vlnUseFDR) {
                        final_pvals <- p.adjust(pvals, method = "fdr")
                        print("FDR-adjusted p-values:")
                        print(final_pvals)
                      } else {
                        final_pvals <- pvals
                        print("Using raw p-values (no FDR correction)")
                      }
                      }
                    }
                    
                    # Calculate appropriate y positions for each comparison (common for both methods)
                    # Get the maximum expression value for each group.by category
                    max_y_by_group <- aggregate(plot_data$expression, 
                                              by = list(plot_data[[input$vlnGroupBy]]), 
                                              FUN = max)
                    names(max_y_by_group) <- c("group_cat", "max_y")
                    
                    print("Max Y by group:")
                    print(max_y_by_group)
                    print("Comparisons:")
                    print(my_comparisons)
                    
                    # Create y.position vector for each comparison
                    y_positions <- c()
                    for (i in seq_along(my_comparisons)) {
                      # Extract group category from the comparison
                      comp_pair <- my_comparisons[[i]]
                      group_cat <- gsub("_[^_]*$", "", comp_pair[1])  # Remove last _XX part
                      print(paste("Comparison", i, ": group_cat =", group_cat))
                      
                      group_max_y <- max_y_by_group$max_y[max_y_by_group$group_cat == group_cat]
                      if (length(group_max_y) == 0) {
                        # Fallback to overall max if group not found
                        group_max_y <- max(plot_data$expression)
                      }
                      print(paste("Group max_y:", group_max_y))
                      y_positions <- c(y_positions, group_max_y * 1.1)  # 10% above max
                    }
                    print("Y positions:")
                    print(y_positions)
                    
                    p <- ggplot(plot_data, aes(x = group_split, y = expression, fill = .data[[SplitBy]])) +
                      geom_violin(scale = "width", trim = TRUE, adjust = 1.5)
                    
                    # Create annotations
                    for (i in seq_along(my_comparisons)) {
                      x1 <- which(levels(plot_data$group_split) == my_comparisons[[i]][1])
                      x2 <- which(levels(plot_data$group_split) == my_comparisons[[i]][2])
                      y_pos <- y_positions[i]
                      
                      # Format p-values based on label choice
                      if (input$vlnPvalueLabel == "p.signif") {
                        label_text <- ifelse(final_pvals[i] <= 0.0001, "****",
                                           ifelse(final_pvals[i] <= 0.001, "***",
                                                 ifelse(final_pvals[i] <= 0.01, "**",
                                                       ifelse(final_pvals[i] <= 0.05, "*", "ns"))))
                      } else {
                        label_text <- format.pval(final_pvals[i], digits = 3)
                      }
                      
                      # Skip if hiding non-significant
                      if (input$vlnHideNS && final_pvals[i] > 0.05) next
                      
                      p <- p + 
                        annotate("segment", x = x1, xend = x2, y = y_pos, yend = y_pos, size = 0.3) +
                        annotate("segment", x = x1, xend = x1, y = y_pos, yend = y_pos - 0.05, size = 0.3) +
                        annotate("segment", x = x2, xend = x2, y = y_pos, yend = y_pos - 0.05, size = 0.3) +
                        annotate("text", x = (x1 + x2)/2, y = y_pos + 0.05, 
                                label = label_text, 
                                size = 4 * as.numeric(input$vlnFontScale))
                    }
                    
                    p <- p +
                      scale_x_discrete(labels = function(x) {
                        # Create labels showing both group and split info
                        parts <- strsplit(x, "_")
                        group_part <- sapply(parts, function(p) paste(p[1:(length(p)-1)], collapse = "_"))
                        split_part <- sapply(parts, function(p) p[length(p)])
                        return(paste(group_part, split_part, sep = "\n"))
                      }) +
                      theme_classic() +
                      labs(title = gene, y = "Expression Level", x = "") +
                      scale_fill_manual(values = cols)
                  } else {
                    # Without split.by
                    plot_data <- FetchData(seurat_object, vars = c(gene, input$vlnGroupBy), layer = input$vlnSlot)
                    colnames(plot_data)[1] <- "expression"
                    
                    # Add noise to expression values if requested (similar to Seurat's add.noise)
                    if (input$addnoise) {
                      noise_factor <- max(plot_data$expression) * 0.01  # 1% of max expression
                      plot_data$expression <- plot_data$expression + rnorm(nrow(plot_data), mean = 0, sd = noise_factor)
                    }
                    
                    p <- ggplot(plot_data, aes(x = .data[[input$vlnGroupBy]], y = expression, fill = .data[[input$vlnGroupBy]])) +
                      geom_violin(scale = "width", trim = TRUE, adjust = 1.5)
                    
                    # Choose test based on method and number of groups
                    unique_groups <- unique(plot_data[[input$vlnGroupBy]])
                    
                    if (input$vlnStatMethod == "ziqrank") {
                      # ZIQRank implementation for no split.by case
                      if (length(unique_groups) == 2) {
                        print("Using ZIQRank test for 2 groups (no split.by)")
                        
                        # ZIQRank pairwise comparisons (same structure as Wilcoxon)
                        pvals <- c()
                        for (comp in comparisons) {
                          # Filter data for this specific pairwise comparison
                          comp_data <- plot_data[plot_data[[input$vlnGroupBy]] %in% comp, ]
                          
                          if (nrow(comp_data) > 10) { # Minimum sample size requirement
                            # Prepare data for ZIQRank
                            ziq_data <- data.frame(
                              expression = comp_data$expression,
                              condition = factor(comp_data[[input$vlnGroupBy]], levels = comp)
                            )
                            
                            # Run ZIQRank for this specific pairwise comparison
                            tryCatch({
                              ziq_result <- ZIQRank(
                                formula.logistic = expression ~ condition,
                                formula.quantile = expression ~ condition,
                                C = "condition",
                                y_CorD = "C",
                                data = ziq_data,
                                taus = c(0.1, 0.25, 0.5, 0.75, 0.9)
                              )
                              
                              # Combine p-values using Cauchy method (default for ZIQRank)
                              final_pval <- Combination(ziq_result, method = "Cauchy")
                              pvals <- c(pvals, final_pval)
                              
                              print(paste("ZIQRank p-value for", comp[1], "vs", comp[2], ":", final_pval))
                              
                            }, error = function(e) {
                              print(paste("ZIQRank failed for", comp[1], "vs", comp[2], ":", e$message))
                              pvals <<- c(pvals, 1)  # Assign non-significant p-value on error
                            })
                          } else {
                            pvals <- c(pvals, 1)  # Not enough data
                            print(paste("Not enough data for", comp[1], "vs", comp[2]))
                          }
                        }
                        
                        # Apply FDR correction if requested
                        if (input$vlnUseFDR) {
                          final_pvals <- p.adjust(pvals, method = "fdr")
                          print("FDR-adjusted p-values (ZIQRank):")
                          print(final_pvals)
                        } else {
                          final_pvals <- pvals
                          print("Raw p-values (ZIQRank):")
                          print(final_pvals)
                        }
                        
                      } else {
                        showNotification(paste("ZIQRank is only applicable for 2-group comparisons. Current number of groups:", length(unique_groups), 
                                             ". Please use Wilcoxon/Kruskal-Wallis method."), 
                                       type = 'error', duration = 10)
                        return()
                      }
                    } else {
                      # Wilcoxon/Kruskal-Wallis implementation
                      if (length(unique_groups) == 2) {
                        # Two groups: use Wilcoxon test
                        print("Using Wilcoxon test for 2 groups")
                        
                        pvals <- c()
                        for (comp in comparisons) {
                          group1_data <- plot_data$expression[plot_data[[input$vlnGroupBy]] == comp[1]]
                          group2_data <- plot_data$expression[plot_data[[input$vlnGroupBy]] == comp[2]]
                          
                          print(paste("Comparing", comp[1], "vs", comp[2]))
                          print(paste("Group 1 size:", length(group1_data)))
                          print(paste("Group 2 size:", length(group2_data)))
                          
                          if (length(group1_data) > 0 && length(group2_data) > 0) {
                            pval <- wilcox.test(group1_data, group2_data)$p.value
                          } else {
                            pval <- 1  # No data, set p-value to 1
                          }
                          pvals <- c(pvals, pval)
                        }
                        
                        print("Original p-values:")
                        print(pvals)
                        
                        # Apply FDR correction if requested
                        if (input$vlnUseFDR) {
                          final_pvals <- p.adjust(pvals, method = "fdr")
                          print("FDR-adjusted p-values:")
                          print(final_pvals)
                        } else {
                          final_pvals <- pvals
                          print("Using raw p-values (no FDR correction)")
                        }
                      } else {
                        # Three or more groups: use Kruskal-Wallis then pairwise Wilcoxon
                        print(paste("Using Kruskal-Wallis test for", length(unique_groups), "groups"))
                        
                        # First perform Kruskal-Wallis test
                        kw_test <- kruskal.test(expression ~ get(input$vlnGroupBy), data = plot_data)
                        print(paste("Kruskal-Wallis p-value:", kw_test$p.value))
                        
                        # Perform pairwise Wilcoxon tests
                        pw_test <- pairwise.wilcox.test(plot_data$expression, 
                                                        plot_data[[input$vlnGroupBy]], 
                                                        p.adjust.method = "none")
                        
                        # Extract p-values in the same order as comparisons
                        pvals <- c()
                        for (comp in comparisons) {
                          # pairwise.wilcox.test returns a matrix with specific ordering
                          row_idx <- comp[2]
                          col_idx <- comp[1]
                          if (row_idx %in% rownames(pw_test$p.value) && col_idx %in% colnames(pw_test$p.value)) {
                            pval <- pw_test$p.value[row_idx, col_idx]
                          } else if (col_idx %in% rownames(pw_test$p.value) && row_idx %in% colnames(pw_test$p.value)) {
                            pval <- pw_test$p.value[col_idx, row_idx]
                          } else {
                            pval <- 1
                          }
                          pvals <- c(pvals, pval)
                        }
                        
                        print("Original p-values from pairwise.wilcox.test:")
                        print(pvals)
                        
                        # Apply FDR correction if requested
                        if (input$vlnUseFDR) {
                          final_pvals <- p.adjust(pvals, method = "fdr")
                          print("FDR-adjusted p-values:")
                          print(final_pvals)
                        } else {
                          final_pvals <- pvals
                          print("Using raw p-values (no FDR correction)")
                        }
                      }
                    }
                    
                    # Create annotations manually
                    for (i in seq_along(comparisons)) {
                      x1 <- which(levels(factor(plot_data[[input$vlnGroupBy]])) == comparisons[[i]][1])
                      x2 <- which(levels(factor(plot_data[[input$vlnGroupBy]])) == comparisons[[i]][2])
                      y_max <- max(plot_data$expression) * 1.1 + (i-1) * 0.2
                      
                      # Format p-value based on label choice
                      if (input$vlnPvalueLabel == "p.signif") {
                        label_text <- ifelse(final_pvals[i] <= 0.0001, "****",
                                            ifelse(final_pvals[i] <= 0.001, "***",
                                                  ifelse(final_pvals[i] <= 0.01, "**",
                                                        ifelse(final_pvals[i] <= 0.05, "*", "ns"))))
                      } else {
                        label_text <- format.pval(final_pvals[i], digits = 3)
                      }
                      
                      # Skip if hiding non-significant
                      if (input$vlnHideNS && final_pvals[i] > 0.05) next
                      
                      p <- p + 
                        annotate("segment", x = x1, xend = x2, y = y_max, yend = y_max, size = 0.3) +
                        annotate("segment", x = x1, xend = x1, y = y_max, yend = y_max - 0.05, size = 0.3) +
                        annotate("segment", x = x2, xend = x2, y = y_max, yend = y_max - 0.05, size = 0.3) +
                        annotate("text", x = (x1 + x2)/2, y = y_max + 0.05, 
                                label = label_text, 
                                size = 4 * as.numeric(input$vlnFontScale))
                    }
                    
                    p <- p +
                      theme_classic() +
                      labs(title = gene, y = "Expression Level", x = input$vlnGroupBy) +
                      scale_fill_manual(values = cols)
                  }
                  
                  # Apply the same theme as the original plot
                  if (input$vlnClean) {
                    p <- p + 
                      theme(axis.text.y = element_text(face = "plain", color = "black", size = ftsize1, angle = 0),
                            panel.grid.major = element_blank(), panel.grid.minor = element_blank(),
                            axis.title.x = element_blank(), axis.ticks.x = element_blank(),
                            axis.text.x = element_blank(), legend.position = "none", 
                            axis.title.y = element_blank(), plot.title = element_blank())
                  } else {
                    p <- p + 
                      theme(axis.text.x = element_text(face = "plain", color = "black", size = ftsize1, angle = 0),
                            axis.text.y = element_text(face = "plain", color = "black", size = ftsize1, angle = 0),
                            axis.title.y = element_text(face = "plain", color = "black", size = ftsize1),
                            axis.title.x = element_text(face = "plain", color = "black", size = ftsize1),
                            title = element_text(face = "bold.italic", color = "black", size = ftsize1*1.2),
                            panel.grid.major = element_blank(), panel.grid.minor = element_blank(),
                            plot.title = element_text(hjust = 0.5),
                            legend.position = ifelse(is.null(SplitBy), "none", "right"))
                  }
                  
                # Add points if requested (always add jitter layer when points are shown)
                # Force point size to 0 if show data point is unchecked
                effective_point_size <- if (input$vlnShowDataPoint) as.numeric(input$findMarkersViolinPtSize) else 0
                
                if (effective_point_size > 0) {
                  p <- p + 
                    geom_jitter(width = as.numeric(input$vlnJitterWidth),
                              size = effective_point_size, 
                              alpha = pointalpha)
                }
                
                # Set the final plot
                plot <- p
              }
            }

                  #    output$findMarkersViolinPlot <- renderPlotly(ggplot(plot, height=as.numeric(input$vlnHeight), width=as.numeric(input$vlnWidth)))

                  output$findMarkersViolinPlot <- renderPlot(plot, height=as.numeric(input$vlnHeight), width=as.numeric(input$vlnWidth))

                  global_vln <<- plot # global plotへコピー

                  # Compute and store summary statistics for the table
                  if (input$vlnAddStatTest) {
                    gene <- geneS[1]
                    if (!is.null(SplitBy)) {
                      summary_data <- FetchData(seurat_object, vars = c(gene, input$vlnGroupBy, SplitBy), layer = input$vlnSlot)
                      colnames(summary_data)[1] <- "expression"
                      # Calculate summary by group and split
                      summary_stats <- summary_data %>%
                        dplyr::group_by(.data[[input$vlnGroupBy]], .data[[SplitBy]]) %>%
                        dplyr::summarise(
                          n = dplyr::n(),
                          Mean = mean(expression, na.rm = TRUE),
                          SD = sd(expression, na.rm = TRUE),
                          Median = median(expression, na.rm = TRUE),
                          Min = min(expression, na.rm = TRUE),
                          Max = max(expression, na.rm = TRUE),
                          Q1 = quantile(expression, 0.25, na.rm = TRUE),
                          Q3 = quantile(expression, 0.75, na.rm = TRUE),
                          `Non-zero %` = round(sum(expression > 0) / dplyr::n() * 100, 1),
                          .groups = 'drop'
                        )
                    } else {
                      summary_data <- FetchData(seurat_object, vars = c(gene, input$vlnGroupBy), layer = input$vlnSlot)
                      colnames(summary_data)[1] <- "expression"
                      # Calculate summary by group
                      summary_stats <- summary_data %>%
                        dplyr::group_by(.data[[input$vlnGroupBy]]) %>%
                        dplyr::summarise(
                          n = dplyr::n(),
                          Mean = mean(expression, na.rm = TRUE),
                          SD = sd(expression, na.rm = TRUE),
                          Median = median(expression, na.rm = TRUE),
                          Min = min(expression, na.rm = TRUE),
                          Max = max(expression, na.rm = TRUE),
                          Q1 = quantile(expression, 0.25, na.rm = TRUE),
                          Q3 = quantile(expression, 0.75, na.rm = TRUE),
                          `Non-zero %` = round(sum(expression > 0) / dplyr::n() * 100, 1),
                          .groups = 'drop'
                        )
                    }
                    # Round numeric columns
                    summary_stats <- summary_stats %>%
                      dplyr::mutate(dplyr::across(where(is.numeric) & !dplyr::matches("^n$|Non-zero"), ~round(., 4)))

                    # Store for download and render table directly (same pattern as clusterTable)
                    export_vlnSummary <<- summary_stats
                    export_vlnGene <<- gene

                    output$vlnSummaryTable <- DT::renderDataTable({
                      DT::datatable(
                        summary_stats,
                        caption = paste("Summary statistics for:", gene),
                        options = list(
                          pageLength = 25,
                          scrollX = TRUE,
                          dom = 'Bfrtip'
                        ),
                        rownames = FALSE
                      ) %>%
                        DT::formatRound(columns = c("Mean", "SD", "Median", "Min", "Max", "Q1", "Q3"), digits = 4)
                    })
                  }

}}
  }, error = function(e) {
    print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
    session$sendCustomMessage("handler_alert", "There was a problem with the generation of the plot.")
  }, finally = {
    removeModal()
    session$sendCustomMessage("handler_startLoader", c("DEA6_loader", 100))
    Sys.sleep(1)
    session$sendCustomMessage("handler_finishLoader", "DEA6_loader")
    session$sendCustomMessage("handler_enableAllButtons", "findMarkersViolinConfirm")
  })
})


