output$umapdownloaderPNG <- downloadHandler(
  filename = "DimPlot.png",
  content =  function(file) {
    if (is.null(global_umap)) {
      showNotification("No UMAP plot available. Please draw the plot first.", type = "error")
      return(NULL)
    }
    tryCatch({
      # Get dimensions with fallback defaults
      h <- if (!is.null(input$umapHeight) && input$umapHeight > 0) input$umapHeight/72 else 8
      w <- if (!is.null(input$umapWidth) && input$umapWidth > 0) input$umapWidth/72 else 10
      ggsave(file, plot = global_umap, dpi = 300, height = h, width = w)
    }, error = function(e) {
      print(paste("Error saving PNG:", e$message))
      showNotification(paste("Error saving plot:", e$message), type = "error")
    })
  }
)

