# NEBULA分析実行関数の修正版
run_NEBULA <- function(seurat_object, ident.1, ident.2, subject.var, latent.vars = NULL, 
                      method = "HL", model = "NBGMM", reml = 0, 
                      logfc.threshold = 0.25, n_cores = 1) {
  require(nebula)
  require(Matrix)
  
  # 現在のIdentsを保存
  current_idents <- Seurat::Idents(seurat_object)
  
  # 解析対象の細胞をサブセット
  cells.1 <- WhichCells(seurat_object, idents = ident.1)
  cells.2 <- WhichCells(seurat_object, idents = ident.2)
  cells_to_include <- c(cells.1, cells.2)
  
  # サブセットが空でないか確認
  if (length(cells_to_include) == 0) {
    stop("指定されたidentではセルが見つかりません")
  }
  
  seurat_subset <- subset(seurat_object, cells = cells_to_include)
  
  # カウントマトリックスを取得
  counts <- GetAssayData(seurat_subset, layer = "counts")
  

# 各遺伝子について、counts > 0 の割合を計算
expr_frac <- rowMeans(counts > 0)  

# 閾値以上の遺伝子だけをフィルタ
keep_genes <- expr_frac >= input$NEBULAMinPctDEG 

# フィルタ後の counts 行列と遺伝子名
counts <- counts[keep_genes, , drop = FALSE]

  # メタデータを取得
  meta_data <- seurat_subset@meta.data
  
  # 被験者IDの取得
  subject_ids <- meta_data[[subject.var]]
  
  # グループ情報作成（対照群vs処理群）
  meta_data$group <- ifelse(Idents(seurat_subset) %in% ident.1, "Group1", "Group2")
  meta_data$group <- as.factor(meta_data$group)
  
  # デザインマトリックスの作成
  pred_vars <- c("group")
  if (!is.null(latent.vars) && length(latent.vars) > 0) {
    valid_vars <- latent.vars[latent.vars %in% colnames(meta_data)]
    if (length(valid_vars) > 0) {
      pred_vars <- c(pred_vars, valid_vars)
    }
  }
  
  design_formula <- as.formula(paste("~", paste(pred_vars, collapse = " + ")))
  design_matrix <- model.matrix(design_formula, data = meta_data)
  
  # ライブラリサイズの計算
  lib_size <- Matrix::colSums(counts)
  
  # 細胞を被験者IDでグループ化
  data_g <- group_cell(count = counts, id = subject_ids, pred = design_matrix, offset = lib_size)
  
  # group_cell関数の結果を確認
  if (is.null(data_g)) {
    message("細胞は既に被験者IDでグループ化されています")
    nebula_count <- counts
    nebula_id <- subject_ids
    nebula_pred <- design_matrix
    nebula_offset <- lib_size
  } else {
    nebula_count <- data_g$count
    nebula_id <- data_g$id
    nebula_pred <- data_g$pred
    nebula_offset <- data_g$offset
  }
  
  # NEBULAモデルフィッティング - フィルタリングパラメータ追加
  message(paste0("NEBULA-", method, "分析を実行しています..."))
  result <- nebula(
    nebula_count,
    nebula_id,
    pred = nebula_pred,
    offset = nebula_offset,
    method = method,
    model = model,
    reml = reml,
    cpc = 0.01,  # 発現の低い遺伝子をフィルタリング（必要に応じて調整）
    ncore = n_cores
  )
  
  # 結果の整形
  summary_df <- as.data.frame(result$summary)
  message("NEBULA分析完了。結果の列名:", paste(colnames(summary_df), collapse = ", "))
  
  # 収束状態のチェック
  problem_genes <- sum(result$convergence <= -20)
  if (problem_genes > 0) {
    message(paste0(problem_genes, "個の遺伝子で収束問題があります (code <= -20)"))
    # 収束問題のある遺伝子の割合を表示
    message(paste0("収束問題のある遺伝子の割合: ", 
                   round(problem_genes / length(result$convergence) * 100, 2), "%"))
  }
  
  # グループ効果（Group2）の列を特定
  group_col <- grep("groupGroup2$", colnames(summary_df), value = TRUE)
  p_col <- grep("^p_groupGroup2$", colnames(summary_df), value = TRUE)
  
  if (length(group_col) > 0 && length(p_col) > 0) {
    # p値の分布を確認
    p_vals <- summary_df[[p_col]]
    message("p値の要約統計量:")
    message(paste("最小値:", min(p_vals), "最大値:", max(p_vals)))
    message(paste("中央値:", median(p_vals), "平均値:", mean(p_vals)))
    message(paste("p < 0.05の遺伝子数:", sum(p_vals < 0.05)))
    message(paste("p = 0の遺伝子数:", sum(p_vals == 0)))

    # 極めて小さいp値の処理（0を避けるため）
    min_p_val <- 1e-300  # 非常に小さい値（非ゼロ）
    p_vals_adj <- ifelse(p_vals < min_p_val, min_p_val, p_vals)
    
    # 複数の調整方法でp値を調整
    p_adj_BH <- p.adjust(p_vals_adj, method = "BH")
  #  p_adj_bonferroni <- p.adjust(p_vals_adj, method = "bonferroni")
    
    # 調整済みp値の分布も確認
    message("BH法での調整済みp値の分布:")
    message(paste("p_adj < 0.05の遺伝子数:", sum(p_adj_BH < 0.05)))
    message(paste("p_adj = 0の遺伝子数:", sum(p_adj_BH == 0)))
        showNotification(paste("p_adj < 0.05の遺伝子数:", sum(p_adj_BH < 0.05)), duration=60)
    
  #  message("Bonferroni法での調整済みp値の分布:")
  #  message(paste("p_adj < 0.05の遺伝子数:", sum(p_adj_bonferroni < 0.05)))
  #  message(paste("p_adj = 0の遺伝子数:", sum(p_adj_bonferroni == 0)))
 

 print("before de")   
    # データフレームの作成
# Create data frame with minimal components
str(summary_df$gene)
print(group_col)
str(summary_df$p_groupGroup2 )
str(summary_df$gene)
de_result <- data.frame(
  gene = summary_df$gene,
  avg_log2FC = summary_df$logFC_groupGroup2 / log(2),  # 直接列名を指定
  p_val = summary_df$p_groupGroup2,                   # 直接列名を指定
  adj_P_BH = p_adj_BH
)

    
    # Check structure of key components
str(summary_df)
str(p_vals)
str(p_adj_BH)
  print("after de")   
 
    # LFC閾値でフィルタリング
    if (logfc.threshold > 0) {
      de_result <- de_result[abs(de_result$avg_log2FC) >= logfc.threshold, ]
      message(paste0("log2FC閾値 ", logfc.threshold, " 適用後の遺伝子数: ", nrow(de_result)))
    }
    
  print("after LFC")   
    # p値でソート（BH法を優先）
    de_result <- de_result[order(de_result$adj_P_BH), ]
    
print("after sort")  

    # 元のIdentsを復元
    Seurat::Idents(seurat_object) <- current_idents
    
    return(de_result)
  } else {
    stop(paste("グループ効果または p値 の列が見つかりません。利用可能な列:", 
               paste(colnames(summary_df), collapse = ", ")))
  }
}

# glmmTMB解析（全遺伝子対象版・並列処理版）
run_glmmTMB <- function(seurat_object, ident.1, ident.2, subject.var, latent.vars = NULL, 
                        logfc.threshold = 0.25, n_cores = 1, REML = FALSE) {

  Sys.setenv(OMP_NUM_THREADS = 16)
  # 現在のIdentsを保存
  current_idents <- Seurat::Idents(seurat_object)
  
  # 解析対象の細胞をサブセット
  cells_to_include <- unlist(CellsByIdentities(seurat_object, c(ident.1, ident.2)))
  seurat_subset <- subset(seurat_object, cells = cells_to_include)
  
  # 生データと細胞情報の取得
  counts <- as.matrix(GetAssayData(seurat_subset, layer = "counts"))
  meta_data <- seurat_subset@meta.data
  
  # 各遺伝子について、counts > 0 の割合を計算
  expr_frac <- rowMeans(counts > 0)  

  # 閾値以上の遺伝子だけをフィルタ
  keep_genes <- expr_frac >= input$NEBULAMinPctDEG 

  # フィルタ後の counts 行列と遺伝子名
  counts <- counts[keep_genes, , drop = FALSE]

  message(sprintf("Kept %d / %d genes (%.1f%%) with detection rate ≥ %.1f%%",
                  sum(keep_genes), length(keep_genes),
                  mean(keep_genes) * 100, input$NEBULAMinPctDEG))

  # グループ情報作成
  meta_data$group <- ifelse(Idents(seurat_subset) %in% ident.1, "Group1", "Group2")
  meta_data$group <- as.factor(meta_data$group)
  
  # ライブラリサイズを計算して対数変換
  lib_size <- colSums(counts)
  meta_data$offset <- log(lib_size)
  
  # 結果を格納するデータフレームを初期化
  gene_names <- rownames(counts)
  total_genes <- length(gene_names)
  message(paste("Testing all", total_genes, "genes with glmmTMB..."))
  
  # モデルの準備
  require(glmmTMB)
  require(BiocParallel)
  require(parallel)
  
  # ランダム効果部分を直接組み立て
  re_part <- paste0("(1|", subject.var, ")")
  if (is.null(latent.vars)) {
    formula_str <- paste("count ~ group + offset(offset) +", re_part)
  } else {
    formula_str <- paste(
      "count ~ group +",
      paste(latent.vars, collapse = " + "),
      "+ offset(offset) +",
      re_part
    )
  }
  
  message("Running glmmTMB analysis with formula: ", formula_str)
  formula_obj <- as.formula(formula_str)
  
  # 並列処理のコア数を設定（最低1、最大システムの物理コア数-1）
  n_cores <- max(1, min(n_cores, parallel::detectCores() - 1))
  message(paste("Using", n_cores, "cores for parallel processing"))
  
  # 遺伝子のバッチを作成（大量の遺伝子を一括で処理するとメモリ不足になる可能性があるため）
  batch_size <- ceiling(total_genes / n_cores)  # 各コアが処理する遺伝子数
  gene_batches <- split(gene_names, ceiling(seq_along(gene_names) / batch_size))
  
  # 各バッチに対する処理関数
  process_batch <- function(genes_batch) {
    library(glmmTMB)  # 各ワーカープロセスで必要なライブラリを読み込む
    
    # このバッチの結果を格納するデータフレーム
    batch_results <- data.frame(
      gene = character(length(genes_batch)),
      avg_log2FC = numeric(length(genes_batch)),
      p_val = numeric(length(genes_batch)),
      stringsAsFactors = FALSE
    )
    
    for (i in seq_along(genes_batch)) {
      gene <- genes_batch[i]
      batch_results$gene[i] <- gene
      
      # モデルデータを準備
      model_data <- meta_data
      model_data$count <- counts[gene, ]
      
      # モデルをフィット
      tryCatch({
        fit <- glmmTMB(formula_obj, 
                      data = model_data, 
                      family = nbinom2,
                      REML = REML,
                      control = glmmTMBControl(optimizer = optim, 
                                              optArgs = list(method = "BFGS")))
        
        # 結果を取得
        summary_fit <- summary(fit)
        coefs <- summary_fit$coefficients$cond
        
        # グループ効果を取得
        if ("groupGroup2" %in% rownames(coefs)) {
          group_effect <- coefs["groupGroup2", "Estimate"]
          group_pvalue <- coefs["groupGroup2", "Pr(>|z|)"]
        } else {
          # 異なる参照レベルの場合のフォールバック
          group_cols <- grep("^group", rownames(coefs), value = TRUE)
          if (length(group_cols) > 0) {
            group_effect <- coefs[group_cols[1], "Estimate"]
            group_pvalue <- coefs[group_cols[1], "Pr(>|z|)"]
          } else {
            group_effect <- NA
            group_pvalue <- NA
          }
        }
        
        # 結果を格納
        batch_results$avg_log2FC[i] <- group_effect / log(2)
        batch_results$p_val[i] <- group_pvalue
        
      }, error = function(e) {
        # エラー時には結果をNAに
        batch_results$avg_log2FC[i] <- NA
        batch_results$p_val[i] <- NA
      })
    }
    
    return(batch_results)
  }
  
  # 並列処理の実行
  if (n_cores > 1) {
    cl <- makeCluster(n_cores)
    # クラスターに必要な変数を転送
    clusterExport(cl, c("counts", "meta_data", "formula_obj", "REML"), envir = environment())
    # 各バッチの処理を実行
    message("Starting parallel processing of ", length(gene_batches), " batches...")
    batch_results_list <- parLapply(cl, gene_batches, process_batch)
    stopCluster(cl)
  } else {
    # シングルコアの場合
    message("Running in single-core mode...")
    batch_results_list <- lapply(gene_batches, process_batch)
  }
  
  # バッチ結果を結合
  all_results <- do.call(rbind, batch_results_list)
  rownames(all_results) <- all_results$gene
  all_results$gene <- NULL
  
  # p値調整
  message("Adjusting p-values...")
  all_results$p_val_adj <- p.adjust(all_results$p_val, method = "BH")
  
  # NAを含む行を削除
  valid_rows <- !is.na(all_results$p_val)
  all_results <- all_results[valid_rows, ]
  message(paste("Removed", sum(!valid_rows), "genes with NA p-values due to errors or convergence issues"))
  
  # LFC閾値でフィルタリング
  if (logfc.threshold > 0) {
    filtered_rows <- abs(all_results$avg_log2FC) >= logfc.threshold
    all_results <- all_results[filtered_rows, ]
    message(paste("Filtered", sum(!filtered_rows), "genes with |log2FC| <", logfc.threshold))
  }
  
  # 結果をp値でソート
  all_results <- all_results[order(all_results$p_val_adj), ]
  
  # 元のIdentsを復元
  Seurat::Idents(seurat_object) <- current_idents
  
  message("glmmTMB analysis completed")

  # 行名をGene列として追加
  result_df <- cbind(rownames(all_results), all_results)
  colnames(result_df)[1] <- 'Gene'
  print(head(result_df))
  
  return(result_df)
}


