          top50 <- DEG_data %>% top_n(n=input$heatmapNum, wt=abs(avg_log2FC)) %>% arrange(-avg_log2FC)
        }

        if (length(seurat_object[[seurat_object@active.assay]]$scale.data) == 0) {
          showNotification("Needs SCALING.", type='error')
        }
        downsampled <- seurat_object
        if(ncol(seurat_object) > input$downNum)
        {
          set.seed(9)
          if (input$downNum < dim(seurat_object@meta.data)[1]){
            downsampled <- subset(seurat_object, cells = sample(Cells(seurat_object), input$downNum))
            } else {
              downsampled <- seurat_object #細胞数が少ないときはそのまま使う
              showNotification("Because the cell number is smaller than the subset number, all cellls are used", duration=30)
