#------------------Doublet detection------------------------------------------
observeEvent(input$doubletsConfirm, {
  session$sendCustomMessage("handler_startLoader", c("doubletRNA_loader1", 10))
  session$sendCustomMessage("handler_disableAllButtons", "doubletsConfirm")
  tryCatch({
    if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
    else
    {
      library(DoubletFinder)
      showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%
      homotypic.prop.seurat_object <- modelHomotypic(seurat_object@meta.data$seurat_clusters)
      nExp_poi.seurat_object <- round( as.numeric(input$doubletsNExp) * nrow(seurat_object@meta.data) )  ## Assuming x% doublet formation rate
      nExp_poi.adj.seurat_object <- round(nExp_poi.seurat_object * (1-homotypic.prop.seurat_object) )
      pK_choose <- 0.09
      session$sendCustomMessage("handler_startLoader", c("doubletRNA_loader1", 30))
      if(input$doubletsPKRadio == "auto")
      {
        #auto pK estimation
   #    sweep.res.list_seurat_object <- paramSweep_v3(seurat_object, PCs = 1:as.numeric(input$doubletsPCs), sct = FALSE)
        sweep.res.list_seurat_object <- paramSweep(seurat_object, PCs = 1:as.numeric(input$doubletsPCs), sct = FALSE)
        sweep.stats_seurat_object <- summarizeSweep(sweep.res.list_seurat_object, GT = FALSE)
        bcmvn_seurat_object <- find.pK(sweep.stats_seurat_object)
        pK=as.numeric(as.character(bcmvn_seurat_object$pK))
        BCmetric=bcmvn_seurat_object$BCmetric
        pK_choose = pK[which(BCmetric %in% max(BCmetric))]
      }
      else
      {
        pK_choose <- input$doubletsPK
      }
      library(DoubletFinder)
      session$sendCustomMessage("handler_startLoader", c("doubletRNA_loader1", 60)) # -> doubletFinder
      seurat_object <<- doubletFinder(seurat_object, PCs = 1:as.numeric(input$doubletsPCs), pN = as.numeric(input$doubletsPN), pK = as.numeric(pK_choose), nExp = nExp_poi.seurat_object, sct = FALSE)
      seurat_object <<- doubletFinder(seurat_object, PCs = 1:as.numeric(input$doubletsPCs), pN = as.numeric(input$doubletsPN), pK = as.numeric(pK_choose), nExp = nExp_poi.adj.seurat_object, sct = FALSE)

      #factor the two last columns
      seurat_object@meta.data[, ncol(seurat_object@meta.data)] <<- factor(seurat_object@meta.data[, ncol(seurat_object@meta.data)])
      seurat_object@meta.data[, ncol(seurat_object@meta.data)-2] <<- factor(seurat_object@meta.data[, ncol(seurat_object@meta.data)-2])

      #output
      column_total_name <- paste0("DF.classifications_", as.numeric(input$doubletsPN), "_", pK_choose, "_", nExp_poi.seurat_object)
      column_not_homotypic_name <- paste0("DF.classifications_", as.numeric(input$doubletsPN), "_", pK_choose, "_", nExp_poi.adj.seurat_object)
      session$sendCustomMessage("handler_startLoader", c("doubletRNA_loader1", 80))
      df_total <- (table(seurat_object@meta.data[, column_total_name]))
      df_not_homotypic <- (table(seurat_object@meta.data[, column_not_homotypic_name]))
      print(head(seurat_object@meta.data))
      print(class(seurat_object@meta.data[, column_not_homotypic_name]))

      updateMetadata()
      updateSelInpColor()

      output$doubletsInfo <- renderPrint(
        {
          cat(paste0("Total number of cells: ", nrow(seurat_object@meta.data), "\nTotal number of doublets: ", df_total["Doublet"], "\nHomotypic doublets:", df_total["Doublet"]-df_not_homotypic["Doublet"],
                     "\nNon-homotypic doublets:", df_not_homotypic["Doublet"]))
        })
    }
  }, error = function(e)
  {
    print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
    session$sendCustomMessage("handler_alert", "There was an error with drawing the resutls. This requires PCA data.")
  }, finally =
    {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("doubletRNA_loader1", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "doubletRNA_loader1")
      session$sendCustomMessage("handler_enableAllButtons", "doubletsConfirm")
    }
  )
})

#------------------scDblFinder detection------------------------------------------
observeEvent(input$scDblFinderConfirm, {
  session$sendCustomMessage("handler_startLoader", c("scDblFinder_loader1", 10))
  session$sendCustomMessage("handler_disableAllButtons", "scDblFinderConfirm")
  tryCatch({
    if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
    else
    {
      library(scDblFinder)
      library(BiocParallel)

      # Set timeout option for scDblFinder (required for database connections)
      old_timeout <- getOption("timeout")
      options(timeout = max(300, old_timeout))

      showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;'))

      session$sendCustomMessage("handler_startLoader", c("scDblFinder_loader1", 20))

      # Convert Seurat object to SingleCellExperiment
      sce <- as.SingleCellExperiment(seurat_object)

      # Get selected reduction from Seurat object and add to SCE
      selected_reduction <- input$scDblFinderReduction
      print(paste("Using reduction:", selected_reduction))
      if (!is.null(seurat_object@reductions[[selected_reduction]])) {
        pca_embeddings <- Embeddings(seurat_object, reduction = selected_reduction)
        reducedDim(sce, "PCA") <- pca_embeddings
        print(paste("Successfully loaded reduction:", selected_reduction, "with dimensions", dim(pca_embeddings)))
      } else {
        warning(paste("Reduction", selected_reduction, "not found. scDblFinder will compute PCA internally."))
      }

      session$sendCustomMessage("handler_startLoader", c("scDblFinder_loader1", 30))

      # Prepare parameters for scDblFinder
      # Handle dbr (0 means NULL for auto-estimation)
      dbr_val <- as.numeric(input$scDblFinderDBR)
      if (dbr_val == 0) {
        dbr_val <- NULL
        print("Using automatic doublet rate estimation")
      } else {
        print(paste("Using manual doublet rate:", dbr_val))
      }

      # Handle dbr.sd (0 means NULL for auto, which is 40% of dbr)
      dbr_sd_val <- as.numeric(input$scDblFinderDBRsd)
      if (dbr_sd_val == 0) {
        dbr_sd_val <- NULL
        print("Using automatic dbr.sd (40% of dbr)")
      } else {
        print(paste("Using manual dbr.sd:", dbr_sd_val))
      }

      scdbf_params <- list(
        sce = sce,
        dbr = dbr_val,
        dbr.sd = dbr_sd_val,
        dims = as.numeric(input$scDblFinderNDims),
        BPPARAM = SnowParam(workers = as.numeric(input$scDblFinderNThreads), RNGseed = 1234)
      )

      # Add clusters parameter if enabled
      if (input$scDblFinderUseClusters == TRUE) {
        cluster_column <- input$scDblFinderClusterColumn
        print(paste("Using cluster information from column:", cluster_column))
        scdbf_params$clusters <- cluster_column
      }

      # Add samples parameter if multiple samples mode is enabled
      if (input$scDblFinderMultiSample == TRUE) {
        sample_column <- input$scDblFinderSampleColumn
        print(paste("Processing multiple samples using column:", sample_column))
        print(paste("Number of samples:", length(unique(seurat_object@meta.data[[sample_column]]))))
        scdbf_params$samples <- sample_column
      } else {
        print("Processing as single sample (no sample splitting)")
      }

      session$sendCustomMessage("handler_startLoader", c("scDblFinder_loader1", 40))

      # Run scDblFinder with all parameters
      sce <- do.call(scDblFinder, scdbf_params)

      # Add results back to Seurat object
      session$sendCustomMessage("handler_startLoader", c("scDblFinder_loader1", 70))
      seurat_object$scDblFinder.score <<- sce$scDblFinder.score
      seurat_object$scDblFinder.class <<- factor(sce$scDblFinder.class)

      # Update metadata
      updateMetadata()
      updateSelInpColor()

      session$sendCustomMessage("handler_startLoader", c("scDblFinder_loader1", 90))

      # Output statistics
      scDblFinder_table <- table(seurat_object$scDblFinder.class)

      # Per-sample statistics if multiple samples
      output$scDblFinderInfo <- renderPrint({
        # Show settings used
        cat("=== scDblFinder Settings ===\n")
        cat(paste0("Doublet rate (dbr): ", ifelse(input$scDblFinderDBR == 0, "Auto-estimation", input$scDblFinderDBR), "\n"))
        cat(paste0("Doublet rate SD (dbr.sd): ", ifelse(input$scDblFinderDBRsd == 0, "Auto (40% of dbr)", input$scDblFinderDBRsd), "\n"))
        cat(paste0("Dimensions: ", input$scDblFinderNDims, "\n"))
        cat(paste0("Reduction used: ", input$scDblFinderReduction, "\n"))
        if (input$scDblFinderUseClusters == TRUE) {
          cat(paste0("Cluster information: ", input$scDblFinderClusterColumn, "\n"))
        } else {
          cat("Cluster information: Not used\n")
        }
        if (input$scDblFinderMultiSample == TRUE) {
          cat(paste0("Sample splitting: ", input$scDblFinderSampleColumn, "\n"))
        } else {
          cat("Sample splitting: Single sample mode\n")
        }
        cat("\n=== Results ===\n")
        cat(paste0("Total number of cells: ", ncol(seurat_object),
                   "\nNumber of singlets: ", scDblFinder_table["singlet"],
                   "\nNumber of doublets: ", scDblFinder_table["doublet"],
                   "\nDoublet rate: ", round(scDblFinder_table["doublet"] / ncol(seurat_object) * 100, 2), "%\n"))

        # Show per-sample statistics if multiple samples mode is enabled
        if (input$scDblFinderMultiSample == TRUE) {
          sample_column <- input$scDblFinderSampleColumn
          cat(paste0("\n--- Per-sample statistics (split by ", sample_column, ") ---\n"))
          for (sample in unique(seurat_object@meta.data[[sample_column]])) {
            sample_cells <- seurat_object@meta.data[[sample_column]] == sample
            sample_table <- table(seurat_object$scDblFinder.class[sample_cells])
            cat(paste0("\n", sample, ":\n"))
            cat(paste0("  Cells: ", sum(sample_cells), "\n"))
            cat(paste0("  Singlets: ", sample_table["singlet"], "\n"))
            cat(paste0("  Doublets: ", sample_table["doublet"], "\n"))
            cat(paste0("  Doublet rate: ", round(sample_table["doublet"] / sum(sample_cells) * 100, 2), "%\n"))
          }
        }
      })
    }
  }, error = function(e)
  {
    print(paste("Error :  ", e))
    showNotification(paste("Error :  ", e), type = 'error', duration=200)
    session$sendCustomMessage("handler_alert", "There was an error with scDblFinder. Make sure the package is installed and PCA has been performed.")
  }, finally =
    {
      # Restore original timeout option
      if (exists("old_timeout") && !is.null(old_timeout)) {
        options(timeout = old_timeout)
      }
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("scDblFinder_loader1", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "scDblFinder_loader1")
      session$sendCustomMessage("handler_enableAllButtons", "scDblFinderConfirm")
    }
  )
})

#ATAC
observeEvent(input$doubletsATACConfirm, {
  session$sendCustomMessage("handler_startLoader", c("doubletATAC_loader2", 10))
  session$sendCustomMessage("handler_disableAllButtons", "doubletsATACConfirm")
  tryCatch({
    if (identical(proj_default, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
    else
    {
      showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%
      shinyjs::show("doubletATAC_loader3")
      shinyjs::show("doubletATAC_loader4")

      proj_default <<- addDoubletScores(
        input = proj_default,
        k = as.numeric(input$doubletsATACk), #Refers to how many cells near a "pseudo-doublet" to count.
        knnMethod = "umap", #Refers to the embedding to use for nearest neighbor search with doublet projection.
        LSIMethod = as.numeric(input$doubletsATACLSI)
      )
      session$sendCustomMessage("handler_startLoader", c("doubletATAC_loader2", 30))
      #plot1
      pal <- c("grey", "#FB8861FF", "#B63679FF", "#51127CFF", "#000004FF") #grey_magma
      df<-proj_default@embeddings$umap$df
      df$score<-proj_default$DoubletScore
      df$enrichment<-proj_default$DoubletEnrichment

      xlim <- range(df[,1]) %>% extendrange(f = 0.05)
      ylim <- range(df[,2]) %>% extendrange(f = 0.05)

      #Plot Doublet Score
      pscore <- ggPoint(
        x = df[,1],
        y = df[,2],
        color = ArchR:::.quantileCut(df$score, 0, 0.95),
        xlim = xlim,
        ylim = ylim,
        discrete = FALSE,
        size = 5,
        xlab = "UMAP Dimension 1",
        ylab = "UMAP Dimension 2",
        pal = pal,
        title = "Doublet Scores -log10(P-adj.)",
        colorTitle = "Doublet Scores -log10(P-adj.)",
        rastr = TRUE,
        baseSize = 20
      ) + theme(axis.text.x = element_blank(), axis.ticks.x = element_blank(),
                axis.text.y = element_blank(), axis.ticks.y = element_blank())
      session$sendCustomMessage("handler_startLoader", c("doubletATAC_loader2", 50))
      #plot2
      penrich <- ggPoint(
        x = df[,1],
        y = df[,2],
        color = ArchR:::.quantileCut(df$enrichment, 0, 0.95),
        xlim = xlim,
        ylim = ylim,
        discrete = FALSE,
        size = 5,
        xlab = "UMAP Dimension 1",
        ylab = "UMAP Dimension 2",
        pal = pal,
        title = "Simulated Doublet Enrichment over Expectation",
        colorTitle = "Doublet Enrichment",
        rastr = TRUE,
        baseSize = 20
      ) + theme(axis.text.x = element_blank(), axis.ticks.x = element_blank(),
                axis.text.y = element_blank(), axis.ticks.y = element_blank())

      session$sendCustomMessage("handler_startLoader", c("doubletATAC_loader2", 70))
      output$doubletsScoreATAC <- renderPlot( {pscore} )

      output$doubletEnrichmentATAC <- renderPlot( {penrich} )
    }
  }, error = function(e)
  {
    print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
    session$sendCustomMessage("handler_alert", "There was an error with drawing the resutls.")
  }, finally =
    {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("doubletATAC_loader2", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "doubletATAC_loader2")
      session$sendCustomMessage("handler_enableAllButtons", "doubletsATACConfirm")
    }
  )
})

#------------------Cell cycle tab---------------------------------------------
  observeEvent(input$cellCycleRun, {
    session$sendCustomMessage("handler_startLoader", c("CC1_loader", 10))
    session$sendCustomMessage("handler_startLoader", c("CC2_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "cellCycleRun")
    tryCatch({
      if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
#      else if ( (!"pca" %in% names(seurat_object)) & (!"umap" %in% names(seurat_object) )) {
#        session$sendCustomMessage("handler_alert", "Please, first execute some ruduction ANALYSIS.") }
      else {
        showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%
        shinyjs::show("cellCyclePCA_loader")
        shinyjs::show("cellCycleBarplot_loader")
        print(organism)
        if(organism == "mouse")
        {
 #         s.genes_ver2 <- readRDS("cell_cycle_phase_helper_files/S.phase.human.mouse.conversion.rds")
 #         s.genes_ver2 <- s.genes_ver2$MGI.symbol

 #         g2m.genes_ver2 <- readRDS("cell_cycle_phase_helper_files/G2M.phase.human.mouse.conversion.rds")
 #         g2m.genes_ver2 <- g2m.genes_ver2$MGI.symbol
 #         s.genes <- s.genes_ver2
 #         g2m.genes <- g2m.genes_ver2
 			s.mouse <- read.table('cell.cycle.genes/s_mouse.genes')
			g2m.mouse <- read.table('cell.cycle.genes/g2m_mouse.genes')
			s.genes <- s.mouse[['V1']]
			g2m.genes <- g2m.mouse[['V1']]


        }
        else
        {
          s.genes <- cc.genes$s.genes
          g2m.genes <- cc.genes$g2m.genes
        }

        seurat_object <<- CellCycleScoring(seurat_object, s.features = s.genes, g2m.features = g2m.genes, set.ident = F)
        seurat_object@meta.data$CC.Difference <<- seurat_object$S.Score - seurat_object$G2M.Score
        seurat_object@meta.data$Phase <<- factor(seurat_object@meta.data$Phase, levels = c("G1", "S", "G2M"))
        updateMetadata()

        output$cellCyclePCA <- renderPlotly(
          {
            if(!is.null(seurat_object) & input$cellCycleReduction != "-")
            {
              meta <- seurat_object@meta.data
              meta$Cell_id <- rownames(meta)
              label_x <- "PC_1"
              label_y <- "PC_2"
              selected_Reduction <- input$cellCycleReduction
              #
              if(str_detect(input$cellCycleReduction, pattern = "umap"))
              {
                label_x <- "UMAP_1"
                label_y <- "UMAP_2"
              }
              else if(str_detect(input$cellCycleReduction, pattern = "tsne"))
              {
                label_x <- "tSNE_1"
                label_y <- "tSNE_2"
              }
              else if(str_detect(input$cellCycleReduction, pattern = "dfm"))
              {
                label_x <- "DC_1"
                label_y <- "DC_2"
              }
              else if(str_detect(input$cellCycleReduction, pattern = "phate"))
              {
                label_x <- "PHATE_1"
                label_y <- "PHATE_2"
              }

              plot1 <- DimPlot(seurat_object, reduction = selected_Reduction)
              plot1_data <- plot1$data
              plot1_data$Cell_id <- rownames(plot1_data)
              plot1_data <- left_join(plot1_data, meta)

              p <- ggplot(plot1_data, aes_string(x=label_x, y=label_y, color="Phase"))+
                geom_point() +
                theme_bw() +
                labs(x=label_x, y=label_y)+
                theme(legend.position = "right", panel.grid.minor.x = element_blank() , panel.grid.minor.y = element_blank()  ,
                 panel.grid.major.x = element_blank() , panel.grid.major.y = element_blank()  )

              gp <- plotly::ggplotly(p, tooltip = c("x", "y"))
              print(gp)
            }
          }
        )
        session$sendCustomMessage("handler_startLoader", c("CC1_loader", 80))

        output$cellCycleBarplot <- renderPlotly(
          {
            #barplot
            fsize <- 24

            obj_meta <- seurat_object@meta.data
            obj_meta$cell_id <- row.names(obj_meta)
            obj_meta$Cluster_name <- Idents(seurat_object)
            obj_meta <- obj_meta[, c('cell_id', 'Cluster_name', 'Phase')]
            final_df_seurat <- obj_meta %>% dplyr::group_by(Cluster_name) %>% dplyr::count(Phase)
            colnames(final_df_seurat)[3] <- "Cells"

            total_cells_per_cluster <- as.data.frame(table(seurat_object$seurat_clusters)) #as.data.frame(table(Idents(seurat_object)))
            colnames(total_cells_per_cluster)[1] <- "Cluster_name"
            colnames(total_cells_per_cluster)[2] <- "Total"

            final_df_seurat <- left_join(final_df_seurat, total_cells_per_cluster)
            final_df_seurat$Percentage <- (final_df_seurat$Cells/final_df_seurat$Total)*100

            p <- ggplot(final_df_seurat, aes(x=Phase, y=Percentage, fill=Phase))+
              geom_bar(stat='identity')+
              facet_wrap(~Cluster_name) +
              theme_bw() +
              theme(axis.text.x = element_text(face = "bold", color = "black", size = fsize, angle = 90, vjust = 0.5),
                    axis.text.y = element_text(face = "bold", color = "black", size = 18, angle = 0),
                    axis.title.y = element_text(face = "bold", color = "black", size = fsize),
                    axis.title.x = element_text(face = "bold", color = "black", size = fsize),
                    legend.text = element_text(size = 18, color = "black", face = "bold.italic"),
                    legend.title = element_text(size = 18, color = "black", face = "bold.italic"),
                    strip.text.x = element_text(size = 18, color = "black", face = "bold.italic"),
                    strip.background = element_rect(color="black", fill="#FC4E07", size=1.5, linetype="solid")) +
              labs(y="% of cells", x="Phase", color="Phase")
            p
            plotly::ggplotly(p)
            global_umap <<- p
          }
        )
        session$sendCustomMessage("handler_startLoader", c("CC2_loader", 80))
      }
    }, error = function(e) {
      print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
      session$sendCustomMessage("handler_alert", "There was an error with drawing the resutls.")
    }, finally = {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("CC1_loader", 100))
      session$sendCustomMessage("handler_startLoader", c("CC2_loader", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "CC1_loader")
      session$sendCustomMessage("handler_finishLoader", "CC2_loader")
      session$sendCustomMessage("handler_enableAllButtons", "cellCycleRun")
    })
  })

