output$findMotifsATACExport <- downloadHandler(
  filename = function() {
    paste("motifsTableATAC-", Sys.Date(), ".txt", sep="")
  },
  content = function(file) {
    write.table(export_motifs_ATAC, file, sep = "\t", quote = F, row.names = T)
