  # HemaScribe annotation functionality
  observeEvent(input$hemaScribeConfirm, {
    session$sendCustomMessage("handler_startLoader", c("hemaScribe_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "hemaScribeConfirm")
    
    tryCatch({
      if (identical(seurat_object, NULL)) {
        session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
      } else {
        showModal(modalDialog(
          div('HemaScribe Analysis in Progress. This operation may take several minutes, please wait...', 
              style='color:#ffffff; background-color:#222d32;'), 
          footer = NULL, 
          style = 'font-size:20px; text-align:center;position:absolute;'
        ))
        
        session$sendCustomMessage("handler_startLoader", c("hemaScribe_loader", 20))
        
        # Run HemaScribe analysis
        library(HemaScribe)
        library(scuttle)
        source("Rfunc/hemascribe_mod.R") # reductionを指定できるようにしたもの
        source("Rfunc/hemascape_mod.R") # query.reductionをサポートするバージョン

        seurat_object <<- HemaScribe(seurat_object, return.full = FALSE, query.reduction = input$utilitiesReductionHemascribe)
        updateSignatures()
        session$sendCustomMessage("handler_startLoader", c("hemaScribe_loader", 50))
        
        # Run HemaScape with batch consideration (modified version supports query.reduction)
        if (input$hemaScribeBatchCorrection && !is.null(input$hemaScribeBatchMetadata)) {
          # Use batch correction with specified metadata column
          batch_var <- input$hemaScribeBatchMetadata
          seurat_object <<- HemaScape(seurat_object, vars = batch_var, query.reduction = input$utilitiesReductionHemascribe)
        } else {
          # Use default batch variable (orig.ident)
          seurat_object <<- HemaScape(seurat_object, query.reduction = input$utilitiesReductionHemascribe)
        }
        session$sendCustomMessage("handler_startLoader", c("hemaScribe_loader", 90))
        updateUtilitiesAssays()
        updateSelInpColor()
        updateUtilitiesReduction()
        updateSignatures()
        updateUmapTypeChoices(names(seurat_object@reductions))
        session$sendCustomMessage("handler_startLoader", c("hemaScribe_loader", 100))
      }
    }, error = function(e) {
      print(paste("HemaScribe Error:", e))
      showNotification(paste("Error:", e), type = 'error', duration = 200)
      session$sendCustomMessage("handler_alert", "There was an error with HemaScribe analysis.")
    }, finally = {
      removeModal()
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "hemaScribe_loader")
      session$sendCustomMessage("handler_enableAllButtons", "hemaScribeConfirm")
    })
