  #--------------------BoneMarrowMap tab----------------------------------------
  
  # Update BoneMarrowMap selectInputs when seurat_object changes
  observe({
    if (!is.null(seurat_object) && !is.null(seurat_object@meta.data)) {
      metadata_choices <- names(seurat_object@meta.data)
      updateSelectInput(session, "bmmBatchVar", 
                       choices = metadata_choices,
                       selected = if("orig.ident" %in% metadata_choices) "orig.ident" else metadata_choices[1])
      updateSelectInput(session, "bmmDonorKey", 
                       choices = metadata_choices,
                       selected = if("orig.ident" %in% metadata_choices) "orig.ident" else metadata_choices[1])
    }
  })
  
  observeEvent(input$bmmConfirm, {
    session$sendCustomMessage("handler_startLoader", c("bmm_loader", 5))
    session$sendCustomMessage("handler_disableAllButtons", "bmmConfirm")
    
    tryCatch({
      if (identical(seurat_object, NULL)) {
        session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
      } else if (organism != "human") {
        session$sendCustomMessage("handler_alert", "BoneMarrowMap is designed for human data only. Please use human hematopoietic cell data.")
      } else {
        showModal(modalDialog(
          div('BoneMarrowMap Analysis in Progress. This operation may take several minutes, please wait...', 
              style='color:#ffffff; background-color:#222d32;'), 
          footer = NULL, 
          style = 'font-size:20px; text-align:center;position:absolute;'
        ))
        
        session$sendCustomMessage("handler_startLoader", c("bmm_loader", 10))
        
        # Load BoneMarrowMap library
        if (!require(BoneMarrowMap, quietly = TRUE)) {
          stop("BoneMarrowMap package is not installed. Please install it first using: devtools::install_github('andygxzeng/BoneMarrowMap')")
        }
        library(BoneMarrowMap)

        # Load Seurat v5 compatibility patch for BoneMarrowMap
        source("Rfunc/bonemarrowmap_v5_compat.R")

        # Load local reference data
        bmm_ref_path <- "db/BoneMarrowMap/"
        bmm_ref <- readRDS(paste0(bmm_ref_path, "BoneMarrowMap_SymphonyReference.rds"))
        bmm_ref$save_uwot_path <- paste0(bmm_ref_path, "BoneMarrowMap_uwot_model.uwot")
        print(paste0("BoneMarrowMap: Loaded reference from ", bmm_ref_path))

        session$sendCustomMessage("handler_startLoader", c("bmm_loader", 15))
        
        # Get raw counts for mapping
        # BoneMarrowMap expects raw counts
        if ("RNA" %in% Assays(seurat_object)) {
          counts_matrix <- GetAssayData(seurat_object, assay = "RNA", layer = "counts")
        } else {
          counts_matrix <- GetAssayData(seurat_object, layer = "counts")
        }
        
        metadata_query <- seurat_object@meta.data
        
        session$sendCustomMessage("handler_startLoader", c("bmm_loader", 20))
        
        # Step 1: map_Query - project onto reference (using v5 compatible version)
        print("BoneMarrowMap: Running map_Query_v5...")

        vars_param <- NULL
        if (input$bmmUseBatch && !is.null(input$bmmBatchVar) && input$bmmBatchVar != "") {
          vars_param <- input$bmmBatchVar
        }

        query_obj <- map_Query_v5(
          exp_query = counts_matrix,
          metadata_query = metadata_query,
          ref_obj = bmm_ref,
          vars = vars_param,
          verbose = TRUE,
          do_normalize = TRUE,  # Always normalize from counts
          do_umap = TRUE,
          sigma = input$bmmSigma
        )
        
        session$sendCustomMessage("handler_startLoader", c("bmm_loader", 40))
        
        # Step 2: calculate_MappingError - QC (using v5 compatible version)
        # This function returns the query object with mapping_error_score and mapping_error_QC added
        print("BoneMarrowMap: Calculating mapping error...")

        donor_key_param <- NULL
        if (input$bmmThresholdByDonor && !is.null(input$bmmDonorKey) && input$bmmDonorKey != "") {
          donor_key_param <- input$bmmDonorKey
        }

        query_obj <- calculate_MappingError_v5(
          query = query_obj,
          reference = bmm_ref,
          MAD_threshold = input$bmmMADthreshold,
          threshold_by_donor = input$bmmThresholdByDonor,
          donor_key = donor_key_param
        )

        session$sendCustomMessage("handler_startLoader", c("bmm_loader", 60))
        
        # Step 3: predict_CellTypes (using v5 compatible version)
        print("BoneMarrowMap: Predicting cell types...")

        query_obj <- predict_CellTypes_v5(
          query_obj = query_obj,
          ref_obj = bmm_ref,
          ref_label = "CellType_Annotation",
          k = input$bmmK,
          mapQC_col = "mapping_error_QC",
          initial_label = "initial_CellType",
          final_label = "predicted_CellType",
          include_broad = input$bmmIncludeBroad
        )
        
        session$sendCustomMessage("handler_startLoader", c("bmm_loader", 80))
        
        # Step 4: predict_Pseudotime (using v5 compatible version)
        print("BoneMarrowMap: Predicting pseudotime...")

        query_obj <- predict_Pseudotime_v5(
          query_obj = query_obj,
          ref_obj = bmm_ref,
          pseudotime_label = "Pseudotime",
          k = input$bmmK,
          mapQC_class = "mapping_error_QC",
          initial_label = "initial_Pseudotime",
          final_label = "predicted_Pseudotime"
        )
        
        session$sendCustomMessage("handler_startLoader", c("bmm_loader", 90))
        
        # Transfer results back to seurat_object
        print("BoneMarrowMap: Transferring results to Seurat object...")

        # Add metadata columns (column names from BoneMarrowMap functions)
        seurat_object$mapping_error_score <<- query_obj$mapping_error_score
        seurat_object$mapping_error_QC <<- query_obj$mapping_error_QC
        seurat_object$initial_CellType <<- query_obj$initial_CellType
        seurat_object$predicted_CellType <<- query_obj$predicted_CellType
        if ("predicted_CellType_Broad" %in% colnames(query_obj@meta.data)) {
          seurat_object$predicted_CellType_Broad <<- query_obj$predicted_CellType_Broad
        }
        seurat_object$initial_Pseudotime <<- query_obj$initial_Pseudotime
        seurat_object$predicted_Pseudotime <<- query_obj$predicted_Pseudotime

        # Add reductions (names from map_Query_v5: harmony_projected, umap_projected)
        if ("harmony_projected" %in% names(query_obj@reductions)) {
          bmm_embedding <- Embeddings(query_obj, "harmony_projected")
          seurat_object[["bmm"]] <<- CreateDimReducObject(
            embeddings = bmm_embedding,
            key = "BMM_",
            assay = DefaultAssay(seurat_object)
          )
        }

        if ("umap_projected" %in% names(query_obj@reductions)) {
          bmm_umap <- Embeddings(query_obj, "umap_projected")
          seurat_object[["bmm_umap"]] <<- CreateDimReducObject(
            embeddings = bmm_umap,
            key = "BMMUMAP_",
            assay = DefaultAssay(seurat_object)
          )
        }
        
        session$sendCustomMessage("handler_startLoader", c("bmm_loader", 95))
        
        # Update UI elements
        updateUtilitiesAssays()
        updateSelInpColor()
        updateUtilitiesReduction()
        updateSignatures()
        updateUmapTypeChoices(names(seurat_object@reductions))
        
        # Show summary
        n_pass <- sum(seurat_object$mapping_error_QC == "Pass", na.rm = TRUE)
        n_fail <- sum(seurat_object$mapping_error_QC == "Fail", na.rm = TRUE)
        showNotification(
          paste0("BoneMarrowMap completed! QC: ", n_pass, " Pass, ", n_fail, " Fail"),
          type = "message",
          duration = 10
        )
        
        session$sendCustomMessage("handler_startLoader", c("bmm_loader", 100))
        print("BoneMarrowMap: Analysis completed successfully!")
      }
    }, error = function(e) {
      print(paste("BoneMarrowMap Error:", e))
      # Remove ANSI color codes from error message for display
      error_msg <- gsub("\033\\[[0-9;]*m", "", as.character(e$message))
      # Ensure error_msg is a single string
      error_msg <- paste(error_msg, collapse = " ")

      # Check for Seurat v5 compatibility error
      if (any(grepl("slot.*deprecated|slot.*defunct|SetAssayData|GetAssayData", error_msg, ignore.case = TRUE))) {
        error_msg <- paste0(error_msg, "\n\n[Seurat v5 compatibility issue] ",
                           "The BoneMarrowMap package may need updating. ",
                           "Please check Rfunc/bonemarrowmap_v5_compat.R or reinstall BoneMarrowMap.")
      }

      showNotification(paste("Error:", error_msg), type = 'error', duration = 30)
      session$sendCustomMessage("handler_alert", paste("BoneMarrowMap error:", error_msg))
    }, finally = {
      removeModal()
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "bmm_loader")
      session$sendCustomMessage("handler_enableAllButtons", "bmmConfirm")
    })
  })

  #--------------------trajectory tab----------------------------------------
  observeEvent(input$trajectoryConfirm, {

    session$sendCustomMessage("handler_startLoader", c("traj1_loader", 10))
    session$sendCustomMessage("handler_startLoader", c("traj2_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "trajectoryConfirm")
    tryCatch({
      if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
      else if (identical(seurat_object@meta.data$seurat_clusters, NULL)) session$sendCustomMessage("handler_alert", "Please, execute CLUSTERING first and then run UMAP, in the NON LINEAR DIMENSIONALITY REDUCTION tab.")

      else {
        showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%


        #delete previous lineages columns
        for_delete <- grep("Lineage", colnames(seurat_object@meta.data))
        if(length(for_delete) != 0)
        {
          seurat_object@meta.data <<- seurat_object@meta.data[, -for_delete]
        }


        library(slingshot)

        reduction <- Embeddings(seurat_object, input$trajectoryReduction)

        if (as.numeric(input$trajectorySliderDimensions) > dim(reduction)[2]) {
          trajectoryDim <- dim(reduction)[2]
          } else {
            trajectoryDim <- as.numeric(input$trajectorySliderDimensions)
          }

        print("0-------")


        trajectoryStart <- input$trajectoryStart
        if (!is.null(trajectoryStart)){ if(trajectoryStart == "DO NOT SET"){
          trajectoryStart <- NULL }}
        print('trajectoryStart')
        print(trajectoryStart)

        trajectoryEnd <- input$trajectoryEnd
        if  (!is.null(trajectoryEnd)){ if(trajectoryEnd == "DO NOT SET"){
          trajectoryEnd <- NULL }}

# sdsをglobalに
        sds <- slingshot(reduction[, 1:trajectoryDim], clusterLabels = seurat_object$seurat_clusters, dist.method = input$distmethod,
                         start.clus = trajectoryStart, end.clus = trajectoryEnd, stretch = input$stretch, omega = input$omega)

        gl_sds <<- sds


        session$sendCustomMessage("handler_startLoader", c("traj2_loader", 80))
        output$trajectoryPseudotimePlot <- renderPlot({ print(plot_P)} , height=input$trajectoryHeight, width=input$trajectoryWidth)
        output$trajectoryText <- renderPrint({print(metaD$all_lin)})
      }
    }, error = function(e) {
      print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
      session$sendCustomMessage("handler_alert", "There was an error with Trajectory Analysis.")
    }, finally = {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("traj1_loader", 100))
      session$sendCustomMessage("handler_startLoader", c("traj2_loader", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "traj1_loader")
      session$sendCustomMessage("handler_finishLoader", "traj2_loader")
      session$sendCustomMessage("handler_enableAllButtons", "trajectoryConfirm")
    })
  })



 observeEvent(input$trajectoryVis, {

    session$sendCustomMessage("handler_startLoader", c("traj1_loader", 10))
    session$sendCustomMessage("handler_startLoader", c("traj2_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "trajectoryConfirm")
    tryCatch({
      if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
      else if (identical(seurat_object@meta.data$seurat_clusters, NULL)) session$sendCustomMessage("handler_alert", "Please, execute CLUSTERING first and then run UMAP, in the NON LINEAR DIMENSIONALITY REDUCTION tab.")
       else if (is.null(gl_sds)) session$sendCustomMessage("handler_alert", "Please, run cals slingshot first.")

      else {
        showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%
        shinyjs::show("trajectoryPlot_loader")
        shinyjs::show("trajectoryCurve_loader")
        shinyjs::show("trajectoryPseudotimePlot_loader")


        color_length <- length(unique(seurat_object@meta.data$seurat_clusters))


        if (input$trajectoryColorPalette %in% c("Set1", "Set2", "Set3",  "Paired", "Dark2", "Accent","Spectral")){
        col_vector <- brewer.pal(20, input$trajectoryColorPalette)
        } else {
        col_vector <- get(input$trajectoryColorPalette)
        }

        if (length(col_vector) < color_length) {
            cols <- colorRampPalette(col_vector)(color_length )
        } else {
            cols <- col_vector
        }


        library(slingshot)


        metaD$all_lin <- slingLineages(gl_sds)
        pt <- slingPseudotime(gl_sds)

        for(i in 1:ncol(pt))
        {
          temp_lin <- pt[, i]
          seurat_object <<- AddMetaData(
            object = seurat_object,
            metadata = temp_lin,
            col.name = paste0("Lineage", i)
          )
        }

        print("1-------")

        updateInputLineageList(names(metaD$all_lin))
        # globalにlineagelistを保存
        gl_LineageList <<- names(metaD$all_lin)
        updateMetadata()
        session$sendCustomMessage("handler_startLoader", c("traj1_loader", 50))
        session$sendCustomMessage("handler_startLoader", c("traj2_loader", 50))

        library(dittoSeq)
        plot_D <- dittoDimPlot(seurat_object, "seurat_clusters",
                               dim.1 = input$slingX, dim.2 = input$slingY,
                               do.label = TRUE,
                               labels.repel = TRUE, size = input$trajectoryDotSize, opacity = input$trajectoryDotOpacity,
                               reduction.use = input$trajectoryReductionShow,
                               add.trajectory.lineages = slingLineages(gl_sds),
                               trajectory.cluster.meta = "seurat_clusters",
                               color.panel = cols,
                               data.out = F)

        print("2-------")

        # globalにtrajectory reductionを保存
        gl_trReducShow <<- input$trajectoryReductionShow

        if (input$trajectoryReductionShow != input$trajectoryReduction) {
          gl_embedded <<- embedCurves(gl_sds, Embeddings(seurat_object, input$trajectoryReductionShow))
          plot_C <- dittoDimPlot(seurat_object, "seurat_clusters",
                              dim.1 = input$slingX, dim.2 = input$slingY,
                               do.label = FALSE,
