output$circosdownloaderPDF <- downloadHandler(
  filename = function() {
    # ファイル名を動的に生成
    paste0("CircosPlot.", input$circosFigtype)
  },
  content = function(file) {
    # デバッグ情報
    print("Starting download handler")
    print(paste("Requested file type:", input$circosFigtype))
    
    # すべての状態をクリア
    if (exists("last_plot")) rm(last_plot)
    circos.clear()
    graphics.off() # すべてのグラフィックデバイスを確実に閉じる
    
    # 一時ファイルの完全削除
    temp_files <- c("plot.svg", "plot.png", "plot.pdf")
    sapply(temp_files, function(f) {
      if (file.exists(f)) {
        unlink(f, force = TRUE)
      }
    })
    
    # 一時ファイルパスの設定
    temp_file <- tempfile(pattern = "circos_", fileext = paste0(".", input$circosFigtype))
    print(paste("Using temp file:", temp_file))
    
    # グラフィックデバイスを開く
    tryCatch({
      print("Opening graphics device")
      switch(input$circosFigtype,
        "svg" = {
          print("Creating SVG device")
          svg(temp_file, height = input$circosR/72, width = input$circosR/72)
        },
        "png" = {
          print("Creating PNG device")
          png(temp_file, height = input$circosR/72, width = input$circosR/72, units='in', res = 300)
        },
        "pdf" = {
          print("Creating PDF device")
          pdf(temp_file, height = input$circosR/72, width = input$circosR/72)
        }
      )
      

