 #--------------------CellChat---------------------------
  observeEvent(input$cellchatConfirm, {
    session$sendCustomMessage("handler_startLoader", c("lr_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "cellchatConfirm")
    tryCatch({
      if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
      else if (identical(seurat_object@meta.data$seurat_clusters, NULL)) session$sendCustomMessage("handler_alert", "Please, execute CLUSTERING first.")
      else {
        showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;')) #position:absolute;top:50%;left:50%
        shinyjs::show("cellchat_loader")
          # directoryを作る
        if (dir.exists("cellchat")) {
            unlink("cellchat/*", recursive = TRUE)
            }
          dir.create( "cellchat", recursive = TRUE)
          dir.create( "cellchat/centrality", recursive = TRUE)
          dir.create( "cellchat/chord_diagram", recursive = TRUE)
          dir.create( "cellchat/vln", recursive = TRUE)
          dir.create( "cellchat/data_matrix", recursive = TRUE)

          library(CellChat)
          library(patchwork)
          library(qs2)
if (!input$uploadcellchatres){
          showNotification("Data must have been normalized.")
          showNotification("This may take a very very long time.....")

          df <- seurat_object
          Idents(df) <- as.factor(df@meta.data[,input$cellchatIdent]) #目的をactive identへ
          # '0'は名前に使えないのでこれに対する対応
          # seurat_objectのrenameができないので、ここはlocalにコピーする


    seurat_object$seurat_clusters <<- seurat_object@meta.data[, input$cellchatIdent]

# NAチェックと警告
if(sum(is.na(seurat_object$seurat_clusters)) > 0) {
  showNotification(
    paste("Warning: seurat_clusters contains", sum(is.na(seurat_object$seurat_clusters)), "NA values"),
    type = "warning",
    duration = 90
  )
}

    Idents(seurat_object) <<- seurat_object$seurat_clusters
    updateInputLRclusters()


          # v5 assayは V3に変換
          if (is_assay5(df)){
            df[["RNA"]] <- as(object = df[[DefaultAssay(df)]], Class = "Assay")
            DefaultAssay(df) <- "RNA"
            showNotification("Assay5 object was converted to assay3 for cellchat calc.")
          }

          ident_levels = levels(Idents(df))
          print(ident_levels)
          if ('0' %in% ident_levels){
            showNotification("Activity identity contains 0 as the name of a cluster. This cluster name is converted to zero.",
              type = 'error', duration = 60)
#            df <<- RenameIdents(df,  '0' = 'zero') # RenameIdentsは動かない。
            print(ident_levels)
            ident_levels[which(ident_levels == '0' )] <- "zero"
             levels(Idents(df)) <- ident_levels
             levels(df@meta.data[,input$cellchatIdent]) <- ident_levels
            print(levels(Idents(df)))
          }


          cellchat <- createCellChat(df, assay = DefaultAssay(df), do.sparse = T)
          cellchat <- setIdent(cellchat, ident.use = input$cellchatIdent)


          # humanへ
          if ((organism == 'mouse') & (input$cellchatDB_use == 'CellPhoneDB')){
            print("mouse_cellphoneDB")
            library(nichenetr)
            mouse_genes <- row.names(cellchat@data)
            human_symbol <- convert_mouse_to_human_symbols(mouse_genes, version =2)
            human_symbol[is.na(human_symbol)]  <- mouse_genes[is.na(human_symbol)]
            human_genes <- as.vector(unlist(human_symbol, use.names=FALSE))
            row.names(cellchat@data) <- human_genes
            showNotification("Mouse symbols have been converted to human ones for calculation.")
            print(str(cellchat))

          }

#          output$cellchatidents <- renderText({levels(cellchat@idents)})
          groupSize <- as.numeric(table(cellchat@idents)) # number of cells in each cell group
          if(organism == "mouse"){
          CellChatDB <- CellChatDB.mouse } else {CellChatDB <- CellChatDB.human }

#          output$cellchatDB_g <- renderPlot({showDatabaseCategory(CellChatDB)})

          print('CellChatDB')
          print( input$cellchatDB )

          if (input$cellchatDB_use == 'CellPhoneDB'){

            CellChatDB.use <- readRDS('nichenetr_helper_files/cellphoneDB_cellchat.RDS')
              if ( input$cellphoneDB != "all") {
              CellChatDB.use <- subsetDB(CellChatDB.use, search = input$cellphoneDB)
                }
            } else {
              if ( input$cellchatDB != "all") {
              CellChatDB.use <- subsetDB(CellChatDB, search = input$cellchatDB)
                } else { CellChatDB.use <- CellChatDB }
          }


withProgress(message = 'Computing...', value = 0, {

          cellchat@DB <- CellChatDB.use

          cellchat <- subsetData(cellchat)
          options(future.globals.maxSize = 1000 * 1024^2)  # Set to 700 MB
          future::plan("multisession", workers = 16) # do parallel
          incProgress(0.1)

          showNotification("Computing...this may take long long time....",  type = 'message', duration = 120)
          cellchat <- identifyOverExpressedGenes(cellchat, thresh.p = input$thresh.p)
          incProgress(0.1)
          cellchat <- identifyOverExpressedInteractions(cellchat)

          incProgress(0.1, detail = "Start the longest process")

          if (input$projectData){ # projected data
          showNotification("Data are projected on protein-protein interaction network.",  type = 'message', duration = 120)
            if (organism == "human"){
            cellchat <- projectData(cellchat, PPI.human)
          } else {
            cellchat <- projectData(cellchat, PPI.mouse)
          }
          cellchat <- computeCommunProb(cellchat, raw.use = FALSE)
          } else {
          cellchat <- computeCommunProb(cellchat)
        }
          # Filter out the cell-cell communication if there are only few number of cells in certain cell groups
          incProgress(0.3, detail = "The longest part is done.")

          cellchat <- filterCommunication(cellchat, min.cells = 10)
          showNotification("The clusters with fewer than 10 cells have been removed.")

          showNotification("Generating aggregated networks....",  type = 'message')

