      regulons.seurat_object <- regulonsToGeneLists(regulons_incidMat.seurat_object)
      regulonsAUC.seurat_object <- get_regulons_AUC(loom.seurat_object, column.attr.name='RegulonsAUC')
      
      print("2----")
      regulonsAucThresholds.seurat_object <- get_regulon_thresholds(loom.seurat_object)
      embeddings.seurat_object <- get_embeddings(loom.seurat_object)
      
      print("3----")
      exprMat.seurat_object <- get_dgem(loom.seurat_object)
      
      # バイナリマトリックスを読み込む（pySCENICで計算済み）
      print("Reading binary matrix from loom...")
      binary_data <- loom.seurat_object[["col_attrs/RegulonsBinary"]]$read()
      binary_matrix_loaded <- t(binary_data)  # 転置（loomでは列が細胞）
      print(paste("Binary matrix from loom - dimensions:", paste(dim(binary_matrix_loaded), collapse=" x ")))
      
      # 行名と列名を設定
      cell_ids <- get_cell_ids(loom.seurat_object)
      rownames(binary_matrix_loaded) <- cell_ids
      colnames(binary_matrix_loaded) <- names(regulons.seurat_object)
      
      # RSSデータを読み込む（pySCENICで計算済み）
      print("Reading RSS data from loom...")
    #  rss_json <- get_global_attr(loom.seurat_object, "RSS_cellType")
    #  rss.seurat_object.loaded <- as.data.frame(fromJSON(rss_json))

    # RSSデータを読み込む（pySCENICで計算済み）
    print("Reading RSS data from loom...")
    rss_json <- get_global_attr(loom.seurat_object, "RSS_cellType")

    # JSONをリストとして解析（重要：simplifyVector = FALSE）

    rss_list <- fromJSON(rss_json, simplifyVector = FALSE)

    # PythonのRSS構造（cell_type -> regulon）をRの期待する構造（regulon -> cell_type）に変換
    cell_types <- names(rss_list)
    regulons <- names(rss_list[[1]])

    # マトリックスを作成して埋める
    rss_matrix <- matrix(NA, nrow = length(regulons), ncol = length(cell_types))
    for (i in seq_along(cell_types)) {
      for (j in seq_along(regulons)) {
        rss_matrix[j, i] <- as.numeric(rss_list[[cell_types[i]]][[regulons[j]]])
      }
    }

    # 行名と列名を設定してデータフレームに変換
    rownames(rss_matrix) <- regulons
    colnames(rss_matrix) <- cell_types
    rss.seurat_object.loaded <- as.data.frame(rss_matrix)


      print(paste("RSS data from loom - dimensions:", paste(dim(rss.seurat_object.loaded), collapse=" x ")))
      
      # フィルタリング情報を読み込む
      print("Reading filtered regulons from loom...")
      filtered_json <- get_global_attr(loom.seurat_object, "FilteredRegulons")
      filtered_regulons_py <- fromJSON(filtered_json)
      print(paste("pySCENIC filtered regulons from loom:", length(filtered_regulons_py)))
      
      try({
        add_col_attr(loom=loom.seurat_object, key = "seurat_clusters", value=as.character(seurat_object$seurat_clusters), as.annotation=T)
      })
      
      # cellInfo作成（seurat_objectのメタデータを使用）
      cellInfo.seurat_object <- data.frame(
        CellID = cell_ids,
        seurat_clusters = seurat_object$seurat_clusters[match(cell_ids, colnames(seurat_object))],
        stringsAsFactors = FALSE
      )
      
      print("4----")
      close_loom(loom.seurat_object)
      
      session$sendCustomMessage("handler_startLoader", c("loom_analysis_loader", 30))
      
      # 元のコードに忠実に、AUCell関連の処理を行う（ただしpySCENICのデータを使用）
      cells_AUC.seurat_object <- regulonsAUC.seurat_object
      
      # geneSetsの準備（元のコードと同じ）
      geneSets.seurat_object <- regulons.seurat_object
      names(geneSets.seurat_object) <- paste0(names(geneSets.seurat_object)," ",lengths(geneSets.seurat_object),sep="")
      geneSets.seurat_object <- geneSets.seurat_object[unlist(lapply(geneSets.seurat_object, function(x) length(x) > 10))]
      
      print("6----")
      # geneSets.dfの作成（元のコードと同じ）
      geneSets.df <- data.frame(
        TF = "TF",
        gene_set = "gene_set",
        stringsAsFactors = FALSE
      )
      
      for(i in 1:length(geneSets.seurat_object)){
        temp <- as.data.frame(geneSets.seurat_object[i])
        TF_name <- names(geneSets.seurat_object[i])
        genes <- paste(temp[[1]], collapse=",")
        geneSets.df <- rbind(geneSets.df, 
                             data.frame(
                               TF = TF_name,
                               gene_set = genes,
                               stringsAsFactors = FALSE
                             ))
      }
      
      write.table(geneSets.df, paste0(user_dir_pyscenic, "/regulons.seurat_object.txt"),
                  sep="\t", quote=FALSE, col.names=FALSE, row.names=FALSE)

        print("7----")
      
      # AUCデータをファイルに保存（後の可視化用）
      auc_data <- getAUC(cells_AUC.seurat_object)
      write.table(auc_data, paste0(user_dir_pyscenic, "/AUC_per_cell.txt"), quote=F, sep="\t", row.names=T, col.names=NA)
      
      session$sendCustomMessage("handler_startLoader", c("loom_analysis_loader", 50))
      
      # バイナリマトリックスからの割り当てを作成
      print("Using binary matrix from loom...")
      cellsAssigned.seurat_object <- apply(binary_matrix_loaded, 2, function(x) {
        names(which(x == 1))
      })
      names(cellsAssigned.seurat_object) <- colnames(binary_matrix_loaded)
      
      # regulonsCellsを作成
      regulonsCells.seurat_object <- cellsAssigned.seurat_object
      
      # フィルタリング（元のコードと同じ）
      regulonsCells.seurat_object.filtered <- regulonsCells.seurat_object[unlist(lapply(regulonsCells.seurat_object, function(x) length(x) > 10))]
      
      # assignmentTableとassignmentMatの作成
      assignmentTable.seurat_object <- reshape2::melt(cellsAssigned.seurat_object, value.name="cell")
      colnames(assignmentTable.seurat_object)[2] <- "geneSet"
      assignmentMat.seurat_object <- table(assignmentTable.seurat_object[,"geneSet"], assignmentTable.seurat_object[,"cell"])
      
      library(stringr)
      session$sendCustomMessage("handler_startLoader", c("loom_analysis_loader", 70))
      
      maxRows <- 20
      aucMatrix.seurat_object <- t(assignmentMat.seurat_object)
      aucMatrix.seurat_object <- apply(aucMatrix.seurat_object, 2, as.numeric)
      
      # RSSの処理：loomファイルから読み込んだものを使用
      print("Using RSS from loom file...")
      rss.seurat_object <- rss.seurat_object.loaded

      print("8----")

      # 0. suffix付きregulon名のマッピングを最初に作成
      # まず、フィルタリング前の全regulonsを使用してマッピングを作成
      regulons_all <- regulons.seurat_object  # フィルタリング前のregulon
      names(regulons_all) <- paste0(names(regulons_all), " ", lengths(regulons_all), sep="")

      # AUC行名（suffix無し）から全regulons名（suffix付き）へのマッピング
      auc_names <- rownames(cells_AUC.seurat_object)
      regulons_all_names <- names(regulons_all)

      # suffixなしの名前を抽出してマッピング
      auc_base_names <- auc_names
      regulons_base_names <- gsub(" [0-9]+$", "", regulons_all_names)

      # マッピングテーブルを作成
      name_mapping <- data.frame(
        auc_name = auc_names,
        suffix_name = regulons_all_names[match(auc_base_names, regulons_base_names)],
        stringsAsFactors = FALSE
      )

      # NAチェックとデバッグ情報
      na_count <- sum(is.na(name_mapping$suffix_name))
      if(na_count > 0) {
        print(paste("Warning:", na_count, "regulons could not be mapped to suffix names"))
        print("Unmapped regulons:")
        print(name_mapping$auc_name[is.na(name_mapping$suffix_name)])
        # NAの場合はオリジナル名に遺伝子数0を付ける
        name_mapping$suffix_name[is.na(name_mapping$suffix_name)] <- 
          paste0(name_mapping$auc_name[is.na(name_mapping$suffix_name)], " 0")
      }

      # 1. pySCENICのRSSをそのまま使用（行名をsuffix付きに変更）
      rss.seurat_object.loaded.original <- rss.seurat_object.loaded

      # RSS行名もsuffix付きに変更
      rss_rownames_original <- rownames(rss.seurat_object.loaded.original)
      rss_rownames_suffix <- name_mapping$suffix_name[match(rss_rownames_original, name_mapping$auc_name)]

      # NAチェック（念のため）
      if(any(is.na(rss_rownames_suffix))) {
        rss_rownames_suffix[is.na(rss_rownames_suffix)] <- rss_rownames_original[is.na(rss_rownames_suffix)]
      }

      # 全regulonのRSS（unfiltered）
      rss.seurat_object.unfiltered <- rss.seurat_object.loaded.original
      rownames(rss.seurat_object.unfiltered) <- rss_rownames_suffix

      # unfilteredとして保存（全regulon）
      write.table(rss.seurat_object.unfiltered, 
                  paste0(user_dir_pyscenic, "/rss_regulon_by_cell_type_FULL_TABLE_unfiltered.txt"), 
                  sep = "\t", quote = F, col.names=NA)

      # フィルタリング済みのRSSを作成
      rss.seurat_object <- rss.seurat_object.unfiltered[
        which(gsub(" [0-9]+$", "", rownames(rss.seurat_object.unfiltered)) %in% filtered_regulons_py),
      ]

      # filteredとして保存（10細胞以上で活性なregulonのみ）
      write.table(rss.seurat_object, 
                  paste0(user_dir_pyscenic, "/rss_regulon_by_cell_type_FULL_TABLE_filtered.txt"), 
                  sep = "\t", quote = F, col.names=NA)

      # 2. pySCENICのフィルタリング済みregulonを使用
      # （filtered_regulons_pyには既に10細胞以上で活性なregulonのみが含まれている）
      print(paste("Using pySCENIC filtered regulons:", length(filtered_regulons_py)))

      # デバッグ: 次元確認
      print(paste("rss.seurat_object.unfiltered dimensions:", paste(dim(rss.seurat_object.unfiltered), collapse=" x ")))
      print(paste("rss.seurat_object (filtered) dimensions:", paste(dim(rss.seurat_object), collapse=" x ")))

      # 3. AUCマトリックスの準備（unfilteredとfiltered両方）
      # 3.1 全regulon（unfiltered）
      cells_AUC.seurat_object.unfiltered <- cells_AUC.seurat_object
      # 行名をsuffix付きに変更
      rownames(cells_AUC.seurat_object.unfiltered) <- name_mapping$suffix_name[
        match(rownames(cells_AUC.seurat_object.unfiltered), name_mapping$auc_name)
      ]

      # 3.2 フィルタリング済み（filtered）
      # filtered_regulons_pyはsuffixなしなので、元のAUC行名と直接比較
      filtered_indices <- which(rownames(cells_AUC.seurat_object) %in% filtered_regulons_py)

      cells_AUC.seurat_object.filtered <- cells_AUC.seurat_object[filtered_indices,]

      # 行名をsuffix付きに変更
      rownames(cells_AUC.seurat_object.filtered) <- name_mapping$suffix_name[
        match(rownames(cells_AUC.seurat_object.filtered), name_mapping$auc_name)
      ]

      # デバッグ: 次元確認
      print(paste("cells_AUC.seurat_object.unfiltered dimensions:", paste(dim(cells_AUC.seurat_object.unfiltered), collapse=" x ")))
      print(paste("cells_AUC.seurat_object.filtered dimensions:", paste(dim(cells_AUC.seurat_object.filtered), collapse=" x ")))

      # 4. 細胞タイプごとのregulon活性を計算（両方）
      # 4.1 Unfiltered
      regulonActivity_byCellType.unfiltered <- sapply(
        split(rownames(cellInfo.seurat_object), cellInfo.seurat_object$seurat_clusters),
        function(cells) rowMeans(getAUC(cells_AUC.seurat_object.unfiltered)[,cells])
      )

      # 4.2 Filtered
      regulonActivity_byCellType.filtered <- sapply(
        split(rownames(cellInfo.seurat_object), cellInfo.seurat_object$seurat_clusters),
        function(cells) rowMeans(getAUC(cells_AUC.seurat_object.filtered)[,cells])
      )

      # 5. スケール化（両方）
      # 5.1 Unfiltered
      regulonActivity_byCellType_Scaled.unfiltered <- t(scale(
        t(regulonActivity_byCellType.unfiltered), center = T, scale=T
      ))

      # 5.2 Filtered（元のコードのメイン出力）
      regulonActivity_byCellType_Scaled <- t(scale(
        t(regulonActivity_byCellType.filtered), center = T, scale=T
      ))

      # デバッグ: 次元確認
      print(paste("regulonActivity_byCellType_Scaled.unfiltered dimensions:", paste(dim(regulonActivity_byCellType_Scaled.unfiltered), collapse=" x ")))
      print(paste("regulonActivity_byCellType_Scaled dimensions:", paste(dim(regulonActivity_byCellType_Scaled), collapse=" x ")))

      # 6. 結果の保存
      # 6.1 Unfiltered（全regulon）
      write.table(regulonActivity_byCellType_Scaled.unfiltered, 
                  paste0(user_dir_pyscenic, "/scaled_regulon_activity_by_cell_type_FULL_TABLE_unfiltered.txt"), 
                  sep = "\t", quote = F, col.names = NA)

      # 6.2 Filtered（10細胞以上で活性なregulonのみ）
      write.table(regulonActivity_byCellType_Scaled, 
                  paste0(user_dir_pyscenic, "/scaled_regulon_activity_by_cell_type_FULL_TABLE_filtered.txt"), 
                  sep = "\t", quote = F, col.names = NA)

      # 7. geneSetsから既にフィルタリング済みのものを抽出
      # filtered_regulons_pyはsuffixなしなので、ベース名でマッチング
      geneSets.filtered <- geneSets.seurat_object[
        which(gsub(" [0-9]+$", "", names(geneSets.seurat_object)) %in% filtered_regulons_py)
      ]

      # 8. フィルタリング済みgeneSetsをテキストファイルとして保存
      geneSets.filtered.xls <- data.frame(TF = character(), gene_set = character(), stringsAsFactors = FALSE)
      for(i in 1:length(geneSets.filtered)){
        temp <- as.data.frame(geneSets.filtered[i])
        TF_name <- names(geneSets.filtered[i])  # suffix付きの名前を保持
        genes <- paste(temp[[1]], collapse=",")
        geneSets.filtered.xls <- rbind(geneSets.filtered.xls, 
                                       data.frame(TF = TF_name, gene_set = genes, stringsAsFactors = FALSE))
      }
      write.table(geneSets.filtered.xls, 
                  paste0(user_dir_pyscenic, "/regulons.seurat_object.filtered_by_pySCENIC.txt"),
                  col.names=T, row.names=F, sep="\t", quote=F)

      # 9. RSS上位regulonの抽出（可視化用）
      # 各細胞タイプでトップNのregulonを取得（suffix付き名前で）
      # フィルタリング済みRSSを使用
      top_n <- 20  # 各細胞タイプのトップ20
      top_regulons_per_celltype <- apply(rss.seurat_object, 2, function(x) {
        names(sort(x, decreasing=TRUE)[1:min(top_n, length(x))])
      })

      # ユニークなトップregulonのリスト（suffix付き）
      top_regulons_unique <- unique(as.vector(top_regulons_per_celltype))
      print(paste("Unique top regulons across all cell types:", length(top_regulons_unique)))

      # 10. トップregulonのみのアクティビティマトリックス（ヒートマップ用）
      # regulonActivity_byCellType_Scaledの行名は既にsuffix付き
      regulonActivity_byCellType_top <- regulonActivity_byCellType_Scaled[
        rownames(regulonActivity_byCellType_Scaled) %in% top_regulons_unique,
      ]
      write.table(regulonActivity_byCellType_top, 
                  paste0(user_dir_pyscenic, "/scaled_regulon_activity_top_regulons.txt"), 
                  sep = "\t", quote = F, col.names = NA)

      # 11. サマリー情報の出力
      print(paste("Total regulons from pySCENIC:", nrow(cells_AUC.seurat_object)))
      print(paste("Filtered regulons (>10 cells active):", length(filtered_regulons_py)))
      print(paste("Difference:", nrow(cells_AUC.seurat_object) - length(filtered_regulons_py), "regulons were filtered out"))
      print(paste("Percentage retained:", round(length(filtered_regulons_py)/nrow(cells_AUC.seurat_object)*100, 1), "%"))

      # 12. 後の可視化用に主要な結果をグローバル変数として保存
      # filteredバージョンをメインとして使用
      cells_AUC.seurat_object.ordered.filtered <<- cells_AUC.seurat_object.filtered  # suffix付き
      regulonActivity_byCellType_Scaled.seurat_object <<- regulonActivity_byCellType_Scaled  # suffix付き
      rss.seurat_object <<- rss.seurat_object  # suffix付き（フィルタリング済み）

      # UI通知用
      showNotification(paste("Total regulons from pySCENIC:", nrow(cells_AUC.seurat_object), "  Filtered regulons (>10 cells active):", length(filtered_regulons_py)))

      # 13. UI更新
      updateSliderInput(session, "grnTopRegulonsRNA", max = nrow(rss.seurat_object))

      print("Simplified analysis completed using pySCENIC filtering!")
      print("All done!")


    }, error = function(e) {
      print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
      session$sendCustomMessage("handler_alert", "There was an error with analyzing pyscenic results.")
    }, finally = {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("loom_analysis_loader", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "loom_analysis_loader")
      session$sendCustomMessage("handler_enableAllButtons", "grnLoomAnalysis")
    })
  })


