# デバッグ情報を出力する関数
print_debug_info <- function(data, label) {
  print(paste("Debug info for:", label))
  print(paste("Dimensions:", paste(dim(data), collapse = "x")))
  print("First few rows:")
  print(head(data))
  print("Summary:")
  print(summary(data))
}

# Z-scoreの計算
regulonsAUC <- seurat_object[[input$SCENICName]]$data
cellInfo <- seurat_object@meta.data

#print_debug_info(regulonsAUC, "regulonsAUC")
#print_debug_info(cellInfo, "cellInfo")

df_scores <- as.data.frame(t(regulonsAUC))
df_scores$cell_type <- seurat_object@meta.data[[input$IdentSCENIC]]

#print_debug_info(df_scores, "df_scores")

df_results <- df_scores %>%
  group_by(cell_type) %>%
  summarise(across(everything(), mean)) %>%
  mutate(across(-cell_type, 
                ~ (. - mean(df_scores[[cur_column()]])) / sd(df_scores[[cur_column()]]))) %>%
  pivot_longer(cols = -cell_type, names_to = "regulon", values_to = "Z") %>%
  mutate(regulon = sub("Regulon\\((.+)\\)", "\\1", regulon))

#print_debug_info(df_results, "df_results")

# Z-score >= 3.0 のregulon表示
top_regulons <- df_results %>%
  filter(Z >= 3.0) %>%
  arrange(desc(Z)) %>%
  head(20)  # 上位20個を表示

print("Top regulons with Z-score >= 3.0:")
print(top_regulons)

# 結果が空の場合の処理
if (nrow(top_regulons) == 0) {
  print("No regulons with Z-score >= 3.0 found. Adjusting threshold...")
  # Z-scoreの最大値を表示
  max_z <- max(df_results$Z, na.rm = TRUE)
  print(paste("Maximum Z-score:", max_z))
  
  # 閾値を調整して再度フィルタリング
  adjusted_threshold <- max(0, max_z - 1)  # 最大Z-scoreより1小さい値か0のどちらか大きい方
  top_regulons <- df_results %>%
    filter(Z >= adjusted_threshold) %>%
    arrange(desc(Z)) %>%
    head(20)
  
  print(paste("Adjusted threshold:", adjusted_threshold))
  print("Top regulons with adjusted threshold:")
  print(top_regulons)
}

# ヒートマップの作成
if (nrow(top_regulons) > 0) {
  df_heatmap <- df_results %>%
    filter(regulon %in% top_regulons$regulon) %>%
    pivot_wider(names_from = regulon, values_from = Z) %>%
    column_to_rownames("cell_type")

  # ヒートマップの描画
  tryCatch({

    pheatmap(df_heatmap,
             color = colorRampPalette(c("white", "yellow", "green", "blue"))(100),  # YlGnBu に近い色
             cluster_rows = FALSE,
             cluster_cols = FALSE,
             angle_col = 45,
             cellwidth = 15,
             cellheight = 15,
             border_color = "gray",
             show_rownames = TRUE,
             show_colnames = TRUE,
             fontsize = 6,
             display_numbers = TRUE,
             number_format = "%.1f",
             number_color = "black",
             filename = "scenic/regulon_zscore_heatmap.png",
             main = "Cell Type Specific Regulators - Z-Score",
              width = 12,
             height = 8)

    print("Heatmap generated successfully.")
  }, error = function(e) {
    showNotification(paste("Error in generating heatmap:", e))
  })

  # 結果の保存
  write.csv(df_results, "scenic/regulon_zscore_results.csv", row.names = FALSE)
  print("Z-score results saved to CSV.")
} else {
  print("No data available for heatmap generation.")
}

print("Z-score analysis completed.")

})

