# Function to update geneNameColumnSelect
updateGeneNameColumnSelect <- function() {
  if (!is.null(seurat_object)) {
    tryCatch({
      assay_name <- DefaultAssay(seurat_object)
      meta_features <- get_meta_features(seurat_object, assay_name)

      message(paste("updateGeneNameColumnSelect: meta_features has", ncol(meta_features), "columns"))
      message(paste("  Column names:", paste(colnames(meta_features), collapse = ", ")))

      if (!is.null(meta_features) && ncol(meta_features) > 0) {
        # Get character/factor columns that could contain gene names
        valid_cols <- sapply(meta_features, function(x) {
          is.character(x) || is.factor(x)
        })
        col_names <- colnames(meta_features)[valid_cols]
        message(paste("  Valid columns (character/factor):", paste(col_names, collapse = ", ")))

        if (length(col_names) > 0) {
          choices <- c("(none)" = "none", setNames(col_names, col_names))
          updateSelectInput(session, "geneNameColumnSelect", choices = choices)
          message(paste("  Updated selectInput with", length(col_names), "choices"))
        } else {
          updateSelectInput(session, "geneNameColumnSelect", choices = c("(none)" = "none"))
          message("  No valid columns found - reset to none")
        }
      } else {
        updateSelectInput(session, "geneNameColumnSelect", choices = c("(none)" = "none"))
        message("  meta_features is NULL or empty")
      }
    }, error = function(e) {
      message(paste("Error updating geneNameColumnSelect:", e$message))
    })
  }
}

# Set column from meta.features as rownames
observeEvent(input$confirmColumnToRownames, {
  tryCatch({
    if (identical(seurat_object, NULL)) {
      session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
      return()
    }

    selected_column <- input$geneNameColumnSelect
    if (is.null(selected_column) || selected_column == "none") {
      showNotification("Please select a column first.", type = "warning")
      return()
    }

    showModal(modalDialog(div('Converting gene names...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;'))

    assay_name <- DefaultAssay(seurat_object)
    message("\n=== Setting column as rownames ===")
    message(paste("Selected column:", selected_column))

    # Get meta.features
    meta_features <- get_meta_features(seurat_object, assay_name)

    if (!selected_column %in% colnames(meta_features)) {
      removeModal()
      showNotification(paste("Column", selected_column, "not found"), type = "error")
      return()
    }

    # Get gene symbols from selected column
    gene_symbols <- as.character(meta_features[[selected_column]])
    message(paste("Total genes:", length(gene_symbols)))
    message(paste("First 5 gene symbols:", paste(head(gene_symbols, 5), collapse = ", ")))

    # Convert underscores to dots to avoid Seurat's _ to - conversion
    # (Seurat converts _ to - during NormalizeData, which can cause collisions with genes containing -)
    gene_symbols_dot <- str_replace_all(gene_symbols, '_', '.')

    # Check for duplicates after conversion
    num_duplicates <- sum(duplicated(gene_symbols_dot))
    message(paste("Duplicates found (after _ to . conversion):", num_duplicates))

    # Make unique with "." separator
    if (num_duplicates > 0) {
      gene_symbols_rownames <- make.unique(gene_symbols_dot, sep = ".")
      message("Added .1, .2 suffixes to duplicates")
    } else {
      gene_symbols_rownames <- gene_symbols_dot
    }

    # Update rownames using v4 conversion approach
    if (is_assay5(seurat_object, assay_name)) {
      message("Assay5 detected - converting to Assay v4 for renaming")

      assay5_obj <- seurat_object[[assay_name]]
      assay4_obj <- as(assay5_obj, "Assay")

      # Update rownames (use "-" version for Seurat compatibility)
      if (nrow(assay4_obj@counts) > 0) {
        rownames(assay4_obj@counts) <- gene_symbols_rownames
      }
      if (nrow(assay4_obj@data) > 0) {
        rownames(assay4_obj@data) <- gene_symbols_rownames
      }
      if (nrow(assay4_obj@scale.data) > 0) {
        rownames(assay4_obj@scale.data) <- gene_symbols_rownames
      }

      # Update meta.features
      assay4_obj@meta.features <- data.frame(
        orig.gene.symbol = gene_symbols,  # 元の遺伝子名（_あり）
        gene.symbol = gene_symbols,       # aggregateで使用（_あり）
        row.names = gene_symbols_rownames # Seurat互換（-版）
      )

      # Convert back to Assay5
      new_assay5 <- as(assay4_obj, "Assay5")
      seurat_object[[assay_name]] <<- new_assay5

    } else {
      # Assay v4
      if (nrow(seurat_object@assays[[assay_name]]@counts) > 0) {
        rownames(seurat_object@assays[[assay_name]]@counts) <<- gene_symbols_rownames
      }
      if (nrow(seurat_object@assays[[assay_name]]@data) > 0) {
        rownames(seurat_object@assays[[assay_name]]@data) <<- gene_symbols_rownames
      }
      if (nrow(seurat_object@assays[[assay_name]]@scale.data) > 0) {
        rownames(seurat_object@assays[[assay_name]]@scale.data) <<- gene_symbols_rownames
      }

      seurat_object@assays[[assay_name]]@meta.features <<- data.frame(
        orig.gene.symbol = gene_symbols,  # 元の遺伝子名（_あり）
        gene.symbol = gene_symbols,       # aggregateで使用（_あり）
        row.names = gene_symbols_rownames # Seurat互換（-版）
      )
    }

    # Clear VariableFeatures
    if (length(VariableFeatures(seurat_object)) > 0) {
      VariableFeatures(seurat_object) <<- character(0)
      message("Cleared VariableFeatures")
    }

    # Update UI
    updateMetadata()
    updateGeneSearchFP()

    removeModal()

    showNotification(
      HTML(paste0(
        "<b>Gene names updated!</b><br>",
        "Column: ", selected_column, "<br>",
        "Genes: ", length(gene_symbols), "<br>",
        "Duplicates: ", num_duplicates, " (renamed with _1, _2, ...)"
      )),
      type = "message",
      duration = 10
    )

    message("=== Gene name conversion complete ===")

  }, error = function(e) {
    removeModal()
    showNotification(paste("Error:", e$message), type = "error", duration = 30)
    message(paste("Error in confirmColumnToRownames:", e$message))
  })
})

# Gene conversion from Ensembl ID to gene symbol
observeEvent(input$confirmGeneConversion, {
  tryCatch({
    if (identical(seurat_object, NULL)) {
      session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
    } else {
      showModal(modalDialog(div('Gene conversion in progress. Please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;'))
      
      # Ensembl ID to gene symbol conversion function using local database
      convert_ensembl_to_symbol <- function(ensembl_ids, organism = "mouse") {
        tryCatch({
          # Remove version numbers from Ensembl IDs if present
          ensembl_ids_clean <- sub("\\.\\d+$", "", ensembl_ids)
          print(paste("Cleaned Ensembl IDs (first 5):", paste(head(ensembl_ids_clean, 5), collapse = ", ")))
          
          # Load local gene conversion table
          gene_file <- ifelse(organism == "mouse", "db/mouse_genes.csv", "db/human_genes.csv")
          
          if (file.exists(gene_file)) {
            print(paste("Loading gene table from:", gene_file))
            gene_table <- read.csv(gene_file, stringsAsFactors = FALSE)
            
            print(paste("Gene table contains", nrow(gene_table), "entries"))
            
            # Create mapping from local table
            gene_map <- setNames(gene_table$external_gene_name, gene_table$ensembl_gene_id)
            
            # Remove empty gene names
            gene_map <- gene_map[!is.na(gene_map) & gene_map != ""]
            
            print(paste("Created gene map with", length(gene_map), "valid entries"))
            
          } else {
            print(paste("Gene table file not found:", gene_file))
            print("Falling back to online biomaRt...")
            
            # Fallback to biomaRt if local file doesn't exist
            library(biomaRt)
            
            datasets <- list(
              mouse = "mmusculus_gene_ensembl",
              human = "hsapiens_gene_ensembl"
            )
            
            old_timeout <- getOption("timeout")
            options(timeout = 600)
            
            mart <- useMart("ensembl", dataset = datasets[[organism]])
            
            # Query in smaller batches
            batch_size <- 500
            all_results <- data.frame()
            
            for (i in seq(1, length(ensembl_ids_clean), batch_size)) {
              end_idx <- min(i + batch_size - 1, length(ensembl_ids_clean))
              batch_ids <- ensembl_ids_clean[i:end_idx]
              
              print(paste("Querying batch", ceiling(i/batch_size), "of", ceiling(length(ensembl_ids_clean)/batch_size)))
              
              batch_results <- getBM(
                attributes = c("ensembl_gene_id", "external_gene_name"),
                filters = "ensembl_gene_id",
                values = batch_ids,
                mart = mart
              )
              
              all_results <- rbind(all_results, batch_results)
            }
            
            options(timeout = old_timeout)
            
            all_results <- all_results[!is.na(all_results$external_gene_name) & 
                                      all_results$external_gene_name != "", ]
            gene_map <- setNames(all_results$external_gene_name, all_results$ensembl_gene_id)
          }
          
          print(paste("Final gene_map has", length(gene_map), "entries"))
          
          # Map all input IDs, keeping original if no mapping found
          mapped_symbols <- ifelse(ensembl_ids_clean %in% names(gene_map), 
                                  gene_map[ensembl_ids_clean], 
                                  ensembl_ids)
          
          # Handle duplicate symbols by appending original Ensembl ID
          if (any(duplicated(mapped_symbols))) {
            dup_symbols <- mapped_symbols[duplicated(mapped_symbols) | duplicated(mapped_symbols, fromLast = TRUE)]
            unique_dup_symbols <- unique(dup_symbols)
            
            for (dup_symbol in unique_dup_symbols) {
              if (grepl("^ENS", dup_symbol)) next
              
              dup_indices <- which(mapped_symbols == dup_symbol)
              for (i in dup_indices) {
                # Use dash instead of underscore to avoid Seurat warning
                mapped_symbols[i] <- paste0(dup_symbol, "-", ensembl_ids[i])
              }
            }
          }
          
          return(mapped_symbols)
          
        }, error = function(e) {
          print(paste("Error in gene conversion: ", e$message))
          return(ensembl_ids)
        })
      }
      
      # Get current gene names
      current_genes <- rownames(seurat_object)
      
      # Filter for likely Ensembl IDs (starting with ENSMUSG for mouse or ENSG for human)
      organism <- input$conversionOrganism
      if (organism == "mouse") {
        ensembl_pattern <- "^ENSMUSG"
      } else {
        ensembl_pattern <- "^ENSG"
      }
      
      ensembl_genes <- grep(ensembl_pattern, current_genes, value = TRUE)
      
      if (length(ensembl_genes) == 0) {
        showNotification("No Ensembl IDs found in the dataset.", type = "warning", duration = 200)
        removeModal()
        return()
      }
      
      # Debug information
      print(paste("Found", length(ensembl_genes), "Ensembl IDs"))
      print(paste("First 5 Ensembl IDs:", paste(head(ensembl_genes, 5), collapse = ", ")))
      print(paste("Organism:", organism))
      
      # Convert Ensembl IDs to gene symbols
      converted_symbols <- convert_ensembl_to_symbol(ensembl_genes, organism = organism)
      
      # Create mapping for all genes
      all_genes_mapped <- current_genes
      names(all_genes_mapped) <- current_genes
      
      # Update with converted symbols
      for (i in seq_along(ensembl_genes)) {
        all_genes_mapped[ensembl_genes[i]] <- converted_symbols[i]
      }
      
      # Update gene names in Seurat object if requested
      if (input$updateGeneNames) {
        print("Updating gene names in Seurat object...")

        # Get all assays
        assays <- names(seurat_object@assays)
        print(paste("Found assays:", paste(assays, collapse = ", ")))

        # Process each assay
        for (assay_name in assays) {
          print(paste("Processing assay:", assay_name))

          current_assay <- seurat_object[[assay_name]]
          is_v5 <- inherits(current_assay, "Assay5")
          print(paste("  Assay type:", ifelse(is_v5, "Assay5", "Assay v4")))

          if (is_v5) {
            # ===== Assay5: GetAssayData API でデータ取得 → リネーム → 再構築 =====
            tryCatch({
              # JoinLayers してからデータ取得
              seurat_object <<- JoinLayers(seurat_object, assay = assay_name)

              # counts を取得（GetAssayData は v4/v5 両対応）
              counts_mat <- GetAssayData(seurat_object, assay = assay_name, layer = "counts")
              original_rownames <- rownames(counts_mat)
              print(paste("  Got counts:", nrow(counts_mat), "x", ncol(counts_mat)))

              # 遺伝子名マッピング
              new_gene_names <- all_genes_mapped[original_rownames]
              new_gene_names <- gsub("_", "-", new_gene_names)
              names(new_gene_names) <- NULL
              # NA（マッピングなし）は元の名前を保持
              na_mask <- is.na(new_gene_names)
              if (any(na_mask)) {
                new_gene_names[na_mask] <- original_rownames[na_mask]
              }
              rownames(counts_mat) <- new_gene_names
              print(paste("  Renamed counts:", length(new_gene_names), "genes"))

              # Assay5 として再構築
              new_assay <- CreateAssay5Object(counts = counts_mat)

              # data layer（正規化済みデータ）があれば処理
              available_layers <- Layers(seurat_object[[assay_name]])
              if ("data" %in% available_layers) {
                data_mat <- tryCatch(
                  GetAssayData(seurat_object, assay = assay_name, layer = "data"),
                  error = function(e) NULL
                )
                if (!is.null(data_mat) && nrow(data_mat) > 0) {
                  data_new_names <- all_genes_mapped[rownames(data_mat)]
                  data_new_names <- gsub("_", "-", data_new_names)
                  names(data_new_names) <- NULL
                  na_mask_d <- is.na(data_new_names)
                  if (any(na_mask_d)) data_new_names[na_mask_d] <- rownames(data_mat)[na_mask_d]
                  rownames(data_mat) <- data_new_names
                  new_assay <- SetAssayData(new_assay, layer = "data", new.data = data_mat)
                  print(paste("  Updated data layer:", nrow(data_mat), "genes"))
                }
              }

              # scale.data layer があれば処理
              if ("scale.data" %in% available_layers) {
                scale_mat <- tryCatch(
                  GetAssayData(seurat_object, assay = assay_name, layer = "scale.data"),
                  error = function(e) NULL
                )
                if (!is.null(scale_mat) && nrow(scale_mat) > 0) {
                  scale_new_names <- all_genes_mapped[rownames(scale_mat)]
                  scale_new_names <- gsub("_", "-", scale_new_names)
                  names(scale_new_names) <- NULL
                  na_mask_s <- is.na(scale_new_names)
                  if (any(na_mask_s)) scale_new_names[na_mask_s] <- rownames(scale_mat)[na_mask_s]
                  rownames(scale_mat) <- scale_new_names
                  new_assay <- SetAssayData(new_assay, layer = "scale.data", new.data = scale_mat)
                  print(paste("  Updated scale.data layer:", nrow(scale_mat), "genes"))
                }
              }

              # VariableFeatures
              if (length(VariableFeatures(seurat_object, assay = assay_name)) > 0) {
                var_features <- VariableFeatures(seurat_object, assay = assay_name)
                new_var <- all_genes_mapped[var_features]
                new_var <- gsub("_", "-", new_var)
                names(new_var) <- NULL
                na_mask_v <- is.na(new_var)
                if (any(na_mask_v)) new_var[na_mask_v] <- var_features[na_mask_v]
                VariableFeatures(new_assay) <- new_var
              }

              # 置換（既に Assay5 として作成済み）
              seurat_object[[assay_name]] <<- new_assay
              print(paste("  Replaced assay as Assay5:", assay_name))

            }, error = function(e) {
              print(paste("  Error processing Assay5:", e$message))
              showNotification(paste("Error processing assay", assay_name, ":", e$message), type = "error", duration = 60)
            })

          } else {
            # ===== Assay v4: 直接変更 =====
            # Get features from each slot
            counts_features <- if (!is.null(current_assay@counts) && nrow(current_assay@counts) > 0)
              rownames(current_assay@counts) else NULL
            data_features <- if (!is.null(current_assay@data) && nrow(current_assay@data) > 0)
              rownames(current_assay@data) else NULL
            scale_features <- if (!is.null(current_assay@scale.data) && nrow(current_assay@scale.data) > 0)
              rownames(current_assay@scale.data) else NULL

            has_counts <- !is.null(counts_features)
            has_data <- !is.null(data_features)
            has_scale <- !is.null(scale_features)

            if (!has_counts && !has_data && !has_scale) {
              print(paste("  Skipping assay", assay_name, "- no data found"))
              next
            }

            if (has_counts) {
              new_names <- all_genes_mapped[rownames(current_assay@counts)]
              new_names <- gsub("_", "-", new_names)
              names(new_names) <- NULL
              rownames(current_assay@counts) <- new_names
              print(paste("  Updated counts:", length(new_names), "genes"))
            }
            if (has_data) {
              new_names <- all_genes_mapped[rownames(current_assay@data)]
              new_names <- gsub("_", "-", new_names)
              names(new_names) <- NULL
              rownames(current_assay@data) <- new_names
              print(paste("  Updated data:", length(new_names), "genes"))
            }
            if (has_scale) {
              new_names <- all_genes_mapped[rownames(current_assay@scale.data)]
              new_names <- gsub("_", "-", new_names)
              names(new_names) <- NULL
              rownames(current_assay@scale.data) <- new_names
              print(paste("  Updated scale.data:", length(new_names), "genes"))
            }

            # meta.features
            if (nrow(current_assay@meta.features) > 0) {
              features_to_use <- if (has_counts) counts_features else if (has_data) data_features else scale_features
              if (all(rownames(current_assay@meta.features) %in% features_to_use)) {
                new_meta_names <- all_genes_mapped[rownames(current_assay@meta.features)]
                new_meta_names <- gsub("_", "-", new_meta_names)
                names(new_meta_names) <- NULL
                rownames(current_assay@meta.features) <- new_meta_names
              }
            }

            # VariableFeatures
            if (length(VariableFeatures(seurat_object, assay = assay_name)) > 0) {
              var_features <- VariableFeatures(seurat_object, assay = assay_name)
              new_var <- all_genes_mapped[var_features]
              new_var <- gsub("_", "-", new_var)
              names(new_var) <- NULL
              VariableFeatures(current_assay) <- new_var
            }

            seurat_object[[assay_name]] <<- current_assay
            print(paste("  Successfully updated assay:", assay_name))
          }
        }

        print("Gene name update completed")

        # Ensembl → symbol 変換後、percent.mt を再計算
        # （変換前は Ensembl ID で ^mt-/^MT- にマッチしなかったため 0 になっている）
        tryCatch({
          mt_pattern <- if (organism == "mouse") "^mt-" else "^MT-"
          seurat_object[["percent.mt"]] <<- PercentageFeatureSet(seurat_object, pattern = mt_pattern)
          mt_mean <- mean(seurat_object@meta.data$percent.mt, na.rm = TRUE)
          print(paste("Recalculated percent.mt after gene conversion (pattern:", mt_pattern, ", mean:", round(mt_mean, 2), "%)"))
        }, error = function(e) {
          print(paste("Warning: Could not recalculate percent.mt:", e$message))
        })
      }

      # Count successful conversions
      successfully_converted <- sum(converted_symbols != ensembl_genes)
      
      # Update UI elements
      updateUtilitiesAssays()
      updateGeneSearchFP()
      
      removeModal()
      
      if (successfully_converted > 0) {
        showNotification(paste("Gene conversion completed successfully.", 
                             successfully_converted, "out of", length(ensembl_genes), 
                             "Ensembl IDs were converted to gene symbols."), 
                        type = "message", duration = 200)
      } else {
        showNotification(paste("Gene conversion failed. None of the", length(ensembl_genes), 
                             "Ensembl IDs could be converted. This might be due to:",
                             "1) Network connectivity issues",
                             "2) Ensembl database version mismatch",
                             "3) Non-standard Ensembl ID format.",
                             "Original gene names were preserved."), 
                        type = "warning", duration = 300)
      }
    }
  }, error = function(e) {
    removeModal()
    print(paste("Error in gene conversion: ", e))
    showNotification(paste("Error in gene conversion: ", e), type = "error", duration = 200)
  })
})

# Species Gene Conversion
observeEvent(input$confirmSpeciesConversion, {
  tryCatch({
    if (identical(seurat_object, NULL)) {
      showNotification("Please upload data first.", type = "error", duration = 10)
      return()
    }
    
    showModal(modalDialog(
      title = "Species Gene Conversion",
      "Converting gene symbols between species...",
      footer = NULL,
      easyClose = FALSE
    ))
    
    # Load conversion tables function
    load_species_conversion_tables <- function(method) {
      file_path <- NULL
      
      if (method == "nichenetr_v1_original") {
        file_path <- "db/nichenetr_geneinfo_human.csv"
      } else if (method == "nichenetr_v1_corrected") {
        file_path <- "db/nichenetr_geneinfo_human_corrected.csv"
      } else if (method == "nichenetr_v2_original") {
        file_path <- "db/nichenetr_geneinfo_2022.csv"
      } else if (method == "nichenetr_v2_corrected") {
        file_path <- "db/nichenetr_geneinfo_2022_corrected.csv"
      } else if (method == "consensus_original") {
        file_path <- "db/consensus_orthologs_one_to_one.csv"
      } else if (method == "consensus_corrected") {
        file_path <- "db/consensus_orthologs_one_to_one_corrected.csv"
      }
      
      print(paste("Trying to load file:", file_path))
      print(paste("File exists:", file.exists(file_path)))
      
      if (!is.null(file_path) && file.exists(file_path)) {
        table_data <- read.csv(file_path, stringsAsFactors = FALSE)
        print(paste("Loaded table with", nrow(table_data), "rows and", ncol(table_data), "columns"))
        print(paste("Column names:", paste(colnames(table_data), collapse = ", ")))
        return(table_data)
      } else {
        print(paste("ERROR: Could not load conversion table for method:", method))
        return(NULL)
      }
    }
    
    # Species conversion function
    convert_species_genes <- function(gene_symbols, method, organism) {
      conversion_table <- load_species_conversion_tables(method)
      
      if (is.null(conversion_table)) {
        showNotification("Conversion table not found. Please check file paths.", type = "error")
        return(rep(NA, length(gene_symbols)))
      }
      
      print(paste("Converting", length(gene_symbols), "genes from", organism, "using method", method))
      
      if (startsWith(method, "consensus")) {
        # For consensus tables
        if (organism == "mouse") {
          # Mouse to Human
          mapping_dict <- setNames(conversion_table$human_symbol, conversion_table$mouse_symbol)
          print(paste("Created mapping dictionary with", length(mapping_dict), "mouse->human mappings"))
        } else {
          # Human to Mouse
          mapping_dict <- setNames(conversion_table$mouse_symbol, conversion_table$human_symbol)
          print(paste("Created mapping dictionary with", length(mapping_dict), "human->mouse mappings"))
        }
      } else {
        # For NichenetR tables - use simplified logic first
        print("Using NichenetR table")
        print(paste("Table columns:", paste(colnames(conversion_table), collapse = ", ")))
        
        if (organism == "mouse") {
          # Mouse to Human - simplified
          valid_rows <- !is.na(conversion_table$symbol_mouse) & !is.na(conversion_table$symbol)
          mapping_dict <- setNames(conversion_table$symbol[valid_rows], conversion_table$symbol_mouse[valid_rows])
          print(paste("Created mapping dictionary with", length(mapping_dict), "mouse->human mappings"))
        } else {
          # Human to Mouse - simplified  
          valid_rows <- !is.na(conversion_table$symbol_mouse) & !is.na(conversion_table$symbol)
          mapping_dict <- setNames(conversion_table$symbol_mouse[valid_rows], conversion_table$symbol[valid_rows])
          print(paste("Created mapping dictionary with", length(mapping_dict), "human->mouse mappings"))
        }
      }
      
      # Convert genes
      converted_genes <- mapping_dict[gene_symbols]
      names(converted_genes) <- NULL
      
      # Debug output
      conversion_count <- sum(!is.na(converted_genes))
      print(paste("Successfully converted", conversion_count, "out of", length(gene_symbols), "genes"))
      
      # Show sample conversions
      if (length(gene_symbols) > 0) {
        sample_size <- min(5, length(gene_symbols))
        sample_indices <- 1:sample_size
        print(paste("Sample conversion examples:"))
        for (i in sample_indices) {
          original <- gene_symbols[i]
          converted <- ifelse(is.na(converted_genes[i]), "NO_CONVERSION", converted_genes[i])
          print(paste("  ", original, "→", converted))
        }
      }
      
      return(converted_genes)
    }
    
    # Get current organism and target species
    current_organism <- ifelse(is.null(input$conversionOrganism), organism, input$conversionOrganism)
    target_species <- ifelse(current_organism == "mouse", "human", "mouse")
    target_species_label <- ifelse(current_organism == "mouse", "Human", "Mouse")
    
    # Debug: Show conversion direction
    print(paste("=== SPECIES CONVERSION DEBUG ==="))
    print(paste("Current organism setting:", current_organism))
    print(paste("Target species:", target_species))
    print(paste("Conversion direction:", stringr::str_to_title(current_organism), "→", target_species_label))
    print(paste("Conversion method:", input$speciesConversionMethod))
    
    # Check if counts data exists in the active assay (v5対応)
    active_assay <- DefaultAssay(seurat_object)
    counts_data <- tryCatch({
      Seurat::GetAssayData(seurat_object, assay = active_assay, layer = "counts")
    }, error = function(e) {
      Seurat::GetAssayData(seurat_object, assay = active_assay, slot = "counts")
    })
    if (is.null(counts_data) || nrow(counts_data) == 0) {
      showNotification("Error: No counts data found in active assay. Species conversion requires raw count data.", type = "error", duration = 20)
      removeModal()
      return()
    }

    # Get gene names from the active assay (v5対応)
    current_genes <- rownames(counts_data)
    total_genes <- length(current_genes)
    
    # Convert gene names once for all assays
    converted_genes <- convert_species_genes(current_genes, input$speciesConversionMethod, current_organism)
    
    # Debug: Check conversion results
    print(paste("Conversion method:", input$speciesConversionMethod))
    print(paste("Total genes:", length(current_genes)))
    print(paste("Sample original genes:", paste(head(current_genes, 5), collapse = ", ")))
    print(paste("Sample converted genes:", paste(head(converted_genes, 5), collapse = ", ")))
    
    # Identify genes that couldn't be converted
    failed_conversion <- is.na(converted_genes)
    successful_conversions <- sum(!failed_conversion)
    failed_genes <- current_genes[failed_conversion]
    
    print(paste("Successfully converted:", successful_conversions, "out of", length(current_genes)))
    
    # Filter out genes that couldn't be converted
    valid_genes <- !failed_conversion
    converted_genes_clean <- converted_genes[valid_genes]
    
    # Create gene mapping for duplicates (vectorized approach)
    if (any(duplicated(converted_genes_clean))) {
      # Use factor-based aggregation (much faster)
      gene_factor <- factor(converted_genes_clean)
      unique_genes <- levels(gene_factor)
      gene_indices_list <- split(seq_along(converted_genes_clean), gene_factor)
    }
    
    # Process active assay only
    assay_obj <- seurat_object@assays[[active_assay]]
    
    # Filter to valid genes
    counts_matrix <- assay_obj@counts[valid_genes, ]
    
    # Debug: Check original counts matrix
    print(paste("Original counts matrix dimensions:", paste(dim(assay_obj@counts), collapse = " x ")))
    print(paste("Original non-zero elements:", Matrix::nnzero(assay_obj@counts)))
    print(paste("Valid genes count:", sum(valid_genes)))
    print(paste("Filtered counts matrix dimensions:", paste(dim(counts_matrix), collapse = " x ")))
    print(paste("Filtered non-zero elements:", Matrix::nnzero(counts_matrix)))
    print(paste("Sample original values:", paste(head(assay_obj@counts@x, 5), collapse = ", ")))
    
    # Handle duplicate genes by averaging (keeping dgCMatrix format)
    if (any(duplicated(converted_genes_clean))) {
      print("Processing duplicate genes...")
      
      # Create mapping from original to unique gene names
      unique_converted_genes <- unique(converted_genes_clean)
      gene_mapping <- factor(converted_genes_clean, levels = unique_converted_genes)
      
      # Create aggregation matrix (sparse)
      n_unique <- length(unique_converted_genes)
      n_genes <- length(converted_genes_clean)
      
      # Create sparse aggregation matrix
      agg_matrix <- Matrix::sparseMatrix(
        i = as.integer(gene_mapping),
        j = seq_along(converted_genes_clean),
        x = rep(1, n_genes),
        dims = c(n_unique, n_genes)
      )
      
      # Sum counts for duplicate genes
      summed_counts <- agg_matrix %*% counts_matrix
      
      # Calculate gene counts for averaging
      gene_counts <- Matrix::rowSums(agg_matrix)
      
      # Average by dividing by gene counts (keeping sparse)
      averaged_counts <- Matrix::Diagonal(x = 1/gene_counts) %*% summed_counts
      
      # Set row and column names
      rownames(averaged_counts) <- unique_converted_genes
      colnames(averaged_counts) <- colnames(counts_matrix)
      
      print(paste("After averaging duplicates: dimensions", paste(dim(averaged_counts), collapse = " x ")))
    } else {
      averaged_counts <- counts_matrix
      rownames(averaged_counts) <- converted_genes_clean
      print(paste("No duplicates found: dimensions", paste(dim(averaged_counts), collapse = " x ")))
    }
    
    # Debug: Check matrix integrity before assignment
    print(paste("Matrix class before assignment:", class(averaged_counts)))
    print(paste("Matrix dimensions:", paste(dim(averaged_counts), collapse = " x ")))
    print(paste("Non-zero elements:", Matrix::nnzero(averaged_counts)))
    
    # Check if matrix has @x slot (numeric values)
    tryCatch({
      sample_values <- head(averaged_counts@x, 5)
      print(paste("Sample values:", paste(sample_values, collapse = ", ")))
    }, error = function(e) {
      print("Matrix does not have @x slot (likely logical matrix)")
    })
    
    # Ensure it's a numeric sparse matrix (dgCMatrix)
    if (!inherits(averaged_counts, "dgCMatrix")) {
      if (inherits(averaged_counts, "ngCMatrix")) {
        # Convert logical sparse matrix to numeric sparse matrix
        averaged_counts <- as(averaged_counts, "dgCMatrix")
        print("Converted ngCMatrix to dgCMatrix")
      } else {
        averaged_counts <- as(averaged_counts, "dgCMatrix")
        print("Converted to dgCMatrix")
      }
    }
    
    # Remove the old assay completely and create a new one with converted counts
    print(paste("Removing old assay:", active_assay))
    seurat_object@assays[[active_assay]] <<- NULL
    
    # Create a new assay with the converted counts
    print(paste("Creating new assay with converted counts"))
    new_assay <- Seurat::CreateAssayObject(counts = averaged_counts)
    seurat_object@assays[[active_assay]] <<- new_assay
    
    # Set the default assay
    Seurat::DefaultAssay(seurat_object) <<- active_assay
    
    # v5対応: GetAssayDataを使用
    new_counts <- tryCatch({
      Seurat::GetAssayData(seurat_object, assay = active_assay, layer = "counts")
    }, error = function(e) {
      Seurat::GetAssayData(seurat_object, assay = active_assay, slot = "counts")
    })
    print(paste("New assay created with dimensions:", paste(dim(new_counts), collapse = " x ")))
    
    # Update utility functions
    updateGeneSearchFP()
    
    # Show results
    duplicates_merged <- total_genes - length(failed_genes) - nrow(seurat_object)
    
    # Calculate statistics
    duplicates_merged <- total_genes - length(failed_genes) - nrow(seurat_object)
    
    notification_text <- paste0(
      "Species conversion completed!\n",
      "Original genes: ", total_genes, "\n",
      "Successfully converted: ", successful_conversions, "\n",
      "Genes removed (no conversion): ", length(failed_genes), "\n",
      "Final genes after merging duplicates: ", nrow(seurat_object), "\n",
      "Direction: ", stringr::str_to_title(current_organism), " → ", target_species_label, "\n\n",
      "Data and scale.data slots have been cleared.\n",
      "Please run normalization and scaling in the DATA NORMALIZATION & SCALING tab."
    )
    
    showNotification(notification_text, type = "message", duration = 30)
    
    if (length(failed_genes) > 0) {
      failed_preview <- if (length(failed_genes) <= 10) {
        paste(failed_genes, collapse = ", ")
      } else {
        paste(c(failed_genes[1:10], paste("... and", length(failed_genes) - 10, "more")), collapse = ", ")
      }
      showNotification(paste("Removed genes:", failed_preview), type = "warning", duration = 20)
    }
    
    if (duplicates_merged > 0) {
      showNotification(paste("Merged", duplicates_merged, "duplicate genes by averaging"), type = "message", duration = 15)
    }
    
    showNotification("Next step: Please run normalization and scaling in the DATA NORMALIZATION & SCALING tab.", type = "message", duration = 90)
    
    removeModal()
    
  }, error = function(e) {
    removeModal()
    print(paste("Error in species conversion: ", e))
    showNotification(paste("Error in species conversion: ", e), type = "error", duration = 30)
  })
})

