            p_sub_neb[[x]] <-  ggplot(data=reduc_sub, aes_string(x=colnames(reduc_sub)[input$umapX], y=colnames(reduc_sub)[input$umapY],
               colour =input$umapColorBy, fill=input$umapColorBy)) & #outlineとfillを同じに
            geom_point(size= as.numeric(input$umapDotSize), shape=21, alpha= as.numeric(input$umapDotOpacity), stroke=as.numeric(input$umapDotBorder))&
            scale_fill_manual(values = cols) &
            scale_colour_manual(values = outline_cols) &
            scale_size() &
            theme_classic() &
            theme(axis.text.x = element_text(face = "plain", color = "black", size = input$umaplegendtextSize, angle = 0),
                  axis.text.y = element_text(face = "plain", color = "black", size = input$umaplegendtextSize, angle = 0),
                  axis.title.y = element_text(face = "plain", color = "black", size = input$umaplegendtextSize),
                  axis.title.x = element_text(face = "plain", color = "black", size = input$umaplegendtextSize),
                  legend.position = "none",
                 panel.grid.major.x = element_blank() , panel.grid.major.y = element_blank()  ,
                  title = element_text(face = "bold", color = "black", size = input$umaplegendtextSize*1.2, angle = 0)) &
            labs(x=paste0(reduc.key, "_", as.character(input$umapX)), y=paste0(reduc.key, "_", as.character(input$umapY)), title = split_name[x]) & theme(plot.title = element_text(hjust = 0.5)) &
              xlim(x_min,x_max) & ylim(y_min, y_max)
            p_sub_neb[[x]] <- LabelClusters(plot = p_sub_neb[[x]], id = input$umapColorBy, size = input$umapLabelSize,
              colour = input$umaplegendtextColor, check_overlap = TRUE, fontface = "bold")

        #最後のplotにはlegendをつける
        if ( x == col_len){
        p_sub_neb[[x]] <- p_sub_neb[[x]] + theme(legend.position = "right")+
        theme(legend.text=element_text(size=input$umaplegendtextSize, face='plain'),
          legend.title=element_text(size=input$umaplegendtextSize, face = 'bold'), legend.title.align=0.5)
        }

if (input$umapReverseX){
  p_sub_neb[[x]] <- p_sub_neb[[x]] & scale_x_reverse()
}
if (input$umapReverseY){
  p_sub_neb[[x]] <- p_sub_neb[[x]] & scale_y_reverse()
}
            }

            p <- wrap_plots(p_sub_neb, axis_titles='collect')


            } else {
              library(ggrepel)

          p <- ggplot(data=reduc_data, aes_string(x=colnames(reduc_data)[input$umapX], y=colnames(reduc_data)[input$umapY],
                          colour =input$umapColorBy, fill=input$umapColorBy)) &
            geom_point(size= as.numeric(input$umapDotSize), shape=21, alpha= as.numeric(input$umapDotOpacity), stroke=as.numeric(input$umapDotBorder))&
            scale_fill_manual(values = cols)&
            scale_colour_manual(values = outline_cols) &
            scale_size() &
            theme_classic() &
            theme(axis.text.x = element_text(face = "plain", color = "black", size = input$umaplegendtextSize, angle = 0),
                  axis.text.y = element_text(face = "plain", color = "black", size = input$umaplegendtextSize, angle = 0),
                  axis.title.y = element_text(face = "plain", color = "black", size = input$umaplegendtextSize),
                  axis.title.x = element_text(face = "plain", color = "black", size = input$umaplegendtextSize),
                  legend.text = element_text(face = "plain", color = "black", size = input$umaplegendtextSize),
                  legend.title = element_text(face = "plain", color = "black", size = input$umaplegendtextSize),
                  legend.position="right", panel.grid.minor.x = element_blank() , panel.grid.minor.y = element_blank()  ,
                 panel.grid.major.x = element_blank() , panel.grid.major.y = element_blank()  ,
                  title = element_text(face = "bold", color = "black", size = input$umaplegendtextSize, angle = 0)) &
            labs(x=paste0(reduc.key, "_", as.character(input$umapX)), y=paste0(reduc.key, "_", as.character(input$umapY)), title = '')
            p <- LabelClusters(plot = p, id = input$umapColorBy, size = input$umapLabelSize, colour = input$umaplegendtextColor,
              check_overlap = TRUE, fontface = "bold")

if (input$umapReverseX){
  p <- p & scale_x_reverse()
}
if (input$umapReverseY){
  p <- p & scale_y_reverse()
}

      } }#umap_split_flagの終わり

        # output$umapPlot <- renderPlotly({plotly::ggplotly(p, height=input$umapHeight, width=input$umapWidth)})
        global_umap <<- p
          output$umapPlot <- renderPlot(p, height=input$umapHeight, width=input$umapWidth)
 #       } #umapの終わり


  #      else if( dims == 3) #--------------3D--------------------
  #      {

      }
    }, error = function(e) {
      print(paste("Error :  ", e))
      showNotification(paste("Error :  ", e), type = 'error', duration=200)
      session$sendCustomMessage("handler_alert", "There was an error with drawing the resutls.")
    }, finally = {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("dim_red2_loader", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "dim_red2_loader")
      session$sendCustomMessage("handler_enableAllButtons", "umapConfirm")
    })
  }


updateReduction3D <- function()
  {
    session$sendCustomMessage("handler_startLoader", c("dim_red2_loader", 10))
    session$sendCustomMessage("handler_disableAllButtons", "umapConfirm3D")
    tryCatch({
      if (identical(seurat_object, NULL)) session$sendCustomMessage("handler_alert", "Please, upload some data via the DATA INPUT tab first.")
      else {
        showModal(modalDialog(div('Analysis in Progress. This operation may take several minutes, please wait...', style='color:#ffffff; background-color:#222d32;'), footer = NULL, style = 'font-size:20px; text-align:center;position:absolute;'))
        shinyjs::show("umapPlot_loader")

        ReductionUse <<- input$utilitiesActiveReduction2

        #get input
        dims <- 3
        type <- input$umapType3D

        #prepare metadata and reduction data
        meta <- seurat_object@meta.data
        meta$Cell_id <- rownames(meta)
        meta <- meta[, ]
        reduc_data <- data.frame()
        
        #prepare colors
        if (input$feature3D) {
          # Feature plot mode
          gene_expr <- FetchData(seurat_object, vars = input$feature3DGeneSelect)
          
          # 直接plotlyのカラースケール名を使用
          colorscale <- input$feature3DColor
          
        } else {
          # Regular clustering mode
          color_length <- length(unique(meta[, input$umapColorBy3D]))
          
          if (input$umapColorPalette3D %in% c("Set1", "Set2", "Set3", "Paired", "Dark2", "Accent", "Spectral")) {
            col_vector <- brewer.pal(20, input$umapColorPalette3D)
          } else {
            col_vector <- get(input$umapColorPalette3D)
          }

          if (length(col_vector) < color_length) {
            cols <- colorRampPalette(col_vector)(color_length)
          } else {
            cols <- col_vector
          }
        }

        #get reduction data
        seurat_object_reduc <- as.data.frame(seurat_object@reductions[[input$umapType3D]]@cell.embeddings)
        seurat_object_reduc <- seurat_object_reduc[, c(1:ncol(seurat_object_reduc))]
        seurat_object_reduc$Cell_id <- rownames(seurat_object_reduc)
        reduc_data <- left_join(seurat_object_reduc, meta)
        
        if (input$feature3D) {
          reduc_data$feature_expression <- gene_expr[[input$feature3DGeneSelect]]
        }

        if ( (length(reduc_data) - 1 < input$umapX3D ) | (length(reduc_data) -1  < input$umapY3D ) | (length(reduc_data) - 1 < input$umapZ3D ) ) {

          showNotification("Selected dimension is not available.", type ='error')
          return()
        }

        session$sendCustomMessage("handler_startLoader", c("dim_red2_loader", 50))

        reduc.key <- seurat_object@reductions[[input$umapType3D]]@key

        if (!str_detect(colnames(reduc_data)[3], "_3")) {
          showNotification("Error: no 3rd dimension data", type = 'error')
        }

        if (input$umapRandom3D) {
          reduc_data <- reduc_data[sample(1:nrow(reduc_data)), ]
        }

        # Calculate ranges for axes
        x_max <- max(reduc_data[[input$umapX3D]])
        x_min <- min(reduc_data[[input$umapX3D]])
        y_max <- max(reduc_data[[input$umapY3D]])
        y_min <- min(reduc_data[[input$umapY3D]])
        z_max <- max(reduc_data[[input$umapZ3D]])
        z_min <- min(reduc_data[[input$umapZ3D]])

        # Filter data if selection is active
        if (input$select3D) {
          if (!is.null(input$select3Dcell)) {
            reduc_data <- reduc_data %>%
              filter(.data[[input$select3Dident]] == input$select3Dcell)
          }
        }

        # Create plot
        if (input$feature3D) {
          
          p <- plot_ly(reduc_data, 
                      x = as.formula(paste0('~', reduc.key, as.character(input$umapX3D))), 
                      y = as.formula(paste0('~', reduc.key, as.character(input$umapY3D))),
                      z = as.formula(paste0('~', reduc.key, as.character(input$umapZ3D))), 
                      type = "scatter3d",
                      mode = "markers",
                      marker = list(
                        size = as.numeric(input$umapDotSize3D),
                        color = ~feature_expression,
                        colorscale = colorscale,
                        showscale = TRUE,
                        reversescale = input$reverse3D,
                         opacity = as.numeric(input$umapDotOpacity3D),
                        colorbar = list(
                          title = input$feature3DGeneSelect,
                          len = 0.5
                        ),
                        line = list(color = 'black', width = as.numeric(input$umapDotBorder3D))
                      ),
                      text = ~paste(input$feature3DGeneSelect, ": ", round(feature_expression, 3)),
                      hoverinfo = "text",
                      height = input$umapHeight,
                      width = input$umapWidth)
        } else {
          p <- plot_ly(reduc_data, 
                      x = as.formula(paste0('~', reduc.key, as.character(input$umapX3D))), 
                      y = as.formula(paste0('~', reduc.key, as.character(input$umapY3D))),
                      z = as.formula(paste0('~', reduc.key, as.character(input$umapZ3D))), 
                      type = "scatter3d",
                      alpha = as.numeric(input$umapDotOpacity3D),
                      mode = "markers",
                      color = as.formula(paste0('~', input$umapColorBy3D)),
                      text = ~get(input$umapColorBy3D),
                      hoverinfo = "text",
                      marker = list(
                        size = as.numeric(input$umapDotSize3D),
                        line = list(color = 'black', width = as.numeric(input$umapDotBorder3D))
                      ),
                      colors = cols,
                      height = input$umapHeight,
                      width = input$umapWidth)
        }

        # Add layout
        p <- p %>% layout(
          legend = list(
            font = list(
              size = input$umaplegendtextSize3D,
              color = "black"
            )),
          scene = list(
            xaxis = list(range = c(x_min, x_max)),
            yaxis = list(range = c(y_min, y_max)),
            zaxis = list(range = c(z_min, z_max))
          )
        )

        output$umapPlot3d <- renderPlotly(p)
        global_umap <<- p
      }
    }, error = function(e) {
      print(paste("Error : ", e))
      showNotification(paste("Error : ", e), type = 'error', duration = 200)
      session$sendCustomMessage("handler_alert", "There was an error with drawing the results.")
    }, finally = {
      removeModal()
      session$sendCustomMessage("handler_startLoader", c("dim_red2_loader", 100))
      Sys.sleep(1)
      session$sendCustomMessage("handler_finishLoader", "dim_red2_loader")
      session$sendCustomMessage("handler_enableAllButtons", "umapConfirm3D")
    })
  }

