                  title = element_text(face = "bold", color = "black", size = 12, angle = 0)) +
            labs(x="PC 1", y="PC 2", color="Cell type", title = "", fill="Color")
                    output$umapPlot <- renderPlotly({plotly::ggplotly(p, height=input$umapHeight, width=input$umapWidth)})
     #     output$umapPlot <- renderPlotly({plotly::ggplotly(p)})
        }
        else if(str_detect(type, pattern = "pca") & dims == 3)
        {
