updateUtilitiesReduction <- function()
{
  getReduction <- names(seurat_object@reductions)
  if (length(getReduction) > 0) { 
    print('getReduction')
    print(getReduction)
    period_pos <- regexpr("\\.", input$utilitiesActiveReduction)
    
    # Get assay name from active reduction
    utilitiesActiveAssay2 <- if (period_pos > 0) {
      substr(input$utilitiesActiveReduction, 1, period_pos - 1)
    } else {
      "RNA"
    }
    # Find MNN reductions
    mnn_match <- str_subset(getReduction, pattern='.*mnn')
    mnn_select <- if(length(mnn_match) > 0) mnn_match[length(mnn_match)] else NULL
    
    # Check for active assay specific MNN
    active_assay_mnn_match <- str_subset(mnn_match, pattern=paste0('.*',utilitiesActiveAssay2,'.*'))
    if (length(active_assay_mnn_match) > 0) {
      mnn_select <- active_assay_mnn_match[length(active_assay_mnn_match)]
    }
    # Find PCA and related reductions
    pca_match <- str_subset(getReduction, pattern='.*pca|PCA|mnn|scnrm|harmony')
    print('pca_match')
    print(pca_match)
    
    # Initialize default selections
    pca_select <- if(length(pca_match) > 0) pca_match[length(pca_match)] else NULL
    pca_select_clustering <- if(length(pca_match) > 0) pca_match[1] else NULL
    
    # For utilitiesReductionHemascribe: prioritize .pca endings
    pca_select_hemascribe <- NULL
    # First, look for reductions ending with .pca (not followed by other extensions)
    pca_only_match <- str_subset(getReduction, pattern='\\.pca$')
    if (length(pca_only_match) > 0) {
      # Prioritize active assay specific .pca
      active_assay_pca_only <- str_subset(pca_only_match, pattern=paste0('^',utilitiesActiveAssay2,'\\.pca$'))
      if (length(active_assay_pca_only) > 0) {
        pca_select_hemascribe <- active_assay_pca_only[1]
      } else {
        pca_select_hemascribe <- pca_only_match[1]
      }
    }
    # If no .pca found, fall back to pca_select
    if (is.null(pca_select_hemascribe)) {
      pca_select_hemascribe <- pca_select
    }
    
    # Check for assay-specific matches
    print('match pattern')
    print(paste0('.*', DefaultAssay(seurat_object), '.*'))
    assay_match <- str_subset(pca_match, pattern = paste0('.*', DefaultAssay(seurat_object), '.*'))
    print('assay_match')
    print(assay_match)
    if (length(assay_match) > 0) {
      print('assay match is not null')
      print(assay_match[1])
      pca_select_clustering <- assay_match[1]
    }
    # Check for active assay specific PCA
    active_assay_pca_match <- str_subset(pca_match, pattern=paste0('.*',utilitiesActiveAssay2,'.*'))
    if (length(active_assay_pca_match) > 0) {
      pca_select <- active_assay_pca_match[length(active_assay_pca_match)]
    }
    # Prioritize MNN if available
    if (length(mnn_match) > 0) {
      pca_select <- mnn_select
    }
    # Update UI elements with safe fallbacks
    updateSelectInput(session, "utilitiesActiveReduction", 
                     choices = getReduction, 
                     selected = if(!is.null(pca_select_clustering)) pca_select_clustering else getReduction[1])
    updateSelectInput(session, "utilitiesActiveReduction2", 
                     choices = getReduction, 
                     selected = if(!is.null(pca_select_clustering)) pca_select_clustering else getReduction[1])
    updateSelectInput(session, "utilitiesActiveReduction3", 
                     choices = getReduction, 
                     selected = if(!is.null(pca_select)) pca_select else getReduction[1])
    updateSelectInput(session, "utilitiesReductionHemascribe",
                     choices = getReduction,
                     selected = if(!is.null(pca_select_hemascribe)) pca_select_hemascribe else getReduction[1])

    # Update PC Covariate Analysis reduction choices
    pca_reductions <- grep("pca|lsi|PC", getReduction, value = TRUE, ignore.case = TRUE)
    if (length(pca_reductions) == 0) {
      pca_reductions <- getReduction
    }
    updateSelectInput(session, "pcCovReduction",
                     choices = pca_reductions,
                     selected = if(!is.null(pca_select_clustering)) pca_select_clustering else pca_reductions[1])

    # Update PCs only if we have a valid reduction method
    if (!is.null(pca_select_clustering) &&
        (str_detect(pca_select_clustering, pattern="mnn") ||
         str_detect(pca_select_clustering, pattern="scnrm") ||
         str_detect(pca_select_clustering, pattern="harmony"))) {
      updatePCs_selection(30)
    }
  }
}


