  #update metadata RNA and export_RNA_table

  updateMetadata <- function()
  {
    print("start in updateMetadata")
    seurat_object@meta.data$Cell_id <<- rownames(seurat_object@meta.data)
    print("1st in updateMetadata")
    #seurat_object@meta.data$percent.mt <<- as.double(sprintf("%.3f", as.double(seurat_object@meta.data$percent.mt)))

    #--3 decimal points
    for(i in 1:length(colnames(seurat_object@meta.data)))
    {
      if(is.double(seurat_object@meta.data[, i]))
      {
        seurat_object@meta.data[, i] <- as.double(sprintf("%.3f", as.double(seurat_object@meta.data[, i])))
      }
    }
    #--
    print('2nd in updateMetadata')
    output$metadataTable <- renderDataTable(seurat_object@meta.data, options = list(pageLength = 10), rownames = F)
    print('3rd in updateMetadata')
    export_metadata_RNA <<- seurat_object@meta.data
    updateRegressOut()

    # Update scDblFinder sample and cluster column choices
    updateSelectInput(session, "scDblFinderSampleColumn", choices = names(seurat_object@meta.data), selected = "orig.ident")
    updateSelectInput(session, "scDblFinderClusterColumn", choices = names(seurat_object@meta.data), selected = "seurat_clusters")

    # Update scDblFinder reduction choices
    pca_choices <- names(seurat_object@reductions)
    pca_match <- str_subset(pca_choices, pattern='.*pca|PCA')
    pca_select <- if(length(pca_match) > 0) pca_match[length(pca_match)] else pca_choices[1]
    updateSelectInput(session, "scDblFinderReduction", choices = pca_choices, selected = pca_select)

    #df$col <- sprintf("%.3f", df$col)
  }

