  #---------------------------------RNA VELOCITY / VELOCYTO------------------------------------

  # Global variables for velocyto
  velocyto_original_loom <<- NULL
  velocyto_status_text <<- reactiveVal("Not started")
  velocyto_log_file <<- reactiveVal(NULL)
  velocyto_running <<- reactiveVal(FALSE)

  # Display selected BAM files
  output$velocytoBAMfilesPath <- renderText({
    if(!is.null(input$velocytoBAMfiles) && !is.integer(input$velocytoBAMfiles)) {
      bam_file_info <- parseFilePaths(volumes, input$velocytoBAMfiles)
      if (nrow(bam_file_info) > 0) {
        files <- basename(bam_file_info$datapath)
        return(paste0("Selected ", length(files), " file(s): ", paste(files, collapse=", ")))
      } else {
        return("No files selected")
      }
    } else {
      return("No files selected")
    }
  })

  # Display GTF file path
  output$velocytoGTFfilePath <- renderText({
    if(!is.null(input$velocytoGTFfile) && !is.integer(input$velocytoGTFfile)) {
      gtf_file_info <- parseFilePaths(volumes, input$velocytoGTFfile)
      return(as.character(gtf_file_info$datapath))
    } else {
      return("No file selected")
    }
  })

  # Display Mask GTF file path
  output$velocytoMaskGTFPath <- renderText({
    if(!is.null(input$velocytoMaskGTF) && !is.integer(input$velocytoMaskGTF)) {
      mask_file_info <- parseFilePaths(volumes, input$velocytoMaskGTF)
      return(as.character(mask_file_info$datapath))
    } else {
      return("No file selected")
    }
  })

  # Display velocyto status
  output$velocytoStatus <- renderText({
    velocyto_status_text()
  })

  # Monitor velocyto log file - show last 10 lines with real-time updates
  velocyto_log_content <- reactiveVal("")

  observe({
    invalidateLater(2000, session)  # Check every 2 seconds

    if (velocyto_running() && !is.null(velocyto_log_file())) {
      log_path <- velocyto_log_file()
      if (file.exists(log_path)) {
        tryCatch({
          # Always show last 10 lines using tail command for efficiency
          log_lines <- system(paste("tail -n 10", shQuote(log_path)), intern = TRUE)

          if (length(log_lines) > 0) {
            velocyto_log_content(paste(log_lines, collapse = "\n"))
          } else {
            velocyto_log_content("Waiting for velocyto output...")
          }
        }, error = function(e) {
          velocyto_log_content("Log file not available yet...")
        })
      }
    } else if (!velocyto_running()) {
      # Clear log when not running
      velocyto_log_content("")
    }
  })

  # Display velocyto log output (last 10 lines)
  output$velocytoLogOutput <- renderText({
    velocyto_log_content()
  })

  # Display selected GTF file path
  output$velocytoSelectedGTF <- renderText({
    if (input$velocytoGTFsource == "custom") {
      if (!is.null(input$velocytoGTFfile) && !is.integer(input$velocytoGTFfile)) {
        gtf_file_info <- parseFilePaths(volumes, input$velocytoGTFfile)
        return(paste("Selected GTF:", as.character(gtf_file_info$datapath)))
      } else {
        return("Please select a custom GTF file")
      }
    } else {
      gtf_base <- "./GTF"
      gtf_path <- switch(input$velocytoGTFsource,
        "GRCh38-2024" = file.path(gtf_base, "refdata-gex-GRCh38-2024-A/genes/genes.gtf.gz"),
        "GRCh38-2020" = file.path(gtf_base, "refdata-gex-GRCh38-2020-A/genes/genes.gtf"),
        "GRCm39-2024" = file.path(gtf_base, "refdata-gex-GRCm39-2024-A/genes/genes.gtf.gz"),
        "mm10-2020" = file.path(gtf_base, "mm10-2020A/genes/genes.gtf"),
        NULL
      )
      if (!is.null(gtf_path) && file.exists(gtf_path)) {
        return(paste("Using GTF:", gtf_path))
      } else {
        return("GTF file not found at expected location")
      }
    }
  })

  # Run Velocyto
  observeEvent(input$RunVelocyto, {
    if (!is.null(input$RunVelocyto)) {
      if (input$RunVelocyto > 0) {

        # Disable tabs and show modal
        session$sendCustomMessage("handler_disableTabs", "sidebarMenu")
        session$sendCustomMessage("handler_disableAllButtons", "RunVelocyto")

        tryCatch({
          showModal(modalDialog(
            div('Velocyto analysis in progress. This may take several hours. Please wait...',
                style='color:#ffffff; background-color:#222d32;'),
            footer = NULL,
            style = 'font-size:20px; text-align:center;position:absolute;'
          ))

          velocyto_status_text("Preparing velocyto analysis...")
          showNotification("Starting velocyto analysis", type='message', duration=5)

          # Create output directory
          userId <- session$token
          output_dir <- paste0("./usr_temp/", userId, "_velocyto_", gsub(pattern = "[ ]|[:]", replacement = "_", x = Sys.time()))
          dir.create(output_dir, recursive = TRUE)

          # Collect BAM files
          bam_files <- c()

          # From PC upload
          if (!is.null(input$velocytoBAMupload)) {
            uploaded_bams <- input$velocytoBAMupload$datapath
            bam_files <- c(bam_files, uploaded_bams)
          }

          # From server file selection
          if (!is.null(input$velocytoBAMfiles) && !is.integer(input$velocytoBAMfiles)) {
            bam_file_info <- parseFilePaths(volumes, input$velocytoBAMfiles)
            if (nrow(bam_file_info) > 0) {
              server_bams <- as.character(bam_file_info$datapath)
              bam_files <- c(bam_files, server_bams)
            }
          }

          if (length(bam_files) == 0) {
            stop("No BAM files selected. Please select at least one BAM file.")
          }

          velocyto_status_text(paste("Found", length(bam_files), "BAM file(s)"))
          showNotification(paste("Processing", length(bam_files), "BAM file(s)"), type='message', duration=5)

          # Get GTF file path
          gtf_file <- NULL

          if (input$velocytoGTFsource == "custom") {
            if (!is.null(input$velocytoGTFfile) && !is.integer(input$velocytoGTFfile)) {
              gtf_file_info <- parseFilePaths(volumes, input$velocytoGTFfile)
              gtf_file <- as.character(gtf_file_info$datapath)
            }
          } else {
            gtf_base <- "./GTF"
            gtf_file <- switch(input$velocytoGTFsource,
              "GRCh38-2024" = file.path(gtf_base, "refdata-gex-GRCh38-2024-A/genes/genes.gtf.gz"),
              "GRCh38-2020" = file.path(gtf_base, "refdata-gex-GRCh38-2020-A/genes/genes.gtf"),
              "GRCm39-2024" = file.path(gtf_base, "refdata-gex-GRCm39-2024-A/genes/genes.gtf.gz"),
              "mm10-2020" = file.path(gtf_base, "mm10-2020A/genes/genes.gtf"),
              NULL
            )
          }

          if (is.null(gtf_file) || !file.exists(gtf_file)) {
            stop("GTF file not found. Please select a valid GTF file.")
          }

          velocyto_status_text(paste("Using GTF:", gtf_file))

          # Get mask GTF if specified
          mask_gtf <- NULL
          if (input$velocytoUseMask && !is.null(input$velocytoMaskGTF) && !is.integer(input$velocytoMaskGTF)) {
            mask_file_info <- parseFilePaths(volumes, input$velocytoMaskGTF)
            mask_gtf <- as.character(mask_file_info$datapath)
          }

          # Run velocyto for each BAM file
          output_looms <- c()

          # Setup log file for output monitoring
          log_file_path <- file.path(output_dir, "velocyto.log")
          velocyto_log_file(log_file_path)
          velocyto_running(TRUE)  # Start real-time log monitoring

          for (i in seq_along(bam_files)) {
            bam_file <- bam_files[i]
            velocyto_status_text(paste("Processing BAM file", i, "of", length(bam_files)))
            showNotification(paste("Running velocyto on BAM", i, "of", length(bam_files)), type='message', duration=5)

            # Build velocyto command with log output
            output_name <- paste0("velocyto_output_", i)
            velocyto_cmd <- paste(
              "velocyto run",
              "-vv",  # Verbose output
              "-o", shQuote(output_dir),
              ifelse(!is.null(mask_gtf), paste("-m", shQuote(mask_gtf)), ""),
              "-@", input$velocytoThreads,
              shQuote(bam_file),
              shQuote(gtf_file),
              ">>", shQuote(log_file_path), "2>&1"
            )

            print(paste("Running velocyto command:", velocyto_cmd))

            # Execute velocyto synchronously (blocking) but with log redirection
            # This ensures proper error handling and completion detection
            system(velocyto_cmd, wait = TRUE)

            # Find output loom file
            loom_files <- list.files(output_dir, pattern = "\\.loom$", full.names = TRUE)
            if (length(loom_files) > 0) {
              output_looms <- c(output_looms, loom_files[length(loom_files)])
            }
          }

          if (length(output_looms) == 0) {
            stop("Velocyto did not produce any output .loom files. Check logs for errors.")
          }

          # Save all loom files for download
          velocyto_all_looms <<- output_looms
          velocyto_original_loom <<- output_looms[1]

          if (length(output_looms) > 1) {
            showNotification(paste("Generated", length(output_looms), "loom files. All files will be included in download ZIP."),
                           type='message', duration=10)
          } else {
            showNotification("Generated 1 loom file. Will be downloaded as ZIP archive.",
                           type='message', duration=10)
          }

          velocyto_status_text("Velocyto analysis completed successfully!")
          showNotification("Velocyto completed! Download the .loom file for downstream analysis.", type='message', duration=10)

        }, error = function(e) {
          print(paste("Velocyto error:", e))
          showNotification(paste("Velocyto error:", e$message), type = 'error', duration=30)
          velocyto_status_text(paste("Error:", e$message))
        }, finally = {
          velocyto_running(FALSE)  # Stop real-time log monitoring
          removeModal()
          session$sendCustomMessage("handler_enableAllButtons", "RunVelocyto")
          # Re-enable tabs
          session$sendCustomMessage("handler_enableTabs", c("sidebarMenu", " FILE"))
        })
      }
    }
  })

  # Download loom files as ZIP archive
  output$downloadVelocytoOriginal <- downloadHandler(
    filename = function() {
      paste0("velocyto_loom_files_", Sys.Date(), ".zip")
    },
    content = function(file) {
      if (!is.null(velocyto_all_looms) && length(velocyto_all_looms) > 0) {
        # Check if all loom files exist
        existing_looms <- velocyto_all_looms[file.exists(velocyto_all_looms)]

        if (length(existing_looms) == 0) {
          showNotification("No loom files available for download", type='error', duration=10)
          return(NULL)
        }

        # Create temporary directory for organizing files
        temp_dir <- tempdir()
        zip_temp_dir <- file.path(temp_dir, paste0("velocyto_", format(Sys.time(), "%Y%m%d_%H%M%S")))
        dir.create(zip_temp_dir, showWarnings = FALSE, recursive = TRUE)

        # Copy loom files to temp directory with meaningful names
        for (i in seq_along(existing_looms)) {
          loom_file <- existing_looms[i]
          # Create meaningful filename
          new_name <- paste0("velocyto_sample_", i, ".loom")
          file.copy(loom_file, file.path(zip_temp_dir, new_name))
        }

        # Create ZIP file
        old_wd <- getwd()
        setwd(zip_temp_dir)
        loom_files_in_dir <- list.files(pattern = "\\.loom$")
        zip::zip(zipfile = file, files = loom_files_in_dir, mode = "cherry-pick")
        setwd(old_wd)

        # Clean up temporary directory
        unlink(zip_temp_dir, recursive = TRUE)

        showNotification(paste("Downloaded", length(existing_looms), "loom file(s) as ZIP archive"),
                        type='message', duration=10)
      } else {
        showNotification("Loom files not available. Please run velocyto analysis first.",
                        type='error', duration=10)
      }
    }
  )

  # ============================================================================
  # DropletQC - Detect empty droplets & damaged cells
  # ============================================================================

  # Reactive values for DropletQC
  dropletqc_nf_umi <- reactiveVal(NULL)
  dropletqc_result <- reactiveVal(NULL)

  # --- Helper: strip barcode suffix ---
  strip_barcode_suffix <- function(barcodes) {
    sub("_\\d+$", "", barcodes)
  }

  # --- BAM file path display ---
  output$dropletqcBAMpath <- renderText({
    if (!is.null(input$dropletqcBAMfile) && !is.integer(input$dropletqcBAMfile)) {
      bam_file_info <- parseFilePaths(volumes, input$dropletqcBAMfile)
      if (nrow(bam_file_info) > 0) {
        paths <- as.character(bam_file_info$datapath)
        return(paste0("Selected ", length(paths), " file(s):\n",
                       paste(paths, collapse = "\n")))
      }
    }
    "No file selected"
  })

  # --- GTF file path display ---
  output$dropletqcGTFpath <- renderText({
    if (!is.null(input$dropletqcGTFfile) && !is.integer(input$dropletqcGTFfile)) {
      gtf_file_info <- parseFilePaths(volumes, input$dropletqcGTFfile)
      return(as.character(gtf_file_info$datapath))
    }
    "No file selected"
  })

  # --- Update sample column choices when Seurat object changes ---
  observe({
    req(seurat_object)
    meta_cols <- colnames(seurat_object@meta.data)
    updateSelectInput(session, "dropletqcSampleCol",
      choices = meta_cols, selected = "orig.ident")
    updateSelectInput(session, "dropletqcCelltypeCol",
      choices = meta_cols, selected = NULL)

    # Show/hide multi-sample warning
    n_samples <- length(unique(seurat_object$orig.ident))
    if (n_samples > 1) {
      shinyjs::show("dropletqc_multisample_warning")
    } else {
      shinyjs::hide("dropletqc_multisample_warning")
    }
  })

  # --- Update sample name choices when sample column changes ---
  observeEvent(input$dropletqcSampleCol, {
    req(seurat_object)
    req(input$dropletqcSampleCol)
    if (input$dropletqcSampleCol %in% colnames(seurat_object@meta.data)) {
      sample_names <- sort(unique(seurat_object@meta.data[[input$dropletqcSampleCol]]))
      updateSelectInput(session, "dropletqcSampleName",
        choices = sample_names, selected = sample_names[1])
    }
  })

  # --- Step 4: Calculate Nuclear Fraction ---
  observeEvent(input$RunDropletQCnf, {
    req(seurat_object)

    # Validate BAM file selection
    if (is.null(input$dropletqcBAMfile) || is.integer(input$dropletqcBAMfile)) {
      showNotification("Please select BAM file(s) first.", type = "error", duration = 5)
      return()
    }

    bam_info <- parseFilePaths(volumes, input$dropletqcBAMfile)
    bam_paths <- as.character(bam_info$datapath)

    if (length(bam_paths) == 0) {
      showNotification("No BAM files selected.", type = "error", duration = 5)
      return()
    }

    # Validate all BAM files exist
    missing <- bam_paths[!file.exists(bam_paths)]
    if (length(missing) > 0) {
      showNotification(paste("BAM file(s) not found:", paste(missing, collapse = ", ")),
                       type = "error", duration = 5)
      return()
    }

    # Determine which cells to process
    n_samples <- length(unique(seurat_object@meta.data[[input$dropletqcSampleCol]]))
    if (n_samples > 1 && !is.null(input$dropletqcSampleName)) {
      # Multi-sample: subset to selected sample
      sample_cells <- colnames(seurat_object)[
        seurat_object@meta.data[[input$dropletqcSampleCol]] == input$dropletqcSampleName
      ]
      barcodes <- strip_barcode_suffix(sample_cells)
    } else {
      # Single sample: use all cells
      sample_cells <- colnames(seurat_object)
      barcodes <- strip_barcode_suffix(sample_cells)
    }

    # Write barcodes to temp file
    barcode_tmp <- tempfile(fileext = ".tsv")
    writeLines(barcodes, barcode_tmp)

    # Resolve GTF path (needed for annotation method, resolve once before loop)
    gtf_file <- NULL
    if (input$dropletqcMethod != "tags") {
      gtf_base <- "./GTF"
      if (input$dropletqcGTFsource == "custom") {
        if (is.null(input$dropletqcGTFfile) || is.integer(input$dropletqcGTFfile)) {
          showNotification("Please select a custom GTF file.", type = "error", duration = 5)
          unlink(barcode_tmp)
          return()
        }
        gtf_info <- parseFilePaths(volumes, input$dropletqcGTFfile)
        gtf_file <- as.character(gtf_info$datapath)
      } else {
        gtf_file <- switch(input$dropletqcGTFsource,
          "GRCh38-2024" = file.path(gtf_base, "refdata-gex-GRCh38-2024-A/genes/genes.gtf.gz"),
          "GRCh38-2020" = file.path(gtf_base, "refdata-gex-GRCh38-2020-A/genes/genes.gtf"),
          "GRCm39-2024" = file.path(gtf_base, "refdata-gex-GRCm39-2024-A/genes/genes.gtf.gz"),
          "mm10-2020"   = file.path(gtf_base, "mm10-2020A/genes/genes.gtf"),
          NULL
        )
      }
      if (is.null(gtf_file) || !file.exists(gtf_file)) {
        showNotification("GTF file not found. Check your selection.", type = "error", duration = 5)
        unlink(barcode_tmp)
        return()
      }
    }

    # Helper function to run NF on a single BAM
    run_nf_single <- function(bam_path, barcode_file, method, gtf, cores, tiles) {
      if (method == "tags") {
        DropletQC::nuclear_fraction_tags(
          bam = bam_path,
          barcodes = barcode_file,
          cores = cores,
          tiles = tiles,
          verbose = TRUE
        )
      } else {
        DropletQC::nuclear_fraction_annotation(
          annotation_path = gtf,
          bam = bam_path,
          barcodes = barcode_file,
          cores = cores,
          tiles = tiles,
          verbose = TRUE
        )
      }
    }

    withProgress(message = "Calculating nuclear fraction...", value = 0, {
      tryCatch({
        if (length(bam_paths) == 1) {
          # Single BAM: original logic
          incProgress(0.1, detail = paste("Processing:", basename(bam_paths[1])))
          nf <- run_nf_single(bam_paths[1], barcode_tmp, input$dropletqcMethod,
                              gtf_file, input$dropletqcCores, input$dropletqcTiles)
        } else {
          # Multiple BAMs: process each and merge results
          nf_list <- list()
          for (i in seq_along(bam_paths)) {
            incProgress(0.1 * i / length(bam_paths),
                        detail = paste0("Processing BAM ", i, "/", length(bam_paths),
                                        ": ", basename(bam_paths[i])))
            nf_i <- tryCatch(
              run_nf_single(bam_paths[i], barcode_tmp, input$dropletqcMethod,
                            gtf_file, input$dropletqcCores, input$dropletqcTiles),
              error = function(e) {
                showNotification(paste("BAM error (", basename(bam_paths[i]), "):", e$message),
                                 type = "warning", duration = 10)
                NULL
              }
            )
            if (!is.null(nf_i) && nrow(nf_i) > 0) {
              nf_list[[length(nf_list) + 1]] <- nf_i
            }
          }
          if (length(nf_list) == 0) {
            stop("No results from any BAM file.")
          }
          # Merge: combine and deduplicate by barcode (first result takes priority)
          nf <- do.call(rbind, nf_list)
          nf <- nf[!duplicated(rownames(nf)), , drop = FALSE]
        }

        incProgress(0.8, detail = "Updating Seurat object")

        # Map NF values back to Seurat object
        # nf$nuclear_fraction is named by barcode (without suffix)
        nf_values <- nf$nuclear_fraction
        names(nf_values) <- barcodes[seq_len(length(nf_values))]

        # Match barcodes: NF result rownames ↔ stripped barcodes
        nf_barcodes <- rownames(nf)
        matched_idx <- match(barcodes, nf_barcodes)
        matched_nf <- nf$nuclear_fraction[matched_idx]  # NA for unmatched

        # Write NF to metadata for the processed cells
        if (!"nuclear_fraction" %in% colnames(seurat_object@meta.data)) {
          seurat_object$nuclear_fraction <<- NA_real_
        }
        seurat_object@meta.data[sample_cells, "nuclear_fraction"] <<- matched_nf

        n_matched <- sum(!is.na(matched_nf))

        # Build NF + UMI data frame for all cells that have NF values
        cells_with_nf <- colnames(seurat_object)[!is.na(seurat_object$nuclear_fraction)]
        nf_umi_df <- data.frame(
          nuclear_fraction = seurat_object@meta.data[cells_with_nf, "nuclear_fraction"],
          umi_count = seurat_object@meta.data[cells_with_nf, "nCount_RNA"],
          row.names = cells_with_nf
        )
        dropletqc_nf_umi(nf_umi_df)

        incProgress(1, detail = "Done!")
        showNotification(
          paste0("Nuclear fraction calculated: ", n_matched, "/", length(sample_cells),
                 " cells matched (from ", length(bam_paths), " BAM file(s))."),
          type = "message", duration = 10
        )

      }, error = function(e) {
        showNotification(paste("Error:", e$message), type = "error", duration = 15)
      })
    })

    # Clean up
    unlink(barcode_tmp)
  })

  # --- NF status display ---
  output$dropletqcNFstatus <- renderText({
    nf_umi <- dropletqc_nf_umi()
    if (is.null(nf_umi)) {
      return("Nuclear fraction not yet calculated.")
    }
    paste0("Nuclear fraction calculated for ", nrow(nf_umi), " cells.\n",
           "NF range: ", round(min(nf_umi$nuclear_fraction, na.rm = TRUE), 4),
           " - ", round(max(nf_umi$nuclear_fraction, na.rm = TRUE), 4))
  })

  # --- Step 5: Identify Empty Droplets ---
  observeEvent(input$RunDropletQCempty, {
    nf_umi <- dropletqc_nf_umi()
    if (is.null(nf_umi)) {
      showNotification("Please calculate nuclear fraction first (Step 4).", type = "error", duration = 5)
      return()
    }

    withProgress(message = "Identifying empty droplets...", value = 0.3, {
      tryCatch({
        result_ed <- DropletQC::identify_empty_drops(
          nf_umi = nf_umi,
          nf_rescue = input$dropletqcNFrescue,
          umi_rescue = input$dropletqcUMIrescue
        )

        # Store result and update Seurat metadata
        dropletqc_result(result_ed)
        seurat_object@meta.data[rownames(result_ed), "dropletQC_status"] <<- result_ed$cell_status

        n_empty <- sum(result_ed$cell_status == "empty_droplet")
        n_cell <- sum(result_ed$cell_status == "cell")

        incProgress(1, detail = "Done!")
        showNotification(
          paste0("Empty droplets identified: ", n_empty, " empty, ", n_cell, " cells."),
          type = "message", duration = 10
        )
      }, error = function(e) {
        showNotification(paste("Error:", e$message), type = "error", duration = 15)
      })
    })
  })

  # --- Step 6: Identify Damaged Cells ---
  observeEvent(input$RunDropletQCdamaged, {
    result_df <- dropletqc_result()
    if (is.null(result_df)) {
      showNotification("Please identify empty droplets first (Step 5).", type = "error", duration = 5)
      return()
    }

    if (is.null(input$dropletqcCelltypeCol) || input$dropletqcCelltypeCol == "") {
      showNotification("Please select a cell type column.", type = "error", duration = 5)
      return()
    }

    withProgress(message = "Identifying damaged cells...", value = 0.3, {
      tryCatch({
        # Add cell type information
        nf_umi_ed_ct <- result_df
        nf_umi_ed_ct$cell_type <- seurat_object@meta.data[rownames(nf_umi_ed_ct), input$dropletqcCelltypeCol]

        result_dc <- DropletQC::identify_damaged_cells(
          nf_umi_ed_ct = nf_umi_ed_ct,
          nf_sep = input$dropletqcNFsep,
          umi_sep_perc = input$dropletqcUMIsepPerc,
          verbose = TRUE
        )

        # Update result and Seurat metadata
        dropletqc_result(result_dc$df)
        seurat_object@meta.data[rownames(result_dc$df), "dropletQC_status"] <<- result_dc$df$cell_status

        n_damaged <- sum(result_dc$df$cell_status == "damaged_cell")
        n_cell <- sum(result_dc$df$cell_status == "cell")
        n_empty <- sum(result_dc$df$cell_status == "empty_droplet")

        incProgress(1, detail = "Done!")
        showNotification(
          paste0("Results: ", n_cell, " cells, ", n_empty, " empty, ", n_damaged, " damaged."),
          type = "message", duration = 10
        )
      }, error = function(e) {
        showNotification(paste("Error:", e$message), type = "error", duration = 15)
      })
    })
  })

  # --- NF vs UMI Scatter Plot ---
  output$dropletqcScatter <- plotly::renderPlotly({
    result_df <- dropletqc_result()
    req(result_df)

    df <- result_df
    df$log10_umi <- log10(df$umi_count + 1)

    color_map <- c("cell" = "#2196F3", "empty_droplet" = "#f44336", "damaged_cell" = "#9C27B0")
    present_statuses <- unique(df$cell_status)
    colors_use <- color_map[present_statuses]

    p <- ggplot(df, aes(x = nuclear_fraction, y = log10_umi, color = cell_status)) +
      geom_point(alpha = 0.5, size = 0.8) +
      scale_color_manual(values = colors_use) +
      theme_bw() +
      labs(x = "Nuclear Fraction", y = "log10(UMI count)", color = "Status") +
      theme(legend.position = "bottom")

    plotly::ggplotly(p) %>%
      plotly::layout(legend = list(orientation = "h", y = -0.15))
  })

  # --- NF Distribution Histogram ---
  output$dropletqcNFhist <- renderPlot({
    nf_umi <- dropletqc_nf_umi()
    req(nf_umi)

    result_df <- dropletqc_result()
    if (!is.null(result_df)) {
      # Color by status if available
      df <- result_df
      color_map <- c("cell" = "#2196F3", "empty_droplet" = "#f44336", "damaged_cell" = "#9C27B0")
      ggplot(df, aes(x = nuclear_fraction, fill = cell_status)) +
        geom_histogram(bins = 100, alpha = 0.7, position = "identity") +
        scale_fill_manual(values = color_map) +
        theme_bw() +
        labs(x = "Nuclear Fraction", y = "Count", fill = "Status", title = "Nuclear Fraction Distribution")
    } else {
      ggplot(nf_umi, aes(x = nuclear_fraction)) +
        geom_histogram(bins = 100, fill = "#2196F3", alpha = 0.7) +
        geom_density(aes(y = after_stat(count)), color = "red", linewidth = 0.8) +
        theme_bw() +
        labs(x = "Nuclear Fraction", y = "Count", title = "Nuclear Fraction Distribution")
    }
  })

  # --- Summary Text ---
  output$dropletqcSummary <- renderText({
    result_df <- dropletqc_result()
    if (is.null(result_df)) {
      nf_umi <- dropletqc_nf_umi()
      if (is.null(nf_umi)) {
        return("No DropletQC results yet. Run Steps 4-6 to generate results.")
      }
      return(paste0("Nuclear fraction calculated for ", nrow(nf_umi), " cells.\n",
                     "Run Step 5 (Identify Empty Droplets) to classify cells."))
    }

    status_counts <- table(result_df$cell_status)
    lines <- c("=== DropletQC Summary ===", "")
    for (s in names(status_counts)) {
      lines <- c(lines, paste0("  ", s, ": ", status_counts[s]))
    }
    lines <- c(lines, "", paste0("  Total: ", nrow(result_df)))
    paste(lines, collapse = "\n")
  })

  # --- Summary Table ---
  output$dropletqcTable <- DT::renderDataTable({
    result_df <- dropletqc_result()
    req(result_df)

    display_df <- data.frame(
      Barcode = rownames(result_df),
      Nuclear_Fraction = round(result_df$nuclear_fraction, 4),
      UMI_Count = result_df$umi_count,
      Status = result_df$cell_status
    )

    DT::datatable(display_df,
      options = list(pageLength = 20, scrollX = TRUE),
      filter = "top",
      rownames = FALSE
    )
  })

  # --- Step 7: Filter cells ---
  observeEvent(input$DropletQCfilter, {
    req(seurat_object)

    if (!"dropletQC_status" %in% colnames(seurat_object@meta.data)) {
      showNotification("Please run DropletQC classification first.", type = "error", duration = 5)
      return()
    }

    n_before <- ncol(seurat_object)
    cells_keep <- colnames(seurat_object)[seurat_object$dropletQC_status == "cell" | is.na(seurat_object$dropletQC_status)]

    if (length(cells_keep) == 0) {
      showNotification("No cells would remain after filtering. Aborting.", type = "error", duration = 5)
      return()
    }

    seurat_object <<- subset(seurat_object, cells = cells_keep)
    n_after <- ncol(seurat_object)
    n_removed <- n_before - n_after

    # Reset DropletQC reactive values
    dropletqc_nf_umi(NULL)
    dropletqc_result(NULL)

    showNotification(
      paste0("Filtered: removed ", n_removed, " cells (", n_before, " -> ", n_after, ")."),
      type = "message", duration = 10
    )
  })

}
